/* AUTO-GENERATED — Indiana Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["IN"] = {"code":"IN","name":"Indiana","agency":"Indiana BMV","agencyShort":"BMV","handbook":"https://www.in.gov/bmv/licenses-permits-ids/commercial-drivers-license-overview/obtaining-a-commercial-learners-permit/cdl-manual","links":{},"en":[{"q":"On Indiana highways, what is the maximum legal width of a vehicle and its load (excluding width-exclusive devices such as mirrors)?","options":["8 feet 0 inches","9 feet 0 inches","8 feet 6 inches","10 feet 0 inches"],"answer":2,"explanation":"Indiana limits vehicle and load width to 8 feet 6 inches (102 inches), excluding width-exclusive safety devices per 23 CFR 658. Source: Indiana Code IC 9-20-3-2; Indiana State Police Summary of Indiana Size and Weight Laws (Title 9, Article 20).","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle, including its load, on Indiana highways?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","12 feet 6 inches"],"answer":2,"explanation":"Indiana sets the maximum height at 13 feet 6 inches, and there is no exemption to the legal height. Source: IC 9-20-3-3; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"What is the maximum gross weight of a vehicle or combination allowed under Indiana law without an overweight permit?","options":["73,280 pounds","80,000 pounds","88,000 pounds","84,000 pounds"],"answer":1,"explanation":"Indiana's maximum legal gross weight is 80,000 pounds; anything heavier requires a permit. The 73,280-pound figure applies only under the grandfather provision for certain configurations. Source: IC 9-20-4 (General Weight Restrictions); Indiana State Police Summary of Size and Weight Laws.","handbook":"","hbref":""},{"q":"What is the maximum weight Indiana allows on a single axle?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"Indiana's maximum single axle weight is 20,000 pounds. (The 18,000-pound and 16,000-pound figures appear only in grandfather-law scenarios.) Source: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"What is the maximum weight Indiana allows on a tandem axle group?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"answer":0,"explanation":"Indiana's maximum tandem axle weight is 34,000 pounds, matching the federal standard. Source: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"Indiana limits wheel weight to how much per inch of tire width, measured between the flanges of the rim?","options":["600 pounds","1,000 pounds","500 pounds","800 pounds"],"answer":3,"explanation":"Indiana caps wheel weight at 800 pounds per inch of tire width measured between the flanges of the rim, whether laden or unladen. Source: IC 9-20-11-4; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"What is the maximum length of a single vehicle operating under its own power on Indiana highways (excluding length-exclusive devices)?","options":["40 feet","45 feet","35 feet","53 feet"],"answer":0,"explanation":"A single motor vehicle may not exceed 40 feet, except for length-exclusive devices per 23 CFR 658.13. A recreational vehicle is allowed up to 45 feet. Source: IC 9-20-3-1 / IC 9-20-8; Indiana State Police Summary of Size and Weight Laws.","handbook":"","hbref":""},{"q":"In a truck-tractor and semitrailer combination, what is the maximum length of the semitrailer (including load) under Indiana law?","options":["48 feet","57 feet","45 feet","53 feet"],"answer":3,"explanation":"Indiana allows a semitrailer up to 53 feet in a truck-tractor combination, and no overall length limit is imposed on that combination. Source: IC 9-20-8; Indiana State Police Summary of Size and Weight Laws.","handbook":"","hbref":""},{"q":"Which Indiana agency issues oversize and overweight (OSOW) permits for vehicles exceeding the legal size and weight limits?","options":["Indiana Bureau of Motor Vehicles","Indiana Department of Revenue, Motor Carrier Services","Indiana State Police","Indiana Department of Natural Resources"],"answer":1,"explanation":"OSOW permits are issued by the Indiana Department of Revenue's Motor Carrier Services, under rules set by INDOT and Indiana law. Source: IC 9-20-6; Indiana DOR Motor Carrier Services OSOW program (in.gov/dor).","handbook":"","hbref":""},{"q":"In which year did Indiana adopt the federal Bridge Formula into state law to calculate maximum legal gross and axle weights?","options":["1975","1956","1982","1991"],"answer":0,"explanation":"Indiana adopted the Bridge Formula as state law in 1975, and retains a grandfather provision for weight limits in effect on January 4, 1975. Source: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"Under Indiana's adoption of the federal Bridge Formula W = 500{[(LN) / (N-1)] + 12N + 36}, what does the variable 'N' represent?","options":["The net cargo weight in the vehicle","The total length of the combination in feet","The number of tires on the drive axle","The number of axles in the group under consideration"],"answer":3,"explanation":"In the Bridge Formula, N is the number of axles in the group, L is the distance between the extreme axles of the group, and W is the allowable gross weight on that group. Source: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"Indiana's Bridge Formula allows two consecutive sets of tandem axles to each carry 34,000 pounds provided the first and last axles of those tandems are at least how far apart?","options":["30 feet","40 feet","36 feet","51 feet"],"answer":2,"explanation":"Two consecutive sets of tandem axles may each carry up to 34,000 pounds if the first and last axles of the sets are at least 36 feet apart. Source: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"A combination of two vehicles coupled together, including load, generally may not exceed what total length on Indiana highways?","options":["65 feet","55 feet","75 feet","60 feet"],"answer":3,"explanation":"A combination of two coupled vehicles, including load, may not exceed 60 feet (with limited exceptions such as boat/vehicle haulers and drive-away service). Source: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"A combination of three or more vehicles coupled together, including load, may not exceed what total length under Indiana law?","options":["60 feet","70 feet","65 feet","75 feet"],"answer":2,"explanation":"Indiana limits a combination of three or more coupled vehicles, including load, to 65 feet. Source: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"Indiana grants a 10% gross-weight tolerance for a vehicle hauling farm commodities from the place of production to the first point of delivery, EXCEPT in which situation?","options":["When the vehicle is operated on any part of the interstate system","When the load is hauled at night","When the vehicle has more than five axles","When the trip exceeds 50 miles"],"answer":0,"explanation":"The 10% farm-commodity gross-weight tolerance does not apply on any part of the interstate system, nor where posted bridge/highway limits under IC 9-20-1-4 apply. Source: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"If a combination vehicle is allowed an 80,000-pound gross weight, what is its maximum gross weight when hauling qualifying farm commodities under Indiana's 10% tolerance?","options":["84,000 pounds","90,000 pounds","88,000 pounds","86,000 pounds"],"answer":2,"explanation":"Indiana adds 10% to the allowable gross weight for qualifying farm-commodity hauls, so 80,000 pounds becomes 88,000 pounds (off-interstate, non-posted routes only). Source: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"Indiana treats certain forest products as farm commodities for the 10% weight tolerance. For which of these does the 10% tolerance apply at ALL times for gross and axle weight?","options":["Finished lumber and plywood","Wood chips, bark, and sawdust","Furniture and cabinetry","Paper and cardboard"],"answer":1,"explanation":"Farm commodities include logs, wood chips, bark, sawdust, and bulk milk; for wood chips, bark, and sawdust the 10% tolerance applies at all times to gross and axle weights. Source: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"Under Indiana's grandfather provision retaining weight limits in effect on January 4, 1975, what is the maximum gross weight for affected vehicle configurations?","options":["80,000 pounds","70,000 pounds","64,000 pounds","73,280 pounds"],"answer":3,"explanation":"Indiana's grandfather law preserves a maximum gross weight of 73,280 pounds for configurations that would otherwise be penalized by the Bridge Formula. Source: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"Except on interstate highways, what is the maximum single-axle weight allowed for a qualifying municipal refuse/garbage collection vehicle in Indiana?","options":["20,000 pounds","24,000 pounds","22,400 pounds","26,000 pounds"],"answer":1,"explanation":"Except on the interstate system, qualifying refuse vehicles may carry up to 24,000 pounds on a single axle and 42,000 pounds on a tandem axle, but remain subject to wheel-weight limits under IC 9-20-11-4. Source: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws.","handbook":"","hbref":""},{"q":"In Indiana, which CDL class is required to operate a combination of vehicles with a Gross Combination Weight Rating (GCWR) of 26,001 pounds or more, where the vehicle(s) being towed have a GVWR over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Indiana defines a Class A CDL as any combination of vehicles with a GCWR of 26,001 lbs or more, provided the GVWR of the towed unit(s) exceeds 10,000 lbs. Source: Indiana CDL Manual (Indiana BMV); 49 CFR 383.91 as adopted by Indiana.","handbook":"","hbref":""},{"q":"Under Indiana rules, a single vehicle with a GVWR of 26,001 pounds or more (or such a vehicle towing a unit not over 10,000 pounds GVWR) requires which CDL class?","options":["Class C","Class B","Class A","Chauffeur license"],"answer":1,"explanation":"Indiana defines a Class B CDL as any single vehicle with a GVWR of 26,001 lbs or more, or such a vehicle towing a unit not in excess of 10,000 lbs GVWR. Source: Indiana CDL Manual (Indiana BMV).","handbook":"","hbref":""},{"q":"In Indiana, a vehicle that does not meet the Class A or Class B weight thresholds but is designed to carry 16 or more passengers (including the driver) or carries placarded hazardous materials requires which CDL class?","options":["Class A","Class B","Class C","No CDL is required"],"answer":2,"explanation":"A Class C CDL in Indiana covers vehicles below the Class A/B weight limits that are designed to transport 16+ passengers (including the driver) or that carry hazardous materials requiring placarding. Source: Indiana CDL Manual (Indiana BMV).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Indiana CDL restricted to intrastate (within-Indiana) driving only?","options":["16 years old","17 years old","18 years old","21 years old"],"answer":2,"explanation":"Indiana requires applicants to be at least 18 to hold a CDL or CLP for intrastate operation; drivers aged 18-20 are limited to operating commercial vehicles within Indiana. Source: Indiana CDL Manual (Indiana BMV); IC 9-24.","handbook":"","hbref":""},{"q":"What is the minimum age to drive a commercial motor vehicle in interstate commerce (across state lines) with an Indiana CDL?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"A driver must be at least 21 to operate a commercial motor vehicle interstate, to transport hazardous materials, or to carry passengers across state lines. Drivers 18-20 are restricted to intrastate driving in Indiana. Source: Indiana CDL Manual (Indiana BMV); 49 CFR 391.11.","handbook":"","hbref":""},{"q":"Which endorsement does Indiana require to drive a tank vehicle carrying a liquid or gas in an individual tank of more than 119 gallons (with an aggregate of 1,000+ gallons)?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"answer":0,"explanation":"Indiana's N (Tank Vehicle) endorsement is required for vehicles designed to transport liquids or gases in a tank with an individual rated capacity of more than 119 gallons and an aggregate capacity of 1,000 gallons or more. Source: Indiana BMV CDL Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"Which Indiana CDL endorsement is required to operate a vehicle pulling two or three separate trailers (doubles/triples)?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement S"],"answer":2,"explanation":"The T endorsement authorizes operation of a combination with two or three separate trailers attached (doubles/triples). It is obtained by passing the doubles/triples knowledge test. Source: Indiana BMV CDL Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"Which Indiana CDL endorsement is required to drive a vehicle designed to transport 16 or more passengers, including the driver?","options":["Endorsement S","Endorsement P","Endorsement N","Endorsement H"],"answer":1,"explanation":"The P (Passenger) endorsement is required to operate a vehicle designed to carry 16 or more passengers, including the driver. It requires a knowledge test, a skills test in a representative vehicle, and ELDT for first-time applicants. Source: Indiana BMV CDL Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"In Indiana, what additional federal screening must an applicant complete to obtain the H (Hazardous Materials) endorsement?","options":["A TSA security threat assessment including fingerprinting","An FBI polygraph examination","A state-only criminal records check with no fingerprints","A DEA controlled-substance interview"],"answer":0,"explanation":"Adding the H endorsement requires passing the HazMat knowledge test and completing a TSA security threat assessment, which includes fingerprinting and verification of lawful status. Source: Indiana BMV CDL Endorsements and Restrictions; 49 CFR 1572 (TSA).","handbook":"","hbref":""},{"q":"How often must an Indiana CDL holder renew the TSA security threat assessment to keep the Hazardous Materials (H) endorsement?","options":["Every year","Every 2 years","Every 5 years","Every 10 years"],"answer":2,"explanation":"The TSA security threat assessment for the HazMat endorsement is valid for five years and must be renewed (with a new HazMat knowledge test) at least every five years. Source: Indiana BMV CDL Endorsements and Restrictions; TSA HazMat Endorsement program.","handbook":"","hbref":""},{"q":"Which combined endorsement code does Indiana issue when a driver holds both the Hazardous Materials and Tank Vehicle endorsements?","options":["Endorsement X","Endorsement HN","Endorsement Z","Endorsement W"],"answer":0,"explanation":"Indiana issues the X endorsement to represent the combination of H (HazMat) and N (Tank Vehicle) privileges. Source: Indiana BMV CDL Endorsements and Restrictions.","handbook":"","hbref":""},{"q":"Before taking the CDL skills test in Indiana, how long must an applicant hold a valid Commercial Learner's Permit (CLP)?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"An applicant must hold the CLP for at least 14 days before attempting the CDL skills exam. This is the federal minimum adopted by Indiana. Source: Indiana CDL Manual / Indiana BMV; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"According to the Indiana BMV, how long is a Commercial Learner's Permit (CLP) valid after it is issued?","options":["30 days","90 days","One year","Five years"],"answer":2,"explanation":"The Indiana BMV states a CLP is valid for one year, and CDL knowledge exam results are likewise valid for one year. Source: Indiana BMV, Obtaining a Commercial Learner's Permit.","handbook":"","hbref":""},{"q":"What restriction applies to an Indiana CLP holder while operating a commercial motor vehicle?","options":["They may drive alone on interstate highways only","They must be accompanied by a CDL holder with the proper class and endorsements","They may drive only between sunrise and sunset","They may operate only vehicles under 26,001 pounds GVWR"],"answer":1,"explanation":"A CLP holder may operate a commercial motor vehicle only when accompanied by a person holding a valid CDL with the proper class and endorsements who is seated next to the CLP holder. Source: Indiana BMV, Obtaining a Commercial Learner's Permit; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"When applying for an Indiana CDL or CLP, how many documents must an applicant present to prove Indiana residency?","options":["One document","Two documents","Three documents","No residency proof is required"],"answer":1,"explanation":"Indiana requires two documents proving Indiana residency, plus one proving identity, one proving lawful status, and one proving the full Social Security number. Source: Indiana BMV document requirements.","handbook":"","hbref":""},{"q":"In addition to proof of identity and Indiana residency, which two items must an Indiana CDL applicant document?","options":["Lawful status in the U.S. and full Social Security number","A high school diploma and vehicle title","A vision specialist letter and employer affidavit","Voter registration and a utility deposit receipt"],"answer":0,"explanation":"Indiana requires one document proving lawful status (lawful presence) in the U.S. and one document proving the applicant's full Social Security number, in addition to identity and two residency documents. Source: Indiana BMV document requirements.","handbook":"","hbref":""},{"q":"Effective February 7, 2022, Entry-Level Driver Training (ELDT) must be completed by Indiana applicants in which situation?","options":["Renewing an existing Class A CDL with no class change","Obtaining a first Class A or Class B CDL, or a first H, P, or S endorsement","Adding only the T (doubles/triples) endorsement","Self-certifying as excepted intrastate"],"answer":1,"explanation":"ELDT applies to drivers obtaining a first Class A or Class B CDL, upgrading to a higher class, or obtaining a Hazardous Materials (H), Passenger (P), or School Bus (S) endorsement for the first time on or after February 7, 2022. Source: FMCSA ELDT rule; Indiana BMV.","handbook":"","hbref":""},{"q":"Where must an Indiana applicant complete required Entry-Level Driver Training (ELDT)?","options":["At any private driving school of the applicant's choosing","With a provider listed on the FMCSA Training Provider Registry","At an Indiana BMV branch testing center","Through an online TSA-approved course"],"answer":1,"explanation":"ELDT theory and behind-the-wheel training must be delivered by an entity listed on the FMCSA Training Provider Registry (TPR); only listed providers may report completion. Source: FMCSA Training Provider Registry; Indiana BMV.","handbook":"","hbref":""},{"q":"Which medical self-certification category does an Indiana CDL holder choose if they operate only within Indiana and must meet state driver qualification requirements with a medical examiner's certificate?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":2,"explanation":"Non-Excepted Intrastate (NA) applies to drivers operating only in intrastate (within-Indiana) commerce who must meet Indiana's driver qualification rules and provide a medical examiner's certificate. Source: Indiana BMV CDL self-certification; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Which self-certification category requires an Indiana CDL holder to maintain a valid federal DOT Medical Examiner's Certificate from a provider on the FMCSA National Registry?","options":["Excepted Intrastate (EA)","Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Restricted Agricultural (RA)"],"answer":2,"explanation":"A driver self-certifying as Non-Excepted Interstate (NI) operates across state lines in non-excepted commerce and must hold and maintain a valid Medical Examiner's Certificate issued by a certified examiner on the FMCSA National Registry. Source: Indiana BMV CDL self-certification; 49 CFR 391.41.","handbook":"","hbref":""},{"q":"In Indiana, what is the maximum blood alcohol concentration (BAC) at which it is legal to operate a commercial motor vehicle (CMV)?","options":["Below 0.04%","Below 0.08%","Below 0.02%","Below 0.10%"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Section 1.3.2) states it is illegal to operate a CMV if your blood alcohol concentration is .04% or more, so a CMV driver must stay below 0.04% (half the 0.08% limit for non-commercial drivers). Source: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2.","handbook":"","hbref":""},{"q":"Under Indiana's implied-consent rule, what does operating a CMV mean a driver has agreed to?","options":["To submit to alcohol testing","To waive the right to an attorney","To a vehicle inspection at any time","To a mandatory drug treatment program"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.2) states that if you operate a CMV, you shall be deemed to have given your consent to alcohol testing. Source: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2; IC 9-30-6.","handbook":"","hbref":""},{"q":"For a first major offense such as driving a CMV with a BAC of 0.04% or higher, for how long will an Indiana CDL holder lose their CDL?","options":["At least 1 year","At least 6 months","At least 90 days","At least 3 years"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.2) states you will lose your CDL for at least one year for a first major offense, including driving a CMV with a BAC of .04% or higher. Source: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"If a first major offense occurs while the driver is operating a CMV placarded for hazardous materials, what is the minimum disqualification in Indiana?","options":["At least 3 years","At least 1 year","At least 5 years","Lifetime"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.2) states you will lose your CDL for at least three years if a first major offense occurs while operating a CMV that is placarded for hazardous materials. Source: Indiana BMV CDL Manual, Sec. 1.3.2.","handbook":"","hbref":""},{"q":"What is the consequence for a second major offense (such as a second CMV DWI) under Indiana CDL rules?","options":["Loss of CDL for life","Loss of CDL for 10 years","Loss of CDL for 3 years","Loss of CDL for 5 years"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.2) states you will lose your CDL for life for a second major offense. Source: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"Which of the following is treated as a first major offense that costs an Indiana CDL holder their license for at least one year?","options":["Refusing to undergo blood alcohol testing","Following a vehicle too closely","Driving 16 mph over the posted limit","An improper lane change"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.2) lists refusing to undergo blood alcohol testing as a major offense carrying at least a one-year disqualification; the other choices are serious traffic violations, not major offenses. Source: Indiana BMV CDL Manual, Sec. 1.3.2.","handbook":"","hbref":""},{"q":"In Indiana, what happens to a CDL holder who uses a CMV to commit a felony involving controlled substances?","options":["Loss of CDL for life","Loss of CDL for 3 years","Loss of CDL for 1 year","Loss of CDL for 5 years"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.2) states you will lose your CDL for life if you use a CMV to commit a felony involving controlled substances. Source: Indiana BMV CDL Manual, Sec. 1.3.2.","handbook":"","hbref":""},{"q":"A CMV driver in Indiana is found to have a detectable amount of alcohol under 0.04%. What is the immediate consequence?","options":["Placed out-of-service for 24 hours","CDL disqualified for 60 days","A $2,750 civil penalty","CDL disqualified for 1 year"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.2) states you will be put out-of-service for 24 hours if you have any detectable amount of alcohol under .04%. Source: Indiana BMV CDL Manual, Sec. 1.3.2.","handbook":"","hbref":""},{"q":"How does the Indiana CDL Manual define 'excessive speeding' as a serious traffic violation?","options":["15 mph or more above the posted limit","10 mph or more above the posted limit","20 mph or more above the posted limit","25 mph or more above the posted limit"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.3) defines excessive speeding as 15 mph or more above the posted limit. Source: Indiana BMV CDL Manual, Sec. 1.3.3.","handbook":"","hbref":""},{"q":"For two serious traffic violations in a CMV within a three-year period, how long will an Indiana CDL holder lose their CDL?","options":["At least 60 days","At least 30 days","At least 90 days","At least 120 days"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.3) states you will lose your CDL for at least 60 days for two serious traffic violations within a three-year period involving a CMV. Source: Indiana BMV CDL Manual, Sec. 1.3.3.","handbook":"","hbref":""},{"q":"For three or more serious traffic violations in a CMV within a three-year period, what is the Indiana disqualification?","options":["At least 120 days","At least 60 days","At least 90 days","At least 1 year"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.3) states you will lose your CDL for at least 120 days for three or more serious traffic violations within a three-year period involving a CMV. Source: Indiana BMV CDL Manual, Sec. 1.3.3.","handbook":"","hbref":""},{"q":"Which of the following is listed as a serious traffic violation in the Indiana CDL Manual?","options":["Reckless driving","Driving a CMV with a BAC of 0.04%","Leaving the scene of a CMV accident","Refusing a blood alcohol test"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.3) lists reckless driving among the serious traffic violations; the other three are major offenses under Sec. 1.3.2. Source: Indiana BMV CDL Manual, Sec. 1.3.3.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a first violation of an out-of-service order in Indiana?","options":["At least 90 days","At least 60 days","At least 30 days","At least 180 days"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.4) states you will lose your CDL for at least 90 days for your first violation of an out-of-service order. Source: Indiana BMV CDL Manual, Sec. 1.3.4.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for two out-of-service order violations within a ten-year period in Indiana?","options":["At least 1 year","At least 90 days","At least 6 months","At least 3 years"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.4) states you will lose your CDL for at least one year for two violations of an out-of-service order in a ten-year period. Source: Indiana BMV CDL Manual, Sec. 1.3.4.","handbook":"","hbref":""},{"q":"Three or more out-of-service order violations within a ten-year period result in what minimum disqualification in Indiana?","options":["At least 3 years","At least 1 year","At least 5 years","Lifetime"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.4) states you will lose your CDL for at least three years for three or more violations of an out-of-service order in a ten-year period. Source: Indiana BMV CDL Manual, Sec. 1.3.4.","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a first railroad-highway grade crossing violation in Indiana?","options":["At least 60 days","At least 30 days","At least 90 days","At least 120 days"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.5) states you will lose your CDL for at least 60 days for your first railroad-highway grade crossing violation. Source: Indiana BMV CDL Manual, Sec. 1.3.5.","handbook":"","hbref":""},{"q":"A second railroad-highway grade crossing violation within a three-year period carries what minimum disqualification in Indiana?","options":["At least 120 days","At least 60 days","At least 90 days","At least 1 year"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.5) states you will lose your CDL for at least 120 days for a second railroad-highway grade crossing violation within a three-year period. Source: Indiana BMV CDL Manual, Sec. 1.3.5.","handbook":"","hbref":""},{"q":"A third railroad-highway grade crossing violation within a three-year period carries what minimum disqualification in Indiana?","options":["At least 1 year","At least 120 days","At least 6 months","At least 3 years"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 1.3.5) states you will lose your CDL for at least one year for a third railroad-highway grade crossing violation within a three-year period. Source: Indiana BMV CDL Manual, Sec. 1.3.5.","handbook":"","hbref":""},{"q":"Under Indiana's rules, after how many convictions of a state texting-while-driving-a-CMV law is a CDL disqualified, and for how long on the second offense?","options":["Two or more convictions; 60 days for the second offense within 3 years","One conviction; 120 days immediately","Two convictions; 1 year for the second offense","Three convictions; 30 days for the third offense"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Sec. 2.9.5) states your CDL will be disqualified after two or more convictions of any state texting law while operating a CMV, with disqualification of 60 days for the second offense within 3 years (120 days for three or more within 3 years). Source: Indiana BMV CDL Manual, Sec. 2.9.5.","handbook":"","hbref":""},{"q":"According to the Indiana CDL Manual, a CMV driver who violates the hand-held mobile phone or texting restriction is subject to a civil penalty of up to what amount?","options":["$2,750","$1,000","$5,000","$11,000"],"answer":0,"explanation":"The Indiana BMV CDL Manual (Secs. 2.9.4-2.9.5) states each violation of the hand-held phone or texting prohibition subjects the driver to a civil penalty up to $2,750; employers may be subject to penalties up to $11,000. Source: Indiana BMV CDL Manual, Secs. 2.9.4 and 2.9.5.","handbook":"","hbref":""},{"q":"On a rural Indiana interstate (outside an urbanized area), what is the maximum speed limit for a loaded tractor-trailer with a declared gross weight greater than 26,000 pounds?","options":["55 mph","60 mph","65 mph","70 mph"],"answer":2,"explanation":"Under IC 9-21-5-2, a vehicle other than a bus with a declared gross weight greater than 26,000 pounds is limited to 65 mph on rural interstate highways, while passenger cars may run 70 mph. This is the basis for Indiana's split (truck vs. car) interstate speed signs.","handbook":"","hbref":""},{"q":"A passenger car may drive 70 mph on a rural Indiana interstate. At the same location, a charter bus carrying passengers may legally travel up to:","options":["55 mph","60 mph","65 mph","70 mph"],"answer":3,"explanation":"IC 9-21-5-2 applies the 65 mph truck limit to vehicles 'other than a bus' over 26,000 lbs. Buses are not subject to the reduced truck limit, so a bus may travel the posted 70 mph on rural interstates. Source: Indiana Code 9-21-5-2.","handbook":"","hbref":""},{"q":"You are driving a placarded hazardous-materials tanker on an Indiana highway. At a railroad grade crossing where stopping is required, you must stop:","options":["No closer than 15 feet and no more than 50 feet from the nearest rail","No closer than 10 feet and no more than 25 feet from the nearest rail","Exactly 50 feet from the nearest rail","No closer than 50 feet and no more than 100 feet from the nearest rail"],"answer":0,"explanation":"The Indiana CDL Manual (Section 9.6.12) requires placarded vehicles, chlorine carriers, and cargo-tank vehicles to stop 15 to 50 feet from the nearest rail, then proceed only when sure no train is coming. Source: Indiana CDL Manual.","handbook":"","hbref":""},{"q":"Indiana's Move Over law (IC 9-21-8-35) requires you to change lanes away from a stopped emergency or disabled vehicle showing flashing lights. If you cannot safely change lanes, you must:","options":["Reduce your speed to 10 mph below the posted speed limit","Stop completely until it is safe to proceed","Sound your horn and maintain the posted speed","Reduce your speed to 20 mph below the posted speed limit"],"answer":0,"explanation":"Under IC 9-21-8-35, when changing lanes is not possible or unsafe, a driver must slow to at least 10 mph below the posted speed limit while passing. INDOT promotes this as 'Move Over or Slow Down.' Source: IC 9-21-8-35; INDOT.","handbook":"","hbref":""},{"q":"On an Indiana interstate with two lanes in your direction of travel, a truck-tractor is generally restricted to which lane, except when passing, entering/leaving, or avoiding a special hazard?","options":["Either lane, freely","The left (passing) lane","The far right lane","The center of the roadway"],"answer":2,"explanation":"IC 9-21-8-12 prohibits operating a truck or truck-tractor on an interstate highway in any lane except the far right lane, except when passing a slower vehicle, entering or leaving the highway, or where a special hazard requires another lane. Source: Indiana Code 9-21-8-12.","handbook":"","hbref":""},{"q":"On an Indiana interstate with three or more lanes in your direction of travel, a truck-tractor is restricted to:","options":["The far right lane only","The two right lanes only","Any lane except the far left","The center lane only"],"answer":1,"explanation":"IC 9-21-8-13 limits trucks on interstates with at least three lanes in one direction to the two far-right lanes, except when entering or leaving the highway or avoiding a special hazard. This is more permissive than the single-lane rule for two-lane stretches. Source: Indiana Code 9-21-8-13.","handbook":"","hbref":""},{"q":"In Indiana, a driver who meets or overtakes a stopped school bus displaying its extended stop arm and flashing red lights must stop and remain stopped until:","options":["The bus driver waves them on","Five seconds have passed","The stop arm is withdrawn and the red lights stop flashing","They have counted to ten"],"answer":2,"explanation":"Under IC 9-21-12-1, a driver must stop before reaching the bus when the arm signal device is extended and may not proceed until the device is no longer extended (lights stop flashing). Violation is a Class A infraction. Source: Indiana Code 9-21-12-1.","handbook":"","hbref":""},{"q":"You are driving toward a stopped school bus (red lights flashing) that is on the OTHER side of a four-lane road. Under Indiana's school-bus law, you do NOT have to stop only if the two roadways are separated by:","options":["A painted center line or a two-way left-turn lane","Any four or more lanes of pavement","A flush painted median at least 4 feet wide","A physical barrier or an unimproved/dividing median not intended for travel"],"answer":3,"explanation":"IC 9-21-12-3 excuses an approaching driver from stopping only when the roadways are divided by an unimproved intervening space, a physical barrier, or a dividing section constructed to impede traffic, and the bus is on the opposite side. A mere painted line does NOT qualify—you must still stop. Source: Indiana Code 9-21-12-3.","handbook":"","hbref":""},{"q":"If you must stop your CMV on the shoulder of a divided Indiana highway, how soon must you place your emergency warning devices?","options":["Within 2 minutes","Within 5 minutes","Within 10 minutes","Immediately, before exiting the cab"],"answer":2,"explanation":"The Indiana CDL Manual (Section 2.5) states that if you stop on a road or shoulder you must put out emergency warning devices within 10 minutes. Source: Indiana CDL Manual.","handbook":"","hbref":""},{"q":"When stopped on a one-way or divided Indiana highway, where do you place your three warning triangles?","options":["10 ft, 100 ft, and 200 ft toward the approaching traffic","10 ft, 50 ft, and 100 ft toward the approaching traffic","100 ft ahead, 100 ft behind, and at the vehicle","At the vehicle only, with four-way flashers on"],"answer":0,"explanation":"The Indiana CDL Manual instructs that on a one-way or divided highway, warning devices go at 10 feet, 100 feet, and 200 feet toward the approaching traffic. Source: Indiana CDL Manual, Section 2.5.","handbook":"","hbref":""},{"q":"When stopped on a two-lane Indiana road carrying traffic in both directions, your warning triangles should be placed:","options":["At 10 ft, 100 ft, and 200 ft behind the vehicle only","At 50 ft ahead and 50 ft behind only","At 200 ft ahead and 200 ft behind only","Within 10 ft of the vehicle, and 100 ft ahead and 100 ft behind"],"answer":3,"explanation":"On an undivided two-way road, the Indiana CDL Manual requires a triangle within 10 feet of the front or rear corner to mark the vehicle, plus one 100 feet ahead and one 100 feet behind, on the shoulder or in the lane. Source: Indiana CDL Manual, Section 2.5.","handbook":"","hbref":""},{"q":"A school bus you are driving in Indiana approaches a railroad grade crossing. You must stop your bus:","options":["Between 15 and 50 feet before the crossing","No closer than 5 feet from the rail","Exactly 25 feet from the rail","Only if a train is visible"],"answer":0,"explanation":"The Indiana CDL Manual (Section 4.3.5) directs bus drivers to stop the bus between 15 and 50 feet before railroad crossings, then look and listen in both directions before proceeding. Source: Indiana CDL Manual.","handbook":"","hbref":""},{"q":"Under Indiana's amended Move Over law, a driver who fails to move over or slow down for a stopped vehicle with flashing lights (with no resulting injury) commits a:","options":["Class A infraction","Class B infraction","Class C infraction","Class D felony"],"answer":1,"explanation":"A basic violation of IC 9-21-8-35 is a Class B infraction; it rises to a felony only if the failure causes serious bodily injury or death to a covered worker. Source: IC 9-21-8-35; INDOT.","handbook":"","hbref":""},{"q":"Without an oversize permit from the Indiana Department of Revenue/INDOT, the maximum legal WIDTH for a commercial load on Indiana highways is:","options":["8 feet 0 inches","8 feet 6 inches","10 feet 0 inches","9 feet 0 inches"],"answer":1,"explanation":"Indiana's legal (non-permit) maximum width is 8 feet 6 inches (102 inches). Loads exceeding this require an oversize/overweight permit through Indiana DOR Motor Carrier Services. Source: INDOT / Indiana DOR OSOW regulations.","handbook":"","hbref":""},{"q":"Without an oversize permit in Indiana, the maximum legal HEIGHT for a vehicle and load is:","options":["13 feet 0 inches","13 feet 6 inches","14 feet 0 inches","12 feet 6 inches"],"answer":1,"explanation":"Indiana's legal maximum height is 13 feet 6 inches; anything taller needs an oversize permit. Drivers must still verify clearances, as posted bridge heights govern. Source: INDOT / Indiana DOR OSOW regulations.","handbook":"","hbref":""},{"q":"Without an overweight permit, the maximum legal gross vehicle weight for a standard rig on Indiana highways is:","options":["73,280 pounds","90,000 pounds","100,000 pounds","80,000 pounds"],"answer":3,"explanation":"Indiana's legal maximum gross vehicle weight is 80,000 pounds (consistent with the federal interstate limit). Heavier loads require an overweight permit from Indiana DOR Motor Carrier Services. Source: INDOT / Indiana DOR OSOW regulations.","handbook":"","hbref":""},{"q":"On a multilane Indiana highway, a CMV traveling slower than the normal flow of traffic is required by Indiana law to:","options":["Use the left-most lane to stay out of merge traffic","Travel in the center lane at all times","Maintain at least the posted minimum in any lane","Use the right-hand lane(s) available for travel"],"answer":3,"explanation":"IC 9-21-5-9 requires vehicles moving slower than the maximum established speed to use the right-hand lanes, and bars continuing in the left-most lane when being overtaken. Source: Indiana Code 9-21-5-9.","handbook":"","hbref":""},{"q":"A school bus in a rural Indiana area activates its alternating flashing AMBER lights. These lights mean:","options":["The bus is broken down—pass with caution","Children are crossing—stop immediately","The bus is exempt from the railroad stop","The bus is preparing to stop to load or unload; be ready to stop"],"answer":3,"explanation":"Amber (yellow) lights are a pre-warning that the bus is about to stop to load or unload, activated roughly 300 feet ahead in rural areas; the RED lights and extended stop arm then require traffic to stop. Source: Indiana CDL Manual / INDOT school bus safety.","handbook":"","hbref":""},{"q":"A police officer is directing traffic at an Indiana railroad grade crossing and signals your placarded vehicle to proceed without stopping. You should:","options":["Stop 15 to 50 feet anyway, ignoring the officer","Stop only if you see a train","Follow the officer's direction and proceed without the mandatory stop","Reverse and find another crossing"],"answer":2,"explanation":"The mandatory 15-to-50-foot stop for placarded and passenger vehicles does not apply when a police officer or flagman directs traffic to proceed (also recognized under 49 CFR 392.10, applied in Indiana). Source: Indiana CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"A motorist who recklessly passes an Indiana school bus with its stop arm extended and red lights flashing faces, in addition to fines, a possible:","options":["Driver's license suspension of up to 90 days for a first offense","Mandatory 30-day jail term with no license action","Only a written warning","Permanent CDL disqualification for any first offense"],"answer":0,"explanation":"Passing a stopped school bus with the stop arm extended is a Class A infraction (IC 9-21-12-1); reckless violations fall under IC 9-21-8-52, and first offenders can face a license suspension of up to 90 days (up to one year for repeat offenders). Source: IC 9-21-12-1 and IC 9-21-8-52.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver's Licenses (CDLs) in Indiana?","options":["The Indiana Bureau of Motor Vehicles (BMV)","The Indiana Department of Transportation (INDOT)","The Federal Motor Carrier Safety Administration (FMCSA)","The Indiana State Police Commercial Vehicle Division"],"answer":0,"explanation":"CDLs in Indiana are issued by the Indiana Bureau of Motor Vehicles (BMV). The CDL manual and all licensing transactions are handled at BMV branches. Source: Indiana Specific CDL Applicant Information manual (SP 283), Indiana BMV.","handbook":"","hbref":""},{"q":"In Indiana, how long is a Commercial Learner's Permit (CLP) valid?","options":["One year","180 days","Two years","Six months, renewable indefinitely"],"answer":0,"explanation":"Per the current Indiana CDL manual, 'A CLP is valid for one year.' Source: Indiana Specific CDL Applicant Information manual (SP 283), Commercial Learner's Permit section, Indiana BMV.","handbook":"","hbref":""},{"q":"How long must an applicant hold the CLP before attempting the CDL skills test in Indiana?","options":["At least 14 days","At least 30 days","At least 10 days","At least 60 days"],"answer":0,"explanation":"The manual states, 'An applicant must hold the CLP 14 days prior to attempting to CDL skills test.' This mirrors the federal minimum and applies in Indiana. Source: Indiana CDL manual (SP 283), CDL Skills Testing section, Indiana BMV.","handbook":"","hbref":""},{"q":"How long is a CDL issued in Indiana valid before it must be renewed?","options":["Four years","Five years","Six years","Three years"],"answer":0,"explanation":"A CDL issued in Indiana is valid for four years. You may renew at any BMV branch up to one year before it expires. Source: Indiana BMV, Renewing or Replacing a CDL.","handbook":"","hbref":""},{"q":"The Indiana CDL skills examination is made up of which three parts?","options":["Vehicle (pre-trip) inspection, basic vehicle control, and on-road driving","Air brakes test, combination test, and on-road driving","General knowledge test, basic control, and pre-trip inspection","Pre-trip inspection, written endorsement test, and on-road driving"],"answer":0,"explanation":"Indiana's CDL skills test has three parts: the Vehicle Inspection Test (Section 11), the Basic Vehicle Control Skills Test (Section 12), and On-road Driving (Section 13). Source: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV.","handbook":"","hbref":""},{"q":"Before obtaining a first Class A or Class B CDL in Indiana, an applicant must complete which federally required training?","options":["Entry-Level Driver Training (ELDT) through an FMCSA-registered provider","A state-run defensive driving course at a BMV branch","A 160-hour Indiana apprenticeship verified by INDOT","An OSHA hazardous-cargo certification"],"answer":0,"explanation":"Applicants must complete Entry-Level Driver Training (ELDT) with a provider listed on the FMCSA Training Provider Registry before obtaining the CDL. Source: Indiana CDL manual (SP 283); 49 CFR Part 380; effective Feb 7, 2022.","handbook":"","hbref":""},{"q":"Who must perform the medical examination required for an Indiana CLP or CDL?","options":["A medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","Any licensed Indiana physician of the applicant's choice","A physician employed directly by the Indiana BMV","A medical examiner approved by INDOT's permit office"],"answer":0,"explanation":"All medical exams must be completed by a medical examiner certified on the FMCSA National Registry of Certified Medical Examiners (nationalregistry.fmcsa.dot.gov). Source: Indiana CDL manual (SP 283), Medical Examiner Requirements, Indiana BMV.","handbook":"","hbref":""},{"q":"How does the Medical Examiner's Certificate (MEC) get into the Indiana BMV's system?","options":["The certified examiner uploads the MEC to the FMCSA National Registry, allowing it to apply to the BMV system","The applicant mails the paper card to FMCSA headquarters in Washington, D.C.","INDOT forwards the certificate to the BMV after a roadside inspection","The certificate is automatically generated when the applicant passes the skills test"],"answer":0,"explanation":"The manual directs CLP/CDL holders to have the certified physician upload the MEC to the National Registry so it applies to the BMV system. Source: Indiana CDL manual (SP 283), Medical Examiner Requirements and Certification, Indiana BMV.","handbook":"","hbref":""},{"q":"How many self-certification categories must an Indiana CDL/CLP applicant choose from when declaring the type of driving they will do?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"Applicants self-certify to one of four categories: non-excepted interstate, excepted interstate, non-excepted intrastate, or excepted intrastate. Source: 49 CFR 383.71 (applied by Indiana BMV); Indiana BMV self-certification.","handbook":"","hbref":""},{"q":"Which self-certification category describes a driver who operates across state lines and must meet the federal medical/physical qualification requirements?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"answer":0,"explanation":"Non-excepted interstate drivers operate in interstate commerce and must meet the medical requirements of 49 CFR Part 391, keeping a valid MEC on file. Source: 49 CFR 383.71 / 391.41 (applied by Indiana BMV).","handbook":"","hbref":""},{"q":"Under Indiana rules, how often may an applicant attempt a CDL knowledge test?","options":["Once per day; a failed test may be retaken the next business day","Three times per day until passed","Once per week, by appointment only","Unlimited times in a single day"],"answer":0,"explanation":"The manual states an applicant may attempt a CDL knowledge test only once a day, and after a failure may take it again the next business day. Source: Indiana CDL manual (SP 283), CDL Knowledge Tests, Indiana BMV.","handbook":"","hbref":""},{"q":"Once passed, how long are Indiana CDL knowledge test results and skills test results valid?","options":["One year","Six months","Two years","90 days"],"answer":0,"explanation":"The manual states CDL knowledge test results are valid for one year and the CDL skills test results are valid for one year. Source: Indiana CDL manual (SP 283), CDL Knowledge Tests and CDL Skills Testing, Indiana BMV.","handbook":"","hbref":""},{"q":"Where must an applicant take the Indiana CDL skills test?","options":["At a BMV-approved (third-party authorized) CDL skills test site","At any full-service BMV license branch counter","At an INDOT weigh station or port of entry","At the FMCSA regional field office"],"answer":0,"explanation":"The CDL skills test must be taken at a BMV-approved CDL skills test site (authorized third-party sites); results are electronically transmitted to the BMV. Source: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an Indiana CDL/CLP for operating in intrastate commerce (and not a school bus or interstate)?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"An applicant must be at least 18 years old; to operate in interstate commerce or apply for a school bus endorsement the applicant must be at least 21. Source: Indiana CDL manual (SP 283), CLP requirements, Indiana BMV.","handbook":"","hbref":""},{"q":"After passing the CDL skills test in Indiana, what must the applicant do to actually receive the CDL?","options":["Return to a BMV license branch to complete the application before the CLP expires","Wait for the license to arrive by mail from FMCSA","Schedule a second on-road test at INDOT","Re-take the general knowledge test at the testing site"],"answer":0,"explanation":"The manual states that after passing the skills test the applicant must return to a BMV license branch to complete the CDL application, and must do so prior to expiration of the CLP. Source: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV.","handbook":"","hbref":""},{"q":"How far in advance must an Indiana CDL skills test appointment be scheduled with the testing site?","options":["At least two days in advance","At least two weeks in advance","At least one day in advance","At least 30 days in advance"],"answer":0,"explanation":"The manual states appointments must be scheduled at least two days in advance, and the skills test may only be taken once a business day. Source: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV.","handbook":"","hbref":""},{"q":"In Indiana, what happens if a CDL has been expired, disqualified, canceled, revoked, suspended, or invalidated for more than three years?","options":["The applicant must pass all applicable knowledge and skills tests as a first-time applicant","The applicant may renew online with only a vision screening","The CDL is automatically reinstated after a written test","The applicant only needs to retake the on-road driving test"],"answer":0,"explanation":"The manual's Retesting Requirement states any applicant whose CDL has been expired, surrendered, disqualified, canceled, revoked, suspended, or invalidated more than three years must pass all applicable knowledge and skills tests as a first-time applicant. Source: Indiana CDL manual (SP 283), Indiana BMV.","handbook":"","hbref":""},{"q":"A new resident with a valid out-of-state CDL has how long to transfer it to an Indiana CDL?","options":["30 days","60 days","90 days","10 days"],"answer":0,"explanation":"The manual states individuals have 30 days to transfer an out-of-state CDL; the driver's license knowledge exam is only required if the out-of-state CDL is expired. Source: Indiana CDL manual (SP 283), Transfer an Out-of-Country or Out-of-State CDL, Indiana BMV.","handbook":"","hbref":""},{"q":"Which statement about the Hazardous Materials (H) endorsement process in Indiana is correct?","options":["It requires TSA security threat assessment approval and is not added to a CLP","It can be added to a CLP once the air brakes test is passed","It only requires passing the general knowledge test","It is issued automatically with any Class A CDL"],"answer":0,"explanation":"The manual states a HazMat endorsement requires TSA security threat assessment approval for the term of the CDL, and that it will not be added to a CLP. Source: Indiana CDL manual (SP 283), CDL Endorsements, Indiana BMV; 49 CFR 1572 (TSA).","handbook":"","hbref":""},{"q":"Beyond passing the knowledge and skills tests, which step is specifically required of every Indiana CDL applicant during the licensing process?","options":["Watch an instructional video on how to recognize, prevent, and report human trafficking","Complete a 40-hour ride-along with a state trooper","Pass an INDOT oversize/overweight permit exam","Obtain notarized employer sponsorship before testing"],"answer":0,"explanation":"Indiana requires CDL applicants to watch an instructional video on how to recognize, prevent, and report human trafficking, in addition to completing ELDT and passing the required tests. Source: Indiana CDL manual (SP 283), application requirements, Indiana BMV.","handbook":"","hbref":""}],"ru":{"0":{"q":"На автомагистралях Индианы какова максимальная допустимая ширина транспортного средства с грузом (без учёта устройств, выступающих по ширине, таких как зеркала)?","options":["8 футов 0 дюймов","9 футов 0 дюймов","8 футов 6 дюймов","10 футов 0 дюймов"],"explanation":"Индиана ограничивает ширину транспортного средства с грузом до 8 футов 6 дюймов (102 дюйма), не считая выступающих по ширине устройств безопасности согласно 23 CFR 658. Источник: Indiana Code IC 9-20-3-2; Indiana State Police Summary of Indiana Size and Weight Laws (Title 9, Article 20)."},"1":{"q":"Какова максимальная допустимая высота транспортного средства, включая груз, на автомагистралях Индианы?","options":["13 футов 0 дюймов","14 футов 0 дюймов","13 футов 6 дюймов","12 футов 6 дюймов"],"explanation":"Индиана устанавливает максимальную высоту в 13 футов 6 дюймов, и исключений из допустимой по закону высоты не предусмотрено. Источник: IC 9-20-3-3; Indiana State Police Summary of Indiana Size and Weight Laws."},"2":{"q":"Каков максимальный полный вес транспортного средства или автопоезда, разрешённый законодательством Индианы без разрешения на перевес?","options":["73 280 фунтов","80 000 фунтов","88 000 фунтов","84 000 фунтов"],"explanation":"Максимально допустимый по закону полный вес в Индиане составляет 80 000 фунтов; всё, что тяжелее, требует разрешения. Значение в 73 280 фунтов применяется только в рамках «дедушкиной оговорки» (grandfather provision) для определённых конфигураций. Источник: IC 9-20-4 (General Weight Restrictions); Indiana State Police Summary of Size and Weight Laws."},"3":{"q":"Какой максимальный вес Индиана допускает на одиночную ось?","options":["18 000 фунтов","20 000 фунтов","22 400 фунтов","34 000 фунтов"],"explanation":"Максимальный вес на одиночную ось в Индиане составляет 20 000 фунтов. (Значения в 18 000 и 16 000 фунтов встречаются только в сценариях «дедушкиной оговорки».) Источник: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"4":{"q":"Какой максимальный вес Индиана допускает на сдвоенную (тандемную) группу осей?","options":["34 000 фунтов","32 000 фунтов","36 000 фунтов","40 000 фунтов"],"explanation":"Максимальный вес на тандемную ось в Индиане составляет 34 000 фунтов, что соответствует федеральному стандарту. Источник: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"5":{"q":"Индиана ограничивает нагрузку на колесо до какого значения на дюйм ширины шины, измеренной между закраинами обода?","options":["600 фунтов","1 000 фунтов","500 фунтов","800 фунтов"],"explanation":"Индиана ограничивает нагрузку на колесо до 800 фунтов на дюйм ширины шины, измеренной между закраинами обода, как в гружёном, так и в порожнем состоянии. Источник: IC 9-20-11-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"6":{"q":"Какова максимальная длина одиночного транспортного средства, движущегося своим ходом, на автомагистралях Индианы (без учёта устройств, выступающих по длине)?","options":["40 футов","45 футов","35 футов","53 фута"],"explanation":"Одиночное автотранспортное средство не может превышать 40 футов, за исключением выступающих по длине устройств согласно 23 CFR 658.13. Жилой автофургон (recreational vehicle) допускается длиной до 45 футов. Источник: IC 9-20-3-1 / IC 9-20-8; Indiana State Police Summary of Size and Weight Laws."},"7":{"q":"В составе из седельного тягача и полуприцепа какова максимальная длина полуприцепа (включая груз) по законодательству Индианы?","options":["48 футов","57 футов","45 футов","53 фута"],"explanation":"Индиана допускает полуприцеп длиной до 53 футов в составе с седельным тягачом, при этом ограничение на общую длину такого состава не устанавливается. Источник: IC 9-20-8; Indiana State Police Summary of Size and Weight Laws."},"8":{"q":"Какое ведомство Индианы выдаёт разрешения на превышение габаритов и веса (OSOW) для транспортных средств, превышающих установленные законом ограничения по размерам и весу?","options":["Indiana Bureau of Motor Vehicles","Indiana Department of Revenue, Motor Carrier Services","Indiana State Police","Indiana Department of Natural Resources"],"explanation":"Разрешения OSOW выдаются службой Motor Carrier Services при Indiana Department of Revenue, в соответствии с правилами, установленными INDOT и законодательством Индианы. Источник: IC 9-20-6; Indiana DOR Motor Carrier Services OSOW program (in.gov/dor)."},"9":{"q":"В каком году Индиана включила федеральную «мостовую формулу» (Bridge Formula) в законодательство штата для расчёта максимально допустимого полного и осевого веса?","options":["1975","1956","1982","1991"],"explanation":"Индиана включила «мостовую формулу» в законодательство штата в 1975 году и сохраняет «дедушкину оговорку» (grandfather provision) для весовых ограничений, действовавших на 4 января 1975 года. Источник: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"10":{"q":"В принятой Индианой федеральной «мостовой формуле» W = 500{[(LN) / (N-1)] + 12N + 36} что обозначает переменная «N»?","options":["Чистый вес груза в транспортном средстве","Общую длину состава в футах","Число шин на ведущей оси","Число осей в рассматриваемой группе"],"explanation":"В «мостовой формуле» N — это число осей в группе, L — расстояние между крайними осями группы, а W — допустимый полный вес на эту группу. Источник: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws."},"11":{"q":"«Мостовая формула» Индианы позволяет двум последовательным группам тандемных осей нести по 34 000 фунтов каждая при условии, что первая и последняя оси этих тандемов разнесены не менее чем на какое расстояние?","options":["30 футов","40 футов","36 футов","51 фут"],"explanation":"Две последовательные группы тандемных осей могут нести до 34 000 фунтов каждая, если первая и последняя оси этих групп разнесены не менее чем на 36 футов. Источник: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws."},"12":{"q":"Состав из двух сцепленных транспортных средств, включая груз, как правило, не может превышать какую общую длину на автомагистралях Индианы?","options":["65 футов","55 футов","75 футов","60 футов"],"explanation":"Состав из двух сцепленных транспортных средств, включая груз, не может превышать 60 футов (с ограниченными исключениями, такими как перевозчики лодок/автомобилей и перегон транспорта своим ходом). Источник: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws."},"13":{"q":"Состав из трёх и более сцепленных транспортных средств, включая груз, не может превышать какую общую длину по законодательству Индианы?","options":["60 футов","70 футов","65 футов","75 футов"],"explanation":"Индиана ограничивает состав из трёх и более сцепленных транспортных средств, включая груз, до 65 футов. Источник: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws."},"14":{"q":"Индиана предоставляет допуск в 10% по полному весу для транспортного средства, перевозящего сельскохозяйственную продукцию от места производства до первого пункта доставки, ЗА ИСКЛЮЧЕНИЕМ какой ситуации?","options":["Когда транспортное средство движется по любому участку системы межштатных автомагистралей","Когда груз перевозится ночью","Когда у транспортного средства более пяти осей","Когда поездка превышает 50 миль"],"explanation":"Допуск в 10% по полному весу для сельхозпродукции не применяется ни на одном участке системы межштатных автомагистралей, а также там, где действуют установленные ограничения по мостам/дорогам согласно IC 9-20-1-4. Источник: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"15":{"q":"Если для составного транспортного средства допускается полный вес 80 000 фунтов, каков его максимальный полный вес при перевозке подпадающей под условия сельхозпродукции в рамках 10-процентного допуска Индианы?","options":["84 000 фунтов","90 000 фунтов","88 000 фунтов","86 000 фунтов"],"explanation":"Индиана добавляет 10% к допустимому полному весу для подпадающих под условия перевозок сельхозпродукции, поэтому 80 000 фунтов превращаются в 88 000 фунтов (только на маршрутах вне межштатных автомагистралей и без установленных ограничений). Источник: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"16":{"q":"Индиана относит некоторые лесные продукты к сельхозпродукции для целей 10-процентного допуска по весу. Для какого из них 10-процентный допуск применяется ВСЕГДА в отношении полного и осевого веса?","options":["Готовый пиломатериал и фанера","Древесная щепа, кора и опилки","Мебель и шкафы","Бумага и картон"],"explanation":"К сельхозпродукции относятся брёвна, древесная щепа, кора, опилки и наливное молоко; для древесной щепы, коры и опилок 10-процентный допуск применяется всегда в отношении полного и осевого веса. Источник: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"17":{"q":"В рамках «дедушкиной оговорки» Индианы, сохраняющей весовые ограничения, действовавшие на 4 января 1975 года, каков максимальный полный вес для затронутых конфигураций транспортных средств?","options":["80 000 фунтов","70 000 фунтов","64 000 фунтов","73 280 фунтов"],"explanation":"«Дедушкина оговорка» Индианы сохраняет максимальный полный вес в 73 280 фунтов для конфигураций, которые в противном случае были бы ограничены «мостовой формулой». Источник: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"18":{"q":"За исключением межштатных автомагистралей, каков максимальный вес на одиночную ось, разрешённый для подпадающего под условия муниципального мусоросборочного транспортного средства в Индиане?","options":["20 000 фунтов","24 000 фунтов","22 400 фунтов","26 000 фунтов"],"explanation":"За исключением системы межштатных автомагистралей, подпадающие под условия мусоросборочные транспортные средства могут нести до 24 000 фунтов на одиночную ось и 42 000 фунтов на тандемную ось, но при этом остаются под действием ограничений по нагрузке на колесо согласно IC 9-20-11-4. Источник: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"19":{"q":"В Индиане какой класс CDL требуется для управления составом транспортных средств с полной массой автопоезда (GCWR) 26 001 фунт или более, когда буксируемое(ые) транспортное(ые) средство(а) имеет(ют) GVWR свыше 10 000 фунтов?","options":["Class A","Class B","Class C","Class D"],"explanation":"Индиана определяет CDL класса Class A как любой состав транспортных средств с GCWR 26 001 фунт или более при условии, что GVWR буксируемого(ых) звена(ьев) превышает 10 000 фунтов. Источник: Indiana CDL Manual (Indiana BMV); 49 CFR 383.91 в редакции, принятой Индианой."},"20":{"q":"По правилам Индианы одиночное транспортное средство с GVWR 26 001 фунт или более (либо такое транспортное средство, буксирующее звено с GVWR не более 10 000 фунтов) требует какого класса CDL?","options":["Class C","Class B","Class A","Chauffeur license"],"explanation":"Индиана определяет CDL класса Class B как любое одиночное транспортное средство с GVWR 26 001 фунт или более, либо такое транспортное средство, буксирующее звено с GVWR не более 10 000 фунтов. Источник: Indiana CDL Manual (Indiana BMV)."},"21":{"q":"В Индиане транспортное средство, которое не достигает весовых порогов Class A или Class B, но предназначено для перевозки 16 и более пассажиров (включая водителя) либо перевозит опасные грузы, требующие нанесения плакатов (placard), требует какого класса CDL?","options":["Class A","Class B","Class C","CDL не требуется"],"explanation":"CDL класса Class C в Индиане охватывает транспортные средства ниже весовых пределов Class A/B, которые предназначены для перевозки 16 и более пассажиров (включая водителя) либо перевозят опасные грузы, требующие нанесения плакатов. Источник: Indiana CDL Manual (Indiana BMV)."},"22":{"q":"Каков минимальный возраст для получения CDL Индианы с ограничением только на вождение внутри штата (intrastate, в пределах Индианы)?","options":["16 лет","17 лет","18 лет","21 год"],"explanation":"Индиана требует, чтобы заявителям было не менее 18 лет для получения CDL или CLP для внутриштатной деятельности; водители в возрасте 18-20 лет ограничены управлением коммерческими транспортными средствами в пределах Индианы. Источник: Indiana CDL Manual (Indiana BMV); IC 9-24."},"23":{"q":"Каков минимальный возраст для управления коммерческим автотранспортным средством в межштатных перевозках (через границы штатов) с CDL Индианы?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Водителю должно быть не менее 21 года, чтобы управлять коммерческим автотранспортным средством в межштатном сообщении, перевозить опасные грузы или перевозить пассажиров через границы штатов. Водители 18-20 лет ограничены вождением внутри штата в Индиане. Источник: Indiana CDL Manual (Indiana BMV); 49 CFR 391.11."},"24":{"q":"Какое дополнение (endorsement) требует Индиана для управления цистерной, перевозящей жидкость или газ в отдельной ёмкости объёмом более 119 галлонов (при суммарном объёме 1 000 и более галлонов)?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"Дополнение N (Tank Vehicle) Индианы требуется для транспортных средств, предназначенных для перевозки жидкостей или газов в ёмкости с индивидуальной паспортной вместимостью более 119 галлонов и суммарной вместимостью 1 000 галлонов или более. Источник: Indiana BMV CDL Endorsements and Restrictions."},"25":{"q":"Какое дополнение к CDL Индианы требуется для управления транспортным средством, буксирующим два или три отдельных прицепа (doubles/triples)?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement S"],"explanation":"Дополнение T разрешает управление составом с двумя или тремя отдельными прицепами (doubles/triples). Оно получается путём сдачи теоретического экзамена по doubles/triples. Источник: Indiana BMV CDL Endorsements and Restrictions."},"26":{"q":"Какое дополнение к CDL Индианы требуется для управления транспортным средством, предназначенным для перевозки 16 и более пассажиров, включая водителя?","options":["Endorsement S","Endorsement P","Endorsement N","Endorsement H"],"explanation":"Дополнение P (Passenger) требуется для управления транспортным средством, предназначенным для перевозки 16 и более пассажиров, включая водителя. Оно требует теоретического экзамена, экзамена по навыкам на репрезентативном транспортном средстве и ELDT для впервые подающих заявителей. Источник: Indiana BMV CDL Endorsements and Restrictions."},"27":{"q":"В Индиане какую дополнительную федеральную проверку должен пройти заявитель для получения дополнения H (Hazardous Materials)?","options":["Оценку угрозы безопасности TSA, включая снятие отпечатков пальцев","Проверку на полиграфе FBI","Проверку судимостей только на уровне штата без отпечатков пальцев","Собеседование DEA по контролируемым веществам"],"explanation":"Добавление дополнения H требует сдачи теоретического экзамена по HazMat и прохождения оценки угрозы безопасности TSA, которая включает снятие отпечатков пальцев и проверку законного статуса. Источник: Indiana BMV CDL Endorsements and Restrictions; 49 CFR 1572 (TSA)."},"28":{"q":"Как часто держатель CDL Индианы должен обновлять оценку угрозы безопасности TSA, чтобы сохранить дополнение по опасным грузам (H)?","options":["Каждый год","Каждые 2 года","Каждые 5 лет","Каждые 10 лет"],"explanation":"Оценка угрозы безопасности TSA для дополнения HazMat действует пять лет и должна обновляться (с повторной сдачей теоретического экзамена по HazMat) не реже чем каждые пять лет. Источник: Indiana BMV CDL Endorsements and Restrictions; TSA HazMat Endorsement program."},"29":{"q":"Какой комбинированный код дополнения выдаёт Индиана, когда водитель имеет одновременно дополнения по опасным грузам и по цистернам?","options":["Endorsement X","Endorsement HN","Endorsement Z","Endorsement W"],"explanation":"Индиана выдаёт дополнение X для обозначения сочетания привилегий H (HazMat) и N (Tank Vehicle). Источник: Indiana BMV CDL Endorsements and Restrictions."},"30":{"q":"Прежде чем сдавать экзамен по навыкам CDL в Индиане, как долго заявитель должен иметь действующее коммерческое ученическое разрешение (CLP)?","options":["Не менее 7 дней","Не менее 14 дней","Не менее 30 дней","Не менее 60 дней"],"explanation":"Заявитель должен иметь CLP не менее 14 дней, прежде чем приступать к экзамену по навыкам CDL. Это федеральный минимум, принятый Индианой. Источник: Indiana CDL Manual / Indiana BMV; 49 CFR 383.25."},"31":{"q":"Согласно Indiana BMV, как долго действует коммерческое ученическое разрешение (CLP) после его выдачи?","options":["30 дней","90 дней","Один год","Пять лет"],"explanation":"Indiana BMV указывает, что CLP действует один год, а результаты теоретического экзамена CDL также действительны в течение одного года. Источник: Indiana BMV, Obtaining a Commercial Learner's Permit."},"32":{"q":"Какое ограничение распространяется на держателя CLP Индианы при управлении коммерческим автотранспортным средством?","options":["Он может ездить в одиночку только по межштатным автомагистралям","Его должен сопровождать держатель CDL с надлежащим классом и дополнениями","Он может ездить только между восходом и заходом солнца","Он может управлять только транспортными средствами с GVWR менее 26 001 фунта"],"explanation":"Держатель CLP может управлять коммерческим автотранспортным средством только в сопровождении лица, имеющего действующий CDL с надлежащим классом и дополнениями, которое сидит рядом с держателем CLP. Источник: Indiana BMV, Obtaining a Commercial Learner's Permit; 49 CFR 383.25."},"33":{"q":"При подаче заявления на CDL или CLP Индианы сколько документов должен предъявить заявитель для подтверждения проживания в Индиане?","options":["Один документ","Два документа","Три документа","Подтверждение проживания не требуется"],"explanation":"Индиана требует два документа, подтверждающих проживание в Индиане, плюс один, подтверждающий личность, один, подтверждающий законный статус, и один, подтверждающий полный номер социального страхования. Источник: Indiana BMV document requirements."},"34":{"q":"Помимо подтверждения личности и проживания в Индиане, какие два пункта должен документально подтвердить заявитель на CDL Индианы?","options":["Законный статус в США и полный номер социального страхования","Аттестат об окончании средней школы и документ о праве собственности на транспортное средство","Письмо специалиста по зрению и аффидевит работодателя","Регистрацию избирателя и квитанцию о коммунальном залоге"],"explanation":"Индиана требует один документ, подтверждающий законный статус (законное присутствие) в США, и один документ, подтверждающий полный номер социального страхования заявителя, в дополнение к документу о личности и двум документам о проживании. Источник: Indiana BMV document requirements."},"35":{"q":"С 7 февраля 2022 года обучение водителей начального уровня (ELDT) должно быть пройдено заявителями Индианы в какой ситуации?","options":["При продлении имеющегося CDL Class A без изменения класса","При получении первого CDL Class A или Class B либо первого дополнения H, P или S","При добавлении только дополнения T (doubles/triples)","При самостоятельной сертификации как excepted intrastate"],"explanation":"ELDT применяется к водителям, получающим первый CDL Class A или Class B, повышающим класс либо впервые получающим дополнение по опасным грузам (H), пассажирское (P) или по школьным автобусам (S) 7 февраля 2022 года или позже. Источник: FMCSA ELDT rule; Indiana BMV."},"36":{"q":"Где заявитель Индианы должен пройти обязательное обучение водителей начального уровня (ELDT)?","options":["В любой частной автошколе по выбору заявителя","У поставщика, внесённого в FMCSA Training Provider Registry","В центре тестирования отделения Indiana BMV","Через онлайн-курс, одобренный TSA"],"explanation":"Теоретическое и практическое обучение ELDT должно проводиться организацией, внесённой в FMCSA Training Provider Registry (TPR); только внесённые в реестр поставщики могут сообщать о прохождении. Источник: FMCSA Training Provider Registry; Indiana BMV."},"37":{"q":"Какую категорию медицинской самостоятельной сертификации выбирает держатель CDL Индианы, если он работает только в пределах Индианы и должен соответствовать квалификационным требованиям штата к водителям, имея медицинскую справку врача-эксперта?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Категория Non-Excepted Intrastate (NA) применяется к водителям, работающим только во внутриштатной (в пределах Индианы) коммерческой деятельности, которые должны соответствовать квалификационным правилам Индианы для водителей и предоставлять медицинскую справку врача-эксперта. Источник: Indiana BMV CDL self-certification; 49 CFR 383.71."},"38":{"q":"Какая категория самостоятельной сертификации требует от держателя CDL Индианы поддерживать действующую федеральную медицинскую справку DOT (Medical Examiner's Certificate) от поставщика, внесённого в FMCSA National Registry?","options":["Excepted Intrastate (EA)","Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Restricted Agricultural (RA)"],"explanation":"Водитель, самостоятельно сертифицирующийся как Non-Excepted Interstate (NI), работает через границы штатов в неисключённой коммерческой деятельности и должен иметь и поддерживать действующую медицинскую справку (Medical Examiner's Certificate), выданную сертифицированным врачом-экспертом из FMCSA National Registry. Источник: Indiana BMV CDL self-certification; 49 CFR 391.41."},"39":{"q":"В Индиане какова максимальная концентрация алкоголя в крови (BAC), при которой законно управлять коммерческим автотранспортным средством (CMV)?","options":["Ниже 0,04%","Ниже 0,08%","Ниже 0,02%","Ниже 0,10%"],"explanation":"Indiana BMV CDL Manual (раздел 1.3.2) указывает, что управлять CMV незаконно, если ваша концентрация алкоголя в крови составляет 0,04% или более, поэтому водитель CMV должен оставаться ниже 0,04% (половина предела 0,08% для некоммерческих водителей). Источник: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2."},"40":{"q":"Согласно правилу подразумеваемого согласия (implied consent) Индианы, на что водитель считается давшим согласие, управляя CMV?","options":["На прохождение теста на алкоголь","На отказ от права на адвоката","На осмотр транспортного средства в любое время","На обязательную программу лечения от наркозависимости"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) указывает, что, управляя CMV, вы считаетесь давшим своё согласие на прохождение теста на алкоголь. Источник: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2; IC 9-30-6."},"41":{"q":"За первое серьёзное правонарушение (major offense), например управление CMV с BAC 0,04% или выше, на какой срок держатель CDL Индианы лишится своего CDL?","options":["Не менее 1 года","Не менее 6 месяцев","Не менее 90 дней","Не менее 3 лет"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) указывает, что вы лишитесь CDL не менее чем на один год за первое серьёзное правонарушение, включая управление CMV с BAC 0,04% или выше. Источник: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51)."},"42":{"q":"Если первое серьёзное правонарушение происходит во время управления CMV с плакатами (placards) об опасных грузах, какова минимальная дисквалификация в Индиане?","options":["Не менее 3 лет","Не менее 1 года","Не менее 5 лет","Пожизненно"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) указывает, что вы лишитесь CDL не менее чем на три года, если первое серьёзное правонарушение происходит во время управления CMV, на котором нанесены плакаты об опасных грузах. Источник: Indiana BMV CDL Manual, Sec. 1.3.2."},"43":{"q":"Каковы последствия второго серьёзного правонарушения (например, второго вождения CMV в нетрезвом виде, DWI) согласно правилам CDL Индианы?","options":["Лишение CDL пожизненно","Лишение CDL на 10 лет","Лишение CDL на 3 года","Лишение CDL на 5 лет"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) указывает, что вы лишитесь CDL пожизненно за второе серьёзное правонарушение. Источник: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51)."},"44":{"q":"Что из перечисленного рассматривается как первое серьёзное правонарушение, из-за которого держатель CDL Индианы лишается лицензии не менее чем на один год?","options":["Отказ пройти тест на содержание алкоголя в крови","Слишком близкое следование за транспортным средством","Вождение на 16 миль/ч выше установленного предела","Неправильная смена полосы движения"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) относит отказ пройти тест на содержание алкоголя в крови к серьёзным правонарушениям, влекущим дисквалификацию не менее чем на один год; остальные варианты являются серьёзными нарушениями ПДД, но не major offenses. Источник: Indiana BMV CDL Manual, Sec. 1.3.2."},"45":{"q":"В Индиане что происходит с держателем CDL, который использует CMV для совершения тяжкого преступления (felony), связанного с контролируемыми веществами?","options":["Лишение CDL пожизненно","Лишение CDL на 3 года","Лишение CDL на 1 год","Лишение CDL на 5 лет"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) указывает, что вы лишитесь CDL пожизненно, если используете CMV для совершения тяжкого преступления, связанного с контролируемыми веществами. Источник: Indiana BMV CDL Manual, Sec. 1.3.2."},"46":{"q":"У водителя CMV в Индиане обнаружено выявляемое количество алкоголя ниже 0,04%. Каковы немедленные последствия?","options":["Вывод из эксплуатации (out-of-service) на 24 часа","Дисквалификация CDL на 60 дней","Гражданский штраф в размере $2,750","Дисквалификация CDL на 1 год"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) указывает, что вы будете выведены из эксплуатации (out-of-service) на 24 часа, если у вас обнаружено любое выявляемое количество алкоголя ниже 0,04%. Источник: Indiana BMV CDL Manual, Sec. 1.3.2."},"47":{"q":"Как Indiana CDL Manual определяет «превышение скорости в опасной степени» (excessive speeding) как серьёзное нарушение ПДД?","options":["На 15 миль/ч или более выше установленного предела","На 10 миль/ч или более выше установленного предела","На 20 миль/ч или более выше установленного предела","На 25 миль/ч или более выше установленного предела"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3) определяет excessive speeding как превышение установленного предела на 15 миль/ч или более. Источник: Indiana BMV CDL Manual, Sec. 1.3.3."},"48":{"q":"За два серьёзных нарушения ПДД на CMV в течение трёхлетнего периода на какой срок держатель CDL Индианы лишится своего CDL?","options":["Не менее 60 дней","Не менее 30 дней","Не менее 90 дней","Не менее 120 дней"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3) указывает, что вы лишитесь CDL не менее чем на 60 дней за два серьёзных нарушения ПДД в течение трёхлетнего периода с участием CMV. Источник: Indiana BMV CDL Manual, Sec. 1.3.3."},"49":{"q":"За три или более серьёзных нарушения ПДД на CMV в течение трёхлетнего периода какова дисквалификация в Индиане?","options":["Не менее 120 дней","Не менее 60 дней","Не менее 90 дней","Не менее 1 года"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3) указывает, что вы лишитесь CDL не менее чем на 120 дней за три или более серьёзных нарушения ПДД в течение трёхлетнего периода с участием CMV. Источник: Indiana BMV CDL Manual, Sec. 1.3.3."},"50":{"q":"Что из перечисленного указано как серьёзное нарушение ПДД в Indiana CDL Manual?","options":["Безрассудное вождение (reckless driving)","Управление CMV с BAC 0,04%","Оставление места ДТП с участием CMV","Отказ от теста на содержание алкоголя в крови"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3) относит безрассудное вождение к серьёзным нарушениям ПДД; остальные три являются серьёзными правонарушениями (major offenses) согласно Sec. 1.3.2. Источник: Indiana BMV CDL Manual, Sec. 1.3.3."},"51":{"q":"Какова минимальная дисквалификация за первое нарушение предписания о выводе из эксплуатации (out-of-service order) в Индиане?","options":["Не менее 90 дней","Не менее 60 дней","Не менее 30 дней","Не менее 180 дней"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.4) указывает, что вы лишитесь CDL не менее чем на 90 дней за первое нарушение предписания о выводе из эксплуатации. Источник: Indiana BMV CDL Manual, Sec. 1.3.4."},"52":{"q":"Какова минимальная дисквалификация за два нарушения предписания о выводе из эксплуатации в течение десятилетнего периода в Индиане?","options":["Не менее 1 года","Не менее 90 дней","Не менее 6 месяцев","Не менее 3 лет"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.4) указывает, что вы лишитесь CDL не менее чем на один год за два нарушения предписания о выводе из эксплуатации в течение десятилетнего периода. Источник: Indiana BMV CDL Manual, Sec. 1.3.4."},"53":{"q":"Три или более нарушения предписания о выводе из эксплуатации в течение десятилетнего периода влекут какую минимальную дисквалификацию в Индиане?","options":["Не менее 3 лет","Не менее 1 года","Не менее 5 лет","Пожизненно"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.4) указывает, что вы лишитесь CDL не менее чем на три года за три или более нарушения предписания о выводе из эксплуатации в течение десятилетнего периода. Источник: Indiana BMV CDL Manual, Sec. 1.3.4."},"54":{"q":"Какова минимальная дисквалификация за первое нарушение на железнодорожном переезде (railroad-highway grade crossing) в Индиане?","options":["Не менее 60 дней","Не менее 30 дней","Не менее 90 дней","Не менее 120 дней"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.5) указывает, что вы лишитесь CDL не менее чем на 60 дней за первое нарушение на железнодорожном переезде. Источник: Indiana BMV CDL Manual, Sec. 1.3.5."},"55":{"q":"Второе нарушение на железнодорожном переезде в течение трёхлетнего периода влечёт какую минимальную дисквалификацию в Индиане?","options":["Не менее 120 дней","Не менее 60 дней","Не менее 90 дней","Не менее 1 года"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.5) указывает, что вы лишитесь CDL не менее чем на 120 дней за второе нарушение на железнодорожном переезде в течение трёхлетнего периода. Источник: Indiana BMV CDL Manual, Sec. 1.3.5."},"56":{"q":"Третье нарушение на железнодорожном переезде в течение трёхлетнего периода влечёт какую минимальную дисквалификацию в Индиане?","options":["Не менее 1 года","Не менее 120 дней","Не менее 6 месяцев","Не менее 3 лет"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.5) указывает, что вы лишитесь CDL не менее чем на один год за третье нарушение на железнодорожном переезде в течение трёхлетнего периода. Источник: Indiana BMV CDL Manual, Sec. 1.3.5."},"57":{"q":"Согласно правилам Индианы, после скольких осуждений по закону штата о наборе текстовых сообщений за рулём CMV (texting-while-driving) CDL дисквалифицируется и на какой срок при втором правонарушении?","options":["Два или более осуждения; 60 дней за второе правонарушение в течение 3 лет","Одно осуждение; 120 дней немедленно","Два осуждения; 1 год за второе правонарушение","Три осуждения; 30 дней за третье правонарушение"],"explanation":"Indiana BMV CDL Manual (Sec. 2.9.5) указывает, что ваш CDL будет дисквалифицирован после двух или более осуждений по любому закону штата о наборе текстовых сообщений при управлении CMV, с дисквалификацией на 60 дней за второе правонарушение в течение 3 лет (120 дней за три или более в течение 3 лет). Источник: Indiana BMV CDL Manual, Sec. 2.9.5."},"58":{"q":"Согласно Indiana CDL Manual, водитель CMV, нарушивший ограничение на использование ручного мобильного телефона или набор текстовых сообщений, подлежит гражданскому штрафу в размере до какой суммы?","options":["$2,750","$1,000","$5,000","$11,000"],"explanation":"Indiana BMV CDL Manual (Secs. 2.9.4-2.9.5) указывает, что каждое нарушение запрета на использование ручного телефона или набор текстовых сообщений влечёт для водителя гражданский штраф в размере до $2,750; работодатели могут подлежать штрафам в размере до $11,000. Источник: Indiana BMV CDL Manual, Secs. 2.9.4 and 2.9.5."},"59":{"q":"На сельской автомагистрали штата Индиана (за пределами урбанизированной территории) каково максимальное ограничение скорости для груженого тягача с полуприцепом, у которого заявленная полная масса превышает 26,000 фунтов?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Согласно IC 9-21-5-2, транспортное средство, не являющееся автобусом, с заявленной полной массой более 26,000 фунтов ограничено скоростью 65 mph на сельских автомагистралях между штатами, в то время как легковые автомобили могут двигаться со скоростью 70 mph. Это является основанием для раздельных (грузовик и легковой автомобиль) знаков ограничения скорости на автомагистралях Индианы."},"60":{"q":"Легковой автомобиль может двигаться со скоростью 70 mph на сельской автомагистрали штата Индиана. В том же месте чартерный автобус, перевозящий пассажиров, может законно двигаться со скоростью до:","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"IC 9-21-5-2 применяет ограничение для грузовиков в 65 mph к транспортным средствам, «не являющимся автобусом», массой более 26,000 фунтов. Автобусы не подпадают под пониженное ограничение для грузовиков, поэтому автобус может двигаться с установленной скоростью 70 mph на сельских автомагистралях между штатами. Источник: Indiana Code 9-21-5-2."},"61":{"q":"Вы управляете автоцистерной с опасными грузами, имеющей соответствующие плакаты (placards), на шоссе штата Индиана. На железнодорожном переезде в одном уровне, где требуется остановка, вы должны остановиться:","options":["Не ближе 15 футов и не дальше 50 футов от ближайшего рельса","Не ближе 10 футов и не дальше 25 футов от ближайшего рельса","Точно в 50 футах от ближайшего рельса","Не ближе 50 футов и не дальше 100 футов от ближайшего рельса"],"explanation":"Руководство CDL штата Индиана (раздел 9.6.12) требует, чтобы транспортные средства с плакатами, перевозчики хлора и автоцистерны останавливались в 15–50 футах от ближайшего рельса, а затем продолжали движение только убедившись, что поезд не приближается. Источник: Руководство CDL штата Индиана."},"62":{"q":"Закон штата Индиана «Move Over» (IC 9-21-8-35) требует, чтобы вы перестроились в другую полосу, удаляясь от остановившегося аварийного или неисправного транспортного средства с мигающими огнями. Если вы не можете безопасно перестроиться, вы должны:","options":["Снизить скорость до 10 mph ниже установленного ограничения скорости","Полностью остановиться, пока не станет безопасно продолжить движение","Подать звуковой сигнал и сохранять установленную скорость","Снизить скорость до 20 mph ниже установленного ограничения скорости"],"explanation":"Согласно IC 9-21-8-35, когда перестроение невозможно или небезопасно, водитель должен снизить скорость как минимум до 10 mph ниже установленного ограничения скорости при проезде. INDOT продвигает это как «Move Over or Slow Down». Источник: IC 9-21-8-35; INDOT."},"63":{"q":"На автомагистрали штата Индиана с двумя полосами в вашем направлении движения тягач, как правило, ограничен какой полосой, за исключением случаев обгона, въезда/выезда или объезда особой опасности?","options":["Любой полосой, свободно","Левой (обгонной) полосой","Крайней правой полосой","Центром проезжей части"],"explanation":"IC 9-21-8-12 запрещает управление грузовиком или тягачом на автомагистрали между штатами в любой полосе, кроме крайней правой, за исключением случаев обгона более медленного транспортного средства, въезда или выезда с автомагистрали, либо когда особая опасность требует использования другой полосы. Источник: Indiana Code 9-21-8-12."},"64":{"q":"На автомагистрали штата Индиана с тремя или более полосами в вашем направлении движения тягач ограничен:","options":["Только крайней правой полосой","Только двумя правыми полосами","Любой полосой, кроме крайней левой","Только центральной полосой"],"explanation":"IC 9-21-8-13 ограничивает движение грузовиков на автомагистралях, имеющих не менее трех полос в одном направлении, двумя крайними правыми полосами, за исключением случаев въезда или выезда с автомагистрали или объезда особой опасности. Это менее строго, чем правило одной полосы для двухполосных участков. Источник: Indiana Code 9-21-8-13."},"65":{"q":"В штате Индиана водитель, который встречает или обгоняет остановившийся школьный автобус с выдвинутым знаком «STOP» и мигающими красными огнями, должен остановиться и оставаться на месте до тех пор, пока:","options":["Водитель автобуса не подаст ему знак продолжить движение","Не пройдет пять секунд","Знак «STOP» не будет убран и красные огни не перестанут мигать","Он не досчитает до десяти"],"explanation":"Согласно IC 9-21-12-1, водитель должен остановиться, не доезжая до автобуса, когда выдвинуто сигнальное устройство со знаком, и не может продолжить движение, пока устройство не будет убрано (огни перестанут мигать). Нарушение является правонарушением класса A (Class A infraction). Источник: Indiana Code 9-21-12-1."},"66":{"q":"Вы движетесь навстречу остановившемуся школьному автобусу (с мигающими красными огнями), который находится на ДРУГОЙ стороне четырехполосной дороги. Согласно закону штата Индиана о школьных автобусах, вы НЕ обязаны останавливаться только в том случае, если две проезжие части разделены:","options":["Нарисованной осевой линией или полосой для левого поворота в обе стороны","Любыми четырьмя или более полосами покрытия","Плоским нарисованным разделителем шириной не менее 4 футов","Физическим барьером или неблагоустроенной/разделительной полосой, не предназначенной для движения"],"explanation":"IC 9-21-12-3 освобождает приближающегося водителя от обязанности останавливаться только тогда, когда проезжие части разделены неблагоустроенным промежуточным пространством, физическим барьером или разделительной секцией, построенной для препятствования движению, и автобус находится на противоположной стороне. Простая нарисованная линия НЕ подходит — вы все равно должны остановиться. Источник: Indiana Code 9-21-12-3."},"67":{"q":"Если вам необходимо остановить ваш CMV на обочине разделенного шоссе штата Индиана, как скоро вы должны выставить аварийные предупреждающие устройства?","options":["В течение 2 минут","В течение 5 минут","В течение 10 минут","Немедленно, до выхода из кабины"],"explanation":"Руководство CDL штата Индиана (раздел 2.5) указывает, что если вы остановились на дороге или обочине, вы должны выставить аварийные предупреждающие устройства в течение 10 минут. Источник: Руководство CDL штата Индиана."},"68":{"q":"При остановке на дороге с односторонним движением или разделенном шоссе штата Индиана где вы размещаете три предупреждающих треугольника?","options":["На 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта","На 10 футов, 50 футов и 100 футов в сторону приближающегося транспорта","На 100 футов впереди, 100 футов сзади и у транспортного средства","Только у транспортного средства, с включенной аварийной сигнализацией"],"explanation":"Руководство CDL штата Индиана предписывает, что на дороге с односторонним движением или разделенном шоссе предупреждающие устройства размещаются на 10 футов, 100 футов и 200 футов в сторону приближающегося транспорта. Источник: Руководство CDL штата Индиана, раздел 2.5."},"69":{"q":"При остановке на двухполосной дороге штата Индиана с движением в обоих направлениях ваши предупреждающие треугольники должны быть размещены:","options":["На 10 футов, 100 футов и 200 футов только позади транспортного средства","Только на 50 футов впереди и 50 футов сзади","Только на 200 футов впереди и 200 футов сзади","В пределах 10 футов от транспортного средства, а также на 100 футов впереди и 100 футов сзади"],"explanation":"На неразделенной двусторонней дороге Руководство CDL штата Индиана требует размещения треугольника в пределах 10 футов от переднего или заднего угла для обозначения транспортного средства, плюс один на 100 футов впереди и один на 100 футов сзади, на обочине или в полосе движения. Источник: Руководство CDL штата Индиана, раздел 2.5."},"70":{"q":"Школьный автобус, которым вы управляете в штате Индиана, приближается к железнодорожному переезду в одном уровне. Вы должны остановить автобус:","options":["В пределах от 15 до 50 футов перед переездом","Не ближе 5 футов от рельса","Точно в 25 футах от рельса","Только если виден поезд"],"explanation":"Руководство CDL штата Индиана (раздел 4.3.5) предписывает водителям автобусов останавливать автобус в пределах от 15 до 50 футов перед железнодорожными переездами, а затем смотреть и слушать в обоих направлениях перед продолжением движения. Источник: Руководство CDL штата Индиана."},"71":{"q":"Согласно измененному закону штата Индиана «Move Over», водитель, который не перестраивается и не снижает скорость для остановившегося транспортного средства с мигающими огнями (без причинения травм), совершает:","options":["Правонарушение класса A (Class A infraction)","Правонарушение класса B (Class B infraction)","Правонарушение класса C (Class C infraction)","Фелонию класса D (Class D felony)"],"explanation":"Базовое нарушение IC 9-21-8-35 является правонарушением класса B (Class B infraction); оно повышается до фелонии только в том случае, если несоблюдение приводит к серьезным телесным повреждениям или смерти охваченного законом работника. Источник: IC 9-21-8-35; INDOT."},"72":{"q":"Без разрешения на негабаритный груз от Indiana Department of Revenue/INDOT максимальная допустимая ШИРИНА коммерческого груза на дорогах штата Индиана составляет:","options":["8 футов 0 дюймов","8 футов 6 дюймов","10 футов 0 дюймов","9 футов 0 дюймов"],"explanation":"Допустимая (без разрешения) максимальная ширина в Индиане составляет 8 футов 6 дюймов (102 дюйма). Грузы, превышающие это значение, требуют разрешения на негабаритный/сверхтяжелый груз через Indiana DOR Motor Carrier Services. Источник: INDOT / правила Indiana DOR OSOW."},"73":{"q":"Без разрешения на негабаритный груз в Индиане максимальная допустимая ВЫСОТА транспортного средства с грузом составляет:","options":["13 футов 0 дюймов","13 футов 6 дюймов","14 футов 0 дюймов","12 футов 6 дюймов"],"explanation":"Допустимая максимальная высота в Индиане составляет 13 футов 6 дюймов; все, что выше, требует разрешения на негабаритный груз. Водители все равно должны проверять габариты проезда, поскольку обозначенные высоты мостов имеют приоритет. Источник: INDOT / правила Indiana DOR OSOW."},"74":{"q":"Без разрешения на сверхтяжелый груз максимальная допустимая полная масса транспортного средства для стандартной сцепки на дорогах штата Индиана составляет:","options":["73,280 фунтов","90,000 фунтов","100,000 фунтов","80,000 фунтов"],"explanation":"Допустимая максимальная полная масса транспортного средства в Индиане составляет 80,000 фунтов (соответствует федеральному лимиту для межштатных перевозок). Более тяжелые грузы требуют разрешения на сверхтяжелый груз от Indiana DOR Motor Carrier Services. Источник: INDOT / правила Indiana DOR OSOW."},"75":{"q":"На многополосном шоссе штата Индиана CMV, движущийся медленнее нормального потока транспорта, согласно законодательству штата Индиана обязан:","options":["Использовать крайнюю левую полосу, чтобы не мешать въезжающему транспорту","Постоянно двигаться по центральной полосе","Поддерживать как минимум установленный минимум в любой полосе","Использовать правую полосу(ы), доступную для движения"],"explanation":"IC 9-21-5-9 требует, чтобы транспортные средства, движущиеся медленнее максимальной установленной скорости, использовали правые полосы, и запрещает продолжать движение в крайней левой полосе при обгоне. Источник: Indiana Code 9-21-5-9."},"76":{"q":"Школьный автобус в сельской местности штата Индиана включает попеременно мигающие ЖЕЛТЫЕ огни. Эти огни означают:","options":["Автобус сломался — проезжайте с осторожностью","Дети переходят дорогу — немедленно остановитесь","Автобус освобожден от остановки на железнодорожном переезде","Автобус готовится остановиться для посадки или высадки; будьте готовы остановиться"],"explanation":"Желтые (янтарные) огни являются предварительным предупреждением о том, что автобус собирается остановиться для посадки или высадки, и включаются примерно за 300 футов в сельской местности; затем КРАСНЫЕ огни и выдвинутый знак «STOP» требуют от транспорта остановиться. Источник: Руководство CDL штата Индиана / безопасность школьных автобусов INDOT."},"77":{"q":"Полицейский регулирует движение на железнодорожном переезде в одном уровне в штате Индиана и подает сигнал вашему транспортному средству с плакатами продолжить движение без остановки. Вам следует:","options":["Все равно остановиться в 15–50 футах, игнорируя полицейского","Остановиться, только если вы видите поезд","Следовать указанию полицейского и продолжить движение без обязательной остановки","Дать задний ход и найти другой переезд"],"explanation":"Обязательная остановка в 15–50 футах для транспортных средств с плакатами и пассажирских транспортных средств не применяется, когда полицейский или регулировщик направляет транспорт продолжить движение (это также признается согласно 49 CFR 392.10, применяемому в Индиане). Источник: Руководство CDL штата Индиана; 49 CFR 392.10."},"78":{"q":"Автомобилист, который безрассудно обгоняет школьный автобус в штате Индиана с выдвинутым знаком «STOP» и мигающими красными огнями, помимо штрафов сталкивается с возможным:","options":["Приостановлением действия водительского удостоверения на срок до 90 дней за первое нарушение","Обязательным 30-дневным тюремным заключением без действий в отношении удостоверения","Только письменным предупреждением","Постоянной дисквалификацией CDL за любое первое нарушение"],"explanation":"Обгон остановившегося школьного автобуса с выдвинутым знаком «STOP» является правонарушением класса A (IC 9-21-12-1); безрассудные нарушения подпадают под IC 9-21-8-52, и нарушители при первом нарушении могут столкнуться с приостановлением действия удостоверения на срок до 90 дней (до одного года для повторных нарушителей). Источник: IC 9-21-12-1 и IC 9-21-8-52."},"79":{"q":"Какое ведомство выдает коммерческие водительские удостоверения (CDL) в штате Индиана?","options":["Бюро транспортных средств штата Индиана (Indiana BMV)","Департамент транспорта штата Индиана (INDOT)","Федеральное управление по безопасности коммерческих автоперевозок (FMCSA)","Отдел коммерческого транспорта полиции штата Индиана"],"explanation":"CDL в штате Индиана выдаются Бюро транспортных средств штата Индиана (Indiana BMV). Руководство CDL и все операции по лицензированию обрабатываются в отделениях BMV. Источник: руководство Indiana Specific CDL Applicant Information (SP 283), Indiana BMV."},"80":{"q":"В штате Индиана как долго действует коммерческое ученическое разрешение (CLP)?","options":["Один год","180 дней","Два года","Шесть месяцев, с возможностью продления неограниченное число раз"],"explanation":"Согласно действующему руководству CDL штата Индиана, «CLP действует в течение одного года». Источник: руководство Indiana Specific CDL Applicant Information (SP 283), раздел Commercial Learner's Permit, Indiana BMV."},"81":{"q":"Как долго заявитель должен иметь CLP перед попыткой сдачи экзамена по навыкам CDL в штате Индиана?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 10 дней","Не менее 60 дней"],"explanation":"В руководстве указано: «Заявитель должен иметь CLP в течение 14 дней до попытки сдачи экзамена по навыкам CDL». Это соответствует федеральному минимуму и применяется в штате Индиана. Источник: руководство CDL штата Индиана (SP 283), раздел CDL Skills Testing, Indiana BMV."},"82":{"q":"Как долго действует CDL, выданное в штате Индиана, до того как его необходимо продлить?","options":["Четыре года","Пять лет","Шесть лет","Три года"],"explanation":"CDL, выданное в штате Индиана, действует в течение четырех лет. Вы можете продлить его в любом отделении BMV не ранее чем за один год до истечения срока. Источник: Indiana BMV, Renewing or Replacing a CDL."},"83":{"q":"Экзамен по навыкам CDL в штате Индиана состоит из каких трех частей?","options":["Осмотр транспортного средства (предрейсовый), базовое управление транспортным средством и вождение по дороге","Тест на пневматические тормоза, тест на состав транспортных средств и вождение по дороге","Тест на общие знания, базовое управление и предрейсовый осмотр","Предрейсовый осмотр, письменный тест на специальную отметку (endorsement) и вождение по дороге"],"explanation":"Экзамен по навыкам CDL в Индиане состоит из трех частей: Тест на осмотр транспортного средства (раздел 11), Тест на базовые навыки управления транспортным средством (раздел 12) и Вождение по дороге (раздел 13). Источник: руководство CDL штата Индиана (SP 283), CDL Skills Testing, Indiana BMV."},"84":{"q":"Перед получением первого CDL класса A или класса B в штате Индиана заявитель должен пройти какое обязательное на федеральном уровне обучение?","options":["Начальное обучение водителей (ELDT) через зарегистрированного в FMCSA провайдера","Государственный курс защитного вождения в отделении BMV","160-часовое ученичество в Индиане, подтвержденное INDOT","Сертификацию OSHA по перевозке опасных грузов"],"explanation":"Заявители должны пройти Начальное обучение водителей (ELDT) у провайдера, указанного в Реестре провайдеров обучения FMCSA, до получения CDL. Источник: руководство CDL штата Индиана (SP 283); 49 CFR Part 380; действует с 7 февраля 2022 года."},"85":{"q":"Кто должен проводить медицинское обследование, необходимое для получения CLP или CDL в штате Индиана?","options":["Медицинский эксперт, указанный в Национальном реестре сертифицированных медицинских экспертов FMCSA","Любой лицензированный врач в Индиане по выбору заявителя","Врач, нанятый непосредственно Indiana BMV","Медицинский эксперт, утвержденный отделом разрешений INDOT"],"explanation":"Все медицинские обследования должны проводиться медицинским экспертом, сертифицированным в Национальном реестре сертифицированных медицинских экспертов FMCSA (nationalregistry.fmcsa.dot.gov). Источник: руководство CDL штата Индиана (SP 283), Medical Examiner Requirements, Indiana BMV."},"86":{"q":"Как Сертификат медицинского эксперта (MEC) попадает в систему Indiana BMV?","options":["Сертифицированный эксперт загружает MEC в Национальный реестр FMCSA, что позволяет ему применяться в системе BMV","Заявитель отправляет бумажную карточку по почте в штаб-квартиру FMCSA в Вашингтоне, округ Колумбия","INDOT направляет сертификат в BMV после придорожной проверки","Сертификат автоматически генерируется, когда заявитель сдает экзамен по навыкам"],"explanation":"Руководство предписывает держателям CLP/CDL обеспечить загрузку сертифицированным врачом MEC в Национальный реестр, чтобы он применялся в системе BMV. Источник: руководство CDL штата Индиана (SP 283), Medical Examiner Requirements and Certification, Indiana BMV."},"87":{"q":"Из скольких категорий самосертификации должен выбрать заявитель на CDL/CLP в штате Индиана при декларировании типа вождения, которым он будет заниматься?","options":["Четырех","Двух","Трех","Пяти"],"explanation":"Заявители самостоятельно сертифицируют себя по одной из четырех категорий: межштатные неосвобожденные, межштатные освобожденные, внутриштатные неосвобожденные или внутриштатные освобожденные. Источник: 49 CFR 383.71 (применяется Indiana BMV); самосертификация Indiana BMV."},"88":{"q":"Какая категория самосертификации описывает водителя, который работает за пределами штата и должен соответствовать федеральным медицинским/физическим квалификационным требованиям?","options":["Межштатные неосвобожденные (Non-excepted interstate)","Межштатные освобожденные (Excepted interstate)","Внутриштатные неосвобожденные (Non-excepted intrastate)","Внутриштатные освобожденные (Excepted intrastate)"],"explanation":"Водители категории «межштатные неосвобожденные» работают в межштатной торговле и должны соответствовать медицинским требованиям 49 CFR Part 391, имея в наличии действующий MEC. Источник: 49 CFR 383.71 / 391.41 (применяется Indiana BMV)."},"89":{"q":"Согласно правилам штата Индиана, как часто заявитель может пытаться сдать тест на знания CDL?","options":["Один раз в день; проваленный тест можно пересдать на следующий рабочий день","Три раза в день до сдачи","Один раз в неделю, только по записи","Неограниченное число раз в один день"],"explanation":"В руководстве указано, что заявитель может пытаться сдать тест на знания CDL только один раз в день, а после провала может сдать его снова на следующий рабочий день. Источник: руководство CDL штата Индиана (SP 283), CDL Knowledge Tests, Indiana BMV."},"90":{"q":"После сдачи, как долго действительны результаты теста на знания CDL и результаты теста по навыкам в штате Индиана?","options":["Один год","Шесть месяцев","Два года","90 дней"],"explanation":"В руководстве указано, что результаты теста на знания CDL действительны в течение одного года, и результаты теста по навыкам CDL действительны в течение одного года. Источник: руководство CDL штата Индиана (SP 283), CDL Knowledge Tests and CDL Skills Testing, Indiana BMV."},"91":{"q":"Где заявитель должен сдавать тест по навыкам CDL в штате Индиана?","options":["На утвержденном BMV (авторизованном стороннем) пункте сдачи теста по навыкам CDL","За стойкой любого полнофункционального отделения лицензирования BMV","На весовой станции или пункте въезда INDOT","В региональном полевом офисе FMCSA"],"explanation":"Тест по навыкам CDL должен сдаваться на утвержденном BMV пункте сдачи теста по навыкам CDL (авторизованные сторонние пункты); результаты передаются в BMV в электронном виде. Источник: руководство CDL штата Индиана (SP 283), CDL Skills Testing, Indiana BMV."},"92":{"q":"Каков минимальный возраст для получения CDL/CLP в штате Индиана для работы во внутриштатной торговле (и не для управления школьным автобусом или межштатной торговли)?","options":["18 лет","21 год","19 лет","16 лет"],"explanation":"Заявителю должно быть не менее 18 лет; для работы в межштатной торговле или для подачи заявления на специальную отметку для управления школьным автобусом заявителю должен быть не менее 21 года. Источник: руководство CDL штата Индиана (SP 283), требования к CLP, Indiana BMV."},"93":{"q":"После сдачи теста по навыкам CDL в штате Индиана что должен сделать заявитель, чтобы фактически получить CDL?","options":["Вернуться в отделение лицензирования BMV, чтобы завершить оформление заявления до истечения срока действия CLP","Дождаться прибытия удостоверения по почте от FMCSA","Записаться на второй тест по вождению по дороге в INDOT","Пересдать тест на общие знания на пункте тестирования"],"explanation":"В руководстве указано, что после сдачи теста по навыкам заявитель должен вернуться в отделение лицензирования BMV, чтобы завершить оформление заявления на CDL, и должен сделать это до истечения срока действия CLP. Источник: руководство CDL штата Индиана (SP 283), CDL Skills Testing, Indiana BMV."},"94":{"q":"За какое время необходимо записаться на тест по навыкам CDL в штате Индиана на пункте тестирования?","options":["Не менее чем за два дня","Не менее чем за две недели","Не менее чем за один день","Не менее чем за 30 дней"],"explanation":"В руководстве указано, что запись должна производиться не менее чем за два дня, и тест по навыкам можно сдавать только один раз в рабочий день. Источник: руководство CDL штата Индиана (SP 283), CDL Skills Testing, Indiana BMV."},"95":{"q":"Что происходит в штате Индиана, если CDL был просрочен, дисквалифицирован, аннулирован, отозван, приостановлен или признан недействительным более чем на три года?","options":["Заявитель должен сдать все применимые тесты на знания и навыки как заявитель, обращающийся впервые","Заявитель может продлить онлайн только с проверкой зрения","CDL автоматически восстанавливается после письменного теста","Заявителю нужно только пересдать тест по вождению по дороге"],"explanation":"Требование о пересдаче (Retesting Requirement) в руководстве гласит, что любой заявитель, чей CDL был просрочен, сдан, дисквалифицирован, аннулирован, отозван, приостановлен или признан недействительным более чем на три года, должен сдать все применимые тесты на знания и навыки как заявитель, обращающийся впервые. Источник: руководство CDL штата Индиана (SP 283), Indiana BMV."},"96":{"q":"Сколько времени есть у нового резидента с действующим CDL другого штата, чтобы перевести его в CDL штата Индиана?","options":["30 дней","60 дней","90 дней","10 дней"],"explanation":"В руководстве указано, что у физических лиц есть 30 дней для перевода CDL другого штата; экзамен на знания для водительского удостоверения требуется только в том случае, если CDL другого штата просрочен. Источник: руководство CDL штата Индиана (SP 283), Transfer an Out-of-Country or Out-of-State CDL, Indiana BMV."},"97":{"q":"Какое утверждение о процессе получения специальной отметки на перевозку опасных грузов (H) в штате Индиана верно?","options":["Для этого требуется одобрение оценки угрозы безопасности TSA, и она не добавляется к CLP","Она может быть добавлена к CLP после сдачи теста на пневматические тормоза","Для этого требуется только сдача теста на общие знания","Она выдается автоматически с любым CDL класса A"],"explanation":"В руководстве указано, что специальная отметка HazMat требует одобрения оценки угрозы безопасности TSA на срок действия CDL, и что она не будет добавлена к CLP. Источник: руководство CDL штата Индиана (SP 283), CDL Endorsements, Indiana BMV; 49 CFR 1572 (TSA)."},"98":{"q":"Помимо сдачи тестов на знания и навыки, какой шаг конкретно требуется от каждого заявителя на CDL в штате Индиана в процессе лицензирования?","options":["Просмотреть обучающее видео о том, как распознавать, предотвращать и сообщать о торговле людьми","Пройти 40-часовую совместную поездку с патрульным штата","Сдать экзамен INDOT на разрешение для негабаритного/сверхтяжелого груза","Получить нотариально заверенное спонсорство работодателя до тестирования"],"explanation":"Индиана требует, чтобы заявители на CDL просмотрели обучающее видео о том, как распознавать, предотвращать и сообщать о торговле людьми, в дополнение к прохождению ELDT и сдаче необходимых тестов. Источник: руководство CDL штата Индиана (SP 283), требования к заявлению, Indiana BMV."}},"tr":{"0":{"q":"Indiana karayollarında, bir aracın ve yükünün maksimum yasal genişliği (aynalar gibi genişlik dışı bırakılan donanımlar hariç) nedir?","options":["8 feet 0 inches","9 feet 0 inches","8 feet 6 inches","10 feet 0 inches"],"explanation":"Indiana, araç ve yük genişliğini 8 feet 6 inches (102 inches) ile sınırlar; 23 CFR 658 uyarınca genişlik dışı bırakılan güvenlik donanımları hariçtir. Kaynak: Indiana Code IC 9-20-3-2; Indiana State Police Summary of Indiana Size and Weight Laws (Title 9, Article 20)."},"1":{"q":"Indiana karayollarında bir aracın, yükü dahil, maksimum yasal yüksekliği nedir?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","12 feet 6 inches"],"explanation":"Indiana maksimum yüksekliği 13 feet 6 inches olarak belirler ve yasal yükseklikten herhangi bir muafiyet yoktur. Kaynak: IC 9-20-3-3; Indiana State Police Summary of Indiana Size and Weight Laws."},"2":{"q":"Indiana yasaları kapsamında, ağır yük izni olmaksızın bir araca veya kombinasyona izin verilen maksimum brüt ağırlık nedir?","options":["73,280 pounds","80,000 pounds","88,000 pounds","84,000 pounds"],"explanation":"Indiana'nın maksimum yasal brüt ağırlığı 80,000 pounds'tur; bundan daha ağır olan her şey izin gerektirir. 73,280 pounds rakamı yalnızca belirli konfigürasyonlar için geçerli olan eski hak (grandfather) hükmü kapsamında uygulanır. Kaynak: IC 9-20-4 (General Weight Restrictions); Indiana State Police Summary of Size and Weight Laws."},"3":{"q":"Indiana'nın tek bir aks üzerinde izin verdiği maksimum ağırlık nedir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Indiana'nın maksimum tek aks ağırlığı 20,000 pounds'tur. (18,000 pounds ve 16,000 pounds rakamları yalnızca eski hak (grandfather) yasası senaryolarında görülür.) Kaynak: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"4":{"q":"Indiana'nın tandem aks grubuna izin verdiği maksimum ağırlık nedir?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Indiana'nın maksimum tandem aks ağırlığı, federal standartla uyumlu olarak 34,000 pounds'tur. Kaynak: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"5":{"q":"Indiana, jant flanşları arasında ölçülen lastik genişliğinin her inch'i başına tekerlek ağırlığını ne kadarla sınırlar?","options":["600 pounds","1,000 pounds","500 pounds","800 pounds"],"explanation":"Indiana, yüklü veya yüksüz olsun, jant flanşları arasında ölçülen lastik genişliğinin her inch'i başına tekerlek ağırlığını 800 pounds ile sınırlar. Kaynak: IC 9-20-11-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"6":{"q":"Indiana karayollarında kendi gücüyle çalışan tek bir aracın maksimum uzunluğu (uzunluk dışı bırakılan donanımlar hariç) nedir?","options":["40 feet","45 feet","35 feet","53 feet"],"explanation":"Tek bir motorlu araç, 23 CFR 658.13 uyarınca uzunluk dışı bırakılan donanımlar dışında 40 feet'i aşamaz. Bir karavana (recreational vehicle) 45 feet'e kadar izin verilir. Kaynak: IC 9-20-3-1 / IC 9-20-8; Indiana State Police Summary of Size and Weight Laws."},"7":{"q":"Bir çekici (truck-tractor) ve yarı römork (semitrailer) kombinasyonunda, Indiana yasaları kapsamında yarı römorkun (yük dahil) maksimum uzunluğu nedir?","options":["48 feet","57 feet","45 feet","53 feet"],"explanation":"Indiana, bir çekici kombinasyonunda 53 feet'e kadar yarı römorka izin verir ve bu kombinasyon için herhangi bir toplam uzunluk sınırı getirilmemiştir. Kaynak: IC 9-20-8; Indiana State Police Summary of Size and Weight Laws."},"8":{"q":"Yasal boyut ve ağırlık sınırlarını aşan araçlar için aşırı boyut ve aşırı ağırlık (OSOW) izinlerini hangi Indiana kurumu verir?","options":["Indiana Bureau of Motor Vehicles","Indiana Department of Revenue, Motor Carrier Services","Indiana State Police","Indiana Department of Natural Resources"],"explanation":"OSOW izinleri, INDOT ve Indiana yasalarının belirlediği kurallar kapsamında Indiana Department of Revenue'nun Motor Carrier Services birimi tarafından verilir. Kaynak: IC 9-20-6; Indiana DOR Motor Carrier Services OSOW programı (in.gov/dor)."},"9":{"q":"Indiana, maksimum yasal brüt ve aks ağırlıklarını hesaplamak için federal Bridge Formula'yı eyalet yasasına hangi yılda kabul etti?","options":["1975","1956","1982","1991"],"explanation":"Indiana, Bridge Formula'yı 1975'te eyalet yasası olarak kabul etti ve 4 Ocak 1975'te yürürlükte olan ağırlık sınırları için bir eski hak (grandfather) hükmünü korur. Kaynak: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"10":{"q":"Indiana'nın federal Bridge Formula'yı W = 500{[(LN) / (N-1)] + 12N + 36} olarak kabul etmesi kapsamında, 'N' değişkeni neyi temsil eder?","options":["Araçtaki net kargo ağırlığı","Kombinasyonun feet cinsinden toplam uzunluğu","Çekici aksındaki lastik sayısı","Söz konusu gruptaki aks sayısı"],"explanation":"Bridge Formula'da N, gruptaki aks sayısıdır; L, grubun en uçtaki aksları arasındaki mesafedir ve W, o grup üzerindeki izin verilen brüt ağırlıktır. Kaynak: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws."},"11":{"q":"Indiana'nın Bridge Formula'sı, bu tandemlerin ilk ve son aksları en az ne kadar aralıklı olması koşuluyla iki ardışık tandem aks setinin her birinin 34,000 pounds taşımasına izin verir?","options":["30 feet","40 feet","36 feet","51 feet"],"explanation":"Setlerin ilk ve son aksları en az 36 feet aralıklı olursa, iki ardışık tandem aks setinin her biri 34,000 pounds'a kadar taşıyabilir. Kaynak: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws."},"12":{"q":"Birbirine bağlanmış iki aracın kombinasyonu, yük dahil, Indiana karayollarında genel olarak hangi toplam uzunluğu aşamaz?","options":["65 feet","55 feet","75 feet","60 feet"],"explanation":"Birbirine bağlanmış iki aracın kombinasyonu, yük dahil, 60 feet'i aşamaz (tekne/araç taşıyıcıları ve drive-away hizmeti gibi sınırlı istisnalar dışında). Kaynak: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws."},"13":{"q":"Birbirine bağlanmış üç veya daha fazla aracın kombinasyonu, yük dahil, Indiana yasaları kapsamında hangi toplam uzunluğu aşamaz?","options":["60 feet","70 feet","65 feet","75 feet"],"explanation":"Indiana, birbirine bağlanmış üç veya daha fazla aracın kombinasyonunu, yük dahil, 65 feet ile sınırlar. Kaynak: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws."},"14":{"q":"Indiana, tarımsal ürünleri üretim yerinden ilk teslimat noktasına taşıyan bir araç için %10 brüt ağırlık toleransı tanır; hangi durum HARİÇ?","options":["Araç eyaletler arası (interstate) sistemin herhangi bir bölümünde işletildiğinde","Yük geceleyin taşındığında","Aracın beşten fazla aksı olduğunda","Sefer 50 mile'ı aştığında"],"explanation":"%10 tarımsal ürün brüt ağırlık toleransı, eyaletler arası (interstate) sistemin herhangi bir bölümünde veya IC 9-20-1-4 kapsamında işaretli köprü/karayolu sınırlarının geçerli olduğu yerlerde uygulanmaz. Kaynak: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"15":{"q":"Bir kombinasyon aracına 80,000 pounds brüt ağırlık izni verilmişse, Indiana'nın %10 toleransı kapsamında uygun tarımsal ürünleri taşırken maksimum brüt ağırlığı nedir?","options":["84,000 pounds","90,000 pounds","88,000 pounds","86,000 pounds"],"explanation":"Indiana, uygun tarımsal ürün taşımalarında izin verilen brüt ağırlığa %10 ekler, böylece 80,000 pounds, 88,000 pounds olur (yalnızca interstate dışı, işaretsiz güzergahlarda). Kaynak: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"16":{"q":"Indiana, %10 ağırlık toleransı için belirli orman ürünlerini tarımsal ürün olarak değerlendirir. Bunlardan hangisi için %10 tolerans brüt ve aks ağırlığında HER ZAMAN uygulanır?","options":["İşlenmiş kereste ve kontrplak","Odun yongaları, kabuk ve talaş","Mobilya ve dolap","Kağıt ve mukavva"],"explanation":"Tarımsal ürünler tomruk, odun yongaları, kabuk, talaş ve dökme sütü kapsar; odun yongaları, kabuk ve talaş için %10 tolerans her zaman brüt ve aks ağırlıklarına uygulanır. Kaynak: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"17":{"q":"Indiana'nın 4 Ocak 1975'te yürürlükte olan ağırlık sınırlarını koruyan eski hak (grandfather) hükmü kapsamında, etkilenen araç konfigürasyonları için maksimum brüt ağırlık nedir?","options":["80,000 pounds","70,000 pounds","64,000 pounds","73,280 pounds"],"explanation":"Indiana'nın eski hak (grandfather) yasası, aksi takdirde Bridge Formula tarafından cezalandırılacak konfigürasyonlar için 73,280 pounds'luk maksimum brüt ağırlığı korur. Kaynak: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"18":{"q":"Eyaletler arası (interstate) karayolları dışında, Indiana'da uygun bir belediye atık/çöp toplama aracı için izin verilen maksimum tek aks ağırlığı nedir?","options":["20,000 pounds","24,000 pounds","22,400 pounds","26,000 pounds"],"explanation":"Eyaletler arası (interstate) sistem dışında, uygun atık araçları tek aks üzerinde 24,000 pounds'a ve tandem aks üzerinde 42,000 pounds'a kadar taşıyabilir, ancak IC 9-20-11-4 kapsamındaki tekerlek ağırlığı sınırlarına tabi kalır. Kaynak: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"19":{"q":"Indiana'da, çekilen araçların GVWR'si 10,000 pounds'un üzerinde olan ve Gross Combination Weight Rating (GCWR) değeri 26,001 pounds veya daha fazla olan bir araç kombinasyonunu işletmek için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Indiana, çekilen ünitelerin GVWR'sinin 10,000 pounds'u aşması koşuluyla, GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç kombinasyonunu Class A CDL olarak tanımlar. Kaynak: Indiana CDL Manual (Indiana BMV); Indiana tarafından kabul edilen 49 CFR 383.91."},"20":{"q":"Indiana kuralları kapsamında, GVWR'si 26,001 pounds veya daha fazla olan tek bir araç (veya GVWR'si 10,000 pounds'u aşmayan bir ünite çeken böyle bir araç) hangi CDL sınıfını gerektirir?","options":["Class C","Class B","Class A","Chauffeur license"],"explanation":"Indiana, GVWR'si 26,001 lbs veya daha fazla olan tek bir aracı ya da GVWR'si 10,000 lbs'yi aşmayan bir ünite çeken böyle bir aracı Class B CDL olarak tanımlar. Kaynak: Indiana CDL Manual (Indiana BMV)."},"21":{"q":"Indiana'da, Class A veya Class B ağırlık eşiklerini karşılamayan ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da işaretli (placarded) tehlikeli madde taşıyan bir araç hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","CDL gerekmez"],"explanation":"Indiana'da Class C CDL, Class A/B ağırlık sınırlarının altında olup 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış ya da işaret (placard) gerektiren tehlikeli madde taşıyan araçları kapsar. Kaynak: Indiana CDL Manual (Indiana BMV)."},"22":{"q":"Yalnızca eyalet içi (Indiana içinde) sürüş ile sınırlı bir Indiana CDL'i almak için minimum yaş nedir?","options":["16 yaş","17 yaş","18 yaş","21 yaş"],"explanation":"Indiana, eyalet içi işletme için CDL veya CLP sahibi olmak isteyen başvuru sahiplerinin en az 18 yaşında olmasını gerektirir; 18-20 yaş arası sürücüler ticari araçları yalnızca Indiana içinde işletmekle sınırlıdır. Kaynak: Indiana CDL Manual (Indiana BMV); IC 9-24."},"23":{"q":"Bir Indiana CDL ile eyaletler arası ticarette (eyalet sınırlarını aşarak) ticari motorlu araç sürmek için minimum yaş nedir?","options":["18 yaş","19 yaş","20 yaş","21 yaş"],"explanation":"Bir sürücünün eyaletler arası ticari motorlu araç işletmek, tehlikeli madde taşımak veya eyalet sınırlarını aşarak yolcu taşımak için en az 21 yaşında olması gerekir. 18-20 yaş arası sürücüler Indiana'da eyalet içi sürüş ile sınırlıdır. Kaynak: Indiana CDL Manual (Indiana BMV); 49 CFR 391.11."},"24":{"q":"Indiana, 119 gallon'dan fazla kapasiteli tek bir tankta (toplamda 1,000+ gallon ile) sıvı veya gaz taşıyan bir tank aracını sürmek için hangi onayı (endorsement) gerektirir?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"Indiana'nın N (Tank Vehicle) onayı, bireysel anma kapasitesi 119 gallon'dan fazla ve toplam kapasitesi 1,000 gallon veya daha fazla olan bir tankta sıvı veya gaz taşımak için tasarlanmış araçlar için gereklidir. Kaynak: Indiana BMV CDL Endorsements and Restrictions."},"25":{"q":"İki veya üç ayrı römork (ikili/üçlü) çeken bir aracı işletmek için hangi Indiana CDL onayı (endorsement) gereklidir?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement S"],"explanation":"T onayı, iki veya üç ayrı römork takılı bir kombinasyonun (ikili/üçlü) işletilmesine izin verir. İkili/üçlü bilgi testini geçerek alınır. Kaynak: Indiana BMV CDL Endorsements and Restrictions."},"26":{"q":"Sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış bir aracı sürmek için hangi Indiana CDL onayı (endorsement) gereklidir?","options":["Endorsement S","Endorsement P","Endorsement N","Endorsement H"],"explanation":"P (Passenger) onayı, sürücü dahil 16 veya daha fazla yolcu taşımak için tasarlanmış bir aracı işletmek için gereklidir. Bilgi testi, temsili bir araçta beceri testi ve ilk kez başvuranlar için ELDT gerektirir. Kaynak: Indiana BMV CDL Endorsements and Restrictions."},"27":{"q":"Indiana'da, H (Hazardous Materials) onayını almak için bir başvuru sahibinin tamamlaması gereken ek federal tarama nedir?","options":["Parmak izi alımı dahil bir TSA güvenlik tehdidi değerlendirmesi","Bir FBI poligraf muayenesi","Parmak izi olmadan yalnızca eyalet düzeyinde bir sabıka kaydı kontrolü","Bir DEA kontrollü madde görüşmesi"],"explanation":"H onayını eklemek, HazMat bilgi testini geçmeyi ve parmak izi alımı ile yasal statü doğrulamasını içeren bir TSA güvenlik tehdidi değerlendirmesini tamamlamayı gerektirir. Kaynak: Indiana BMV CDL Endorsements and Restrictions; 49 CFR 1572 (TSA)."},"28":{"q":"Bir Indiana CDL sahibi, Hazardous Materials (H) onayını korumak için TSA güvenlik tehdidi değerlendirmesini ne sıklıkla yenilemelidir?","options":["Her yıl","Her 2 yılda bir","Her 5 yılda bir","Her 10 yılda bir"],"explanation":"HazMat onayı için TSA güvenlik tehdidi değerlendirmesi beş yıl geçerlidir ve en az her beş yılda bir (yeni bir HazMat bilgi testi ile) yenilenmelidir. Kaynak: Indiana BMV CDL Endorsements and Restrictions; TSA HazMat Endorsement programı."},"29":{"q":"Bir sürücü hem Hazardous Materials hem de Tank Vehicle onaylarına sahip olduğunda Indiana hangi birleşik onay kodunu verir?","options":["Endorsement X","Endorsement HN","Endorsement Z","Endorsement W"],"explanation":"Indiana, H (HazMat) ve N (Tank Vehicle) ayrıcalıklarının kombinasyonunu temsil etmek için X onayını verir. Kaynak: Indiana BMV CDL Endorsements and Restrictions."},"30":{"q":"Indiana'da CDL beceri testine girmeden önce, bir başvuru sahibinin geçerli bir Commercial Learner's Permit (CLP) bulundurması ne kadar süre gereklidir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 60 gün"],"explanation":"Bir başvuru sahibi, CDL beceri sınavına girmeden önce CLP'yi en az 14 gün bulundurmalıdır. Bu, Indiana tarafından kabul edilen federal asgari süredir. Kaynak: Indiana CDL Manual / Indiana BMV; 49 CFR 383.25."},"31":{"q":"Indiana BMV'ye göre, bir Commercial Learner's Permit (CLP) verildikten sonra ne kadar süre geçerlidir?","options":["30 gün","90 gün","Bir yıl","Beş yıl"],"explanation":"Indiana BMV, bir CLP'nin bir yıl geçerli olduğunu belirtir ve CDL bilgi sınavı sonuçları da benzer şekilde bir yıl geçerlidir. Kaynak: Indiana BMV, Obtaining a Commercial Learner's Permit."},"32":{"q":"Bir Indiana CLP sahibi, ticari bir motorlu aracı işletirken hangi kısıtlamaya tabidir?","options":["Yalnızca eyaletler arası karayollarında tek başına sürebilirler","Uygun sınıfa ve onaylara sahip bir CDL sahibi tarafından refakat edilmeleri gerekir","Yalnızca gün doğumu ile gün batımı arasında sürebilirler","Yalnızca GVWR'si 26,001 pounds'un altındaki araçları işletebilirler"],"explanation":"Bir CLP sahibi, ticari bir motorlu aracı yalnızca uygun sınıfa ve onaylara sahip geçerli bir CDL bulunduran ve CLP sahibinin yanında oturan bir kişi tarafından refakat edildiğinde işletebilir. Kaynak: Indiana BMV, Obtaining a Commercial Learner's Permit; 49 CFR 383.25."},"33":{"q":"Bir Indiana CDL veya CLP'sine başvururken, bir başvuru sahibinin Indiana ikametini kanıtlamak için kaç belge sunması gerekir?","options":["Bir belge","İki belge","Üç belge","İkamet kanıtı gerekmez"],"explanation":"Indiana, Indiana ikametini kanıtlayan iki belge ile birlikte kimliği kanıtlayan bir belge, yasal statüyü kanıtlayan bir belge ve tam Social Security numarasını kanıtlayan bir belge gerektirir. Kaynak: Indiana BMV belge gereksinimleri."},"34":{"q":"Kimlik ve Indiana ikamet kanıtına ek olarak, bir Indiana CDL başvuru sahibinin hangi iki öğeyi belgelemesi gerekir?","options":["ABD'de yasal statü ve tam Social Security numarası","Bir lise diploması ve araç tapusu","Bir görme uzmanı mektubu ve işveren beyanı","Seçmen kaydı ve bir hizmet faturası depozito makbuzu"],"explanation":"Indiana, kimlik ve iki ikamet belgesine ek olarak, ABD'de yasal statüyü (yasal varlık) kanıtlayan bir belge ile başvuru sahibinin tam Social Security numarasını kanıtlayan bir belge gerektirir. Kaynak: Indiana BMV belge gereksinimleri."},"35":{"q":"7 Şubat 2022 tarihinden itibaren geçerli olmak üzere, Indiana başvuru sahiplerinin hangi durumda Entry-Level Driver Training (ELDT) tamamlaması gerekir?","options":["Sınıf değişikliği olmadan mevcut bir Class A CDL'i yenilerken","İlk Class A veya Class B CDL'i ya da ilk H, P veya S onayını alırken","Yalnızca T (ikili/üçlü) onayını eklerken","Muaf eyalet içi olarak kendi kendini sertifikalandırırken"],"explanation":"ELDT, 7 Şubat 2022'de veya sonrasında ilk Class A veya Class B CDL'i alan, daha yüksek bir sınıfa yükselten ya da ilk kez Hazardous Materials (H), Passenger (P) veya School Bus (S) onayını alan sürücüler için geçerlidir. Kaynak: FMCSA ELDT kuralı; Indiana BMV."},"36":{"q":"Bir Indiana başvuru sahibi, gerekli Entry-Level Driver Training (ELDT)'i nerede tamamlamalıdır?","options":["Başvuru sahibinin seçeceği herhangi bir özel sürücü kursunda","FMCSA Training Provider Registry'de listelenen bir sağlayıcıyla","Bir Indiana BMV şube test merkezinde","TSA onaylı çevrimiçi bir kurs aracılığıyla"],"explanation":"ELDT teori ve direksiyon başında eğitimi, FMCSA Training Provider Registry (TPR)'de listelenen bir kuruluş tarafından verilmelidir; yalnızca listelenen sağlayıcılar tamamlanmayı bildirebilir. Kaynak: FMCSA Training Provider Registry; Indiana BMV."},"37":{"q":"Bir Indiana CDL sahibi, yalnızca Indiana içinde işletme yapıyorsa ve bir tıbbi muayene sertifikası ile eyaletin sürücü yeterlilik gereksinimlerini karşılaması gerekiyorsa hangi tıbbi kendi kendini sertifikalandırma kategorisini seçer?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Non-Excepted Intrastate (NA), yalnızca eyalet içi (Indiana içinde) ticarette işletme yapan ve Indiana'nın sürücü yeterlilik kurallarını karşılaması ile bir tıbbi muayene sertifikası sunması gereken sürücüler için geçerlidir. Kaynak: Indiana BMV CDL kendi kendini sertifikalandırma; 49 CFR 383.71."},"38":{"q":"Hangi kendi kendini sertifikalandırma kategorisi, bir Indiana CDL sahibinin FMCSA National Registry'de yer alan bir sağlayıcıdan geçerli bir federal DOT Medical Examiner's Certificate bulundurmasını gerektirir?","options":["Excepted Intrastate (EA)","Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Restricted Agricultural (RA)"],"explanation":"Non-Excepted Interstate (NI) olarak kendi kendini sertifikalandıran bir sürücü, muaf olmayan ticarette eyalet sınırlarını aşarak işletme yapar ve FMCSA National Registry'deki sertifikalı bir muayene uzmanı tarafından düzenlenmiş geçerli bir Medical Examiner's Certificate bulundurmalı ve sürdürmelidir. Kaynak: Indiana BMV CDL kendi kendini sertifikalandırma; 49 CFR 391.41."},"39":{"q":"Indiana'da, bir ticari motorlu aracı (CMV) işletmenin yasal olduğu maksimum kan alkol konsantrasyonu (BAC) nedir?","options":["0.04% altında","0.08% altında","0.02% altında","0.10% altında"],"explanation":"Indiana BMV CDL Manual (Section 1.3.2), kan alkol konsantrasyonunuz .04% veya daha fazlaysa bir CMV işletmenin yasa dışı olduğunu belirtir, bu nedenle bir CMV sürücüsü 0.04%'ün altında kalmalıdır (ticari olmayan sürücüler için 0.08% sınırının yarısı). Kaynak: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2."},"40":{"q":"Indiana'nın zımni rıza (implied-consent) kuralı kapsamında, bir CMV işletmek bir sürücünün neyi kabul ettiği anlamına gelir?","options":["Alkol testine tabi olmayı","Avukat hakkından feragat etmeyi","Herhangi bir zamanda araç muayenesine","Zorunlu bir uyuşturucu tedavi programına"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2), bir CMV işletirseniz, alkol testine rıza göstermiş sayılacağınızı belirtir. Kaynak: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2; IC 9-30-6."},"41":{"q":"0.04% veya daha yüksek BAC ile bir CMV sürmek gibi ilk büyük ihlal (major offense) için, bir Indiana CDL sahibi CDL'sini ne kadar süreyle kaybeder?","options":["En az 1 yıl","En az 6 ay","En az 90 gün","En az 3 yıl"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2), 0.04% veya daha yüksek BAC ile bir CMV sürmek dahil ilk büyük ihlal için CDL'nizi en az bir yıl kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51)."},"42":{"q":"İlk büyük ihlal, sürücü tehlikeli madde için işaretli (placarded) bir CMV işletirken meydana gelirse, Indiana'daki minimum diskalifiye süresi nedir?","options":["En az 3 yıl","En az 1 yıl","En az 5 yıl","Ömür boyu"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2), ilk büyük ihlal tehlikeli madde için işaretli (placarded) bir CMV işletirken meydana gelirse CDL'nizi en az üç yıl kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.2."},"43":{"q":"Indiana CDL kuralları kapsamında ikinci büyük ihlalin (örneğin ikinci bir CMV DWI) sonucu nedir?","options":["CDL'nin ömür boyu kaybı","CDL'nin 10 yıl kaybı","CDL'nin 3 yıl kaybı","CDL'nin 5 yıl kaybı"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2), ikinci bir büyük ihlal için CDL'nizi ömür boyu kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51)."},"44":{"q":"Aşağıdakilerden hangisi, bir Indiana CDL sahibine en az bir yıl ehliyetine mal olan ilk büyük ihlal olarak değerlendirilir?","options":["Kan alkol testine girmeyi reddetmek","Bir aracı çok yakından takip etmek","İşaretli sınırın 16 mph üzerinde sürmek","Uygunsuz bir şerit değişikliği"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2), kan alkol testine girmeyi reddetmeyi en az bir yıllık diskalifiye taşıyan bir büyük ihlal olarak listeler; diğer seçenekler büyük ihlal değil, ciddi trafik ihlalleridir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.2."},"45":{"q":"Indiana'da, kontrollü maddeler içeren bir suç işlemek için bir CMV kullanan bir CDL sahibine ne olur?","options":["CDL'nin ömür boyu kaybı","CDL'nin 3 yıl kaybı","CDL'nin 1 yıl kaybı","CDL'nin 5 yıl kaybı"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2), kontrollü maddeler içeren bir suç işlemek için bir CMV kullanırsanız CDL'nizi ömür boyu kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.2."},"46":{"q":"Indiana'daki bir CMV sürücüsünün 0.04%'ün altında saptanabilir miktarda alkol bulundurduğu tespit edilir. Bunun anlık sonucu nedir?","options":["24 saat hizmet dışı (out-of-service) bırakılır","CDL 60 gün diskalifiye edilir","$2,750 idari para cezası","CDL 1 yıl diskalifiye edilir"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2), 0.04%'ün altında saptanabilir herhangi bir miktarda alkol bulundurursanız 24 saat hizmet dışı (out-of-service) bırakılacağınızı belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.2."},"47":{"q":"Indiana CDL Manual, ciddi bir trafik ihlali olarak 'aşırı hız' (excessive speeding) tanımını nasıl yapar?","options":["İşaretli sınırın 15 mph veya üzerinde","İşaretli sınırın 10 mph veya üzerinde","İşaretli sınırın 20 mph veya üzerinde","İşaretli sınırın 25 mph veya üzerinde"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3), aşırı hızı işaretli sınırın 15 mph veya üzerinde olarak tanımlar. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.3."},"48":{"q":"Üç yıllık bir süre içinde bir CMV'de iki ciddi trafik ihlali için, bir Indiana CDL sahibi CDL'sini ne kadar süreyle kaybeder?","options":["En az 60 gün","En az 30 gün","En az 90 gün","En az 120 gün"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3), bir CMV içeren üç yıllık bir süre içindeki iki ciddi trafik ihlali için CDL'nizi en az 60 gün kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.3."},"49":{"q":"Üç yıllık bir süre içinde bir CMV'de üç veya daha fazla ciddi trafik ihlali için Indiana diskalifiye süresi nedir?","options":["En az 120 gün","En az 60 gün","En az 90 gün","En az 1 yıl"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3), bir CMV içeren üç yıllık bir süre içindeki üç veya daha fazla ciddi trafik ihlali için CDL'nizi en az 120 gün kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.3."},"50":{"q":"Aşağıdakilerden hangisi Indiana CDL Manual'da ciddi bir trafik ihlali olarak listelenmiştir?","options":["Dikkatsiz sürüş (reckless driving)","0.04% BAC ile bir CMV sürmek","Bir CMV kazasının olay yerini terk etmek","Bir kan alkol testini reddetmek"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3), dikkatsiz sürüşü (reckless driving) ciddi trafik ihlalleri arasında listeler; diğer üçü Sec. 1.3.2 kapsamındaki büyük ihlallerdir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.3."},"51":{"q":"Indiana'da bir hizmet dışı (out-of-service) emrinin ilk ihlali için minimum diskalifiye süresi nedir?","options":["En az 90 gün","En az 60 gün","En az 30 gün","En az 180 gün"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.4), bir hizmet dışı emrinin ilk ihlali için CDL'nizi en az 90 gün kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.4."},"52":{"q":"Indiana'da on yıllık bir süre içinde iki hizmet dışı (out-of-service) emri ihlali için minimum diskalifiye süresi nedir?","options":["En az 1 yıl","En az 90 gün","En az 6 ay","En az 3 yıl"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.4), on yıllık bir süre içinde bir hizmet dışı emrinin iki ihlali için CDL'nizi en az bir yıl kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.4."},"53":{"q":"On yıllık bir süre içinde üç veya daha fazla hizmet dışı (out-of-service) emri ihlali, Indiana'da hangi minimum diskalifiye süresiyle sonuçlanır?","options":["En az 3 yıl","En az 1 yıl","En az 5 yıl","Ömür boyu"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.4), on yıllık bir süre içinde bir hizmet dışı emrinin üç veya daha fazla ihlali için CDL'nizi en az üç yıl kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.4."},"54":{"q":"Indiana'da bir demiryolu-karayolu hemzemin geçit ihlalinin ilki için minimum diskalifiye süresi nedir?","options":["En az 60 gün","En az 30 gün","En az 90 gün","En az 120 gün"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.5), ilk demiryolu-karayolu hemzemin geçit ihlaliniz için CDL'nizi en az 60 gün kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.5."},"55":{"q":"Üç yıllık bir süre içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali, Indiana'da hangi minimum diskalifiye süresini taşır?","options":["En az 120 gün","En az 60 gün","En az 90 gün","En az 1 yıl"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.5), üç yıllık bir süre içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali için CDL'nizi en az 120 gün kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.5."},"56":{"q":"Üç yıllık bir süre içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali, Indiana'da hangi minimum diskalifiye süresini taşır?","options":["En az 1 yıl","En az 120 gün","En az 6 ay","En az 3 yıl"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.5), üç yıllık bir süre içinde üçüncü bir demiryolu-karayolu hemzemin geçit ihlali için CDL'nizi en az bir yıl kaybedeceğinizi belirtir. Kaynak: Indiana BMV CDL Manual, Sec. 1.3.5."},"57":{"q":"Indiana kuralları kapsamında, bir CMV sürerken mesajlaşmayı yasaklayan bir eyalet yasasının kaç mahkumiyetinden sonra bir CDL diskalifiye edilir ve ikinci ihlalde ne kadar süreyle?","options":["İki veya daha fazla mahkumiyet; 3 yıl içinde ikinci ihlal için 60 gün","Bir mahkumiyet; derhal 120 gün","İki mahkumiyet; ikinci ihlal için 1 yıl","Üç mahkumiyet; üçüncü ihlal için 30 gün"],"explanation":"Indiana BMV CDL Manual (Sec. 2.9.5), bir CMV işletirken herhangi bir eyalet mesajlaşma yasasının iki veya daha fazla mahkumiyetinden sonra CDL'nizin diskalifiye edileceğini belirtir; 3 yıl içindeki ikinci ihlal için 60 gün (3 yıl içinde üç veya daha fazlası için 120 gün) diskalifiye uygulanır. Kaynak: Indiana BMV CDL Manual, Sec. 2.9.5."},"58":{"q":"Indiana CDL Manual'a göre, elde tutulan cep telefonu veya mesajlaşma kısıtlamasını ihlal eden bir CMV sürücüsü, en fazla hangi tutarda bir idari para cezasına tabidir?","options":["$2,750","$1,000","$5,000","$11,000"],"explanation":"Indiana BMV CDL Manual (Secs. 2.9.4-2.9.5), elde tutulan telefon veya mesajlaşma yasağının her ihlalinin sürücüyü en fazla $2,750 idari para cezasına tabi kıldığını belirtir; işverenler en fazla $11,000'a kadar cezalara tabi olabilir. Kaynak: Indiana BMV CDL Manual, Secs. 2.9.4 and 2.9.5."},"59":{"q":"Indiana'da kırsal bir eyaletler arası otoyolda (kentleşmiş bir bölgenin dışında), beyan edilen brüt ağırlığı 26,000 pounddan fazla olan yüklü bir çekici-römork için azami hız sınırı nedir?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"IC 9-21-5-2 uyarınca, beyan edilen brüt ağırlığı 26,000 pounddan fazla olan, otobüs dışındaki bir araç kırsal eyaletler arası otoyollarda 65 mph ile sınırlıyken, binek otomobiller 70 mph hızla seyredebilir. Indiana'nın eyaletler arası otoyollardaki ayrı (kamyon ve otomobil) hız işaretlerinin temeli budur."},"60":{"q":"Bir binek otomobil Indiana'daki kırsal bir eyaletler arası otoyolda 70 mph hızla seyredebilir. Aynı yerde, yolcu taşıyan bir tur otobüsü yasal olarak en fazla ne kadar hızla seyahat edebilir?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"IC 9-21-5-2, 26,000 lbs üzeri 'otobüs dışındaki' araçlara 65 mph kamyon sınırını uygular. Otobüsler azaltılmış kamyon sınırına tabi değildir, bu nedenle bir otobüs kırsal eyaletler arası otoyollarda işaretli 70 mph hızla seyahat edebilir. Kaynak: Indiana Code 9-21-5-2."},"61":{"q":"Indiana'daki bir otoyolda plakart taşıyan tehlikeli madde tankeri sürüyorsunuz. Durmanın gerekli olduğu bir demiryolu hemzemin geçidinde durmanız gereken yer:","options":["En yakın raya 15 fitten daha yakın olmamak ve 50 fitten fazla olmamak üzere","En yakın raya 10 fitten daha yakın olmamak ve 25 fitten fazla olmamak üzere","En yakın raydan tam olarak 50 fit","En yakın raya 50 fitten daha yakın olmamak ve 100 fitten fazla olmamak üzere"],"explanation":"Indiana CDL El Kitabı (Bölüm 9.6.12), plakart taşıyan araçların, klor taşıyıcılarının ve yük tankı araçlarının en yakın raydan 15 ila 50 fit mesafede durmasını, ardından yalnızca hiçbir trenin gelmediğinden emin olduktan sonra devam etmesini gerektirir. Kaynak: Indiana CDL El Kitabı."},"62":{"q":"Indiana'nın Move Over (Şerit Değiştir) yasası (IC 9-21-8-35), yanıp sönen ışıklar gösteren duran bir acil durum veya arızalı araçtan uzağa şerit değiştirmenizi gerektirir. Güvenli bir şekilde şerit değiştiremiyorsanız, yapmanız gereken:","options":["Hızınızı işaretli hız sınırının 10 mph altına düşürmek","Devam etmek güvenli olana kadar tamamen durmak","Korna çalmak ve işaretli hızı korumak","Hızınızı işaretli hız sınırının 20 mph altına düşürmek"],"explanation":"IC 9-21-8-35 uyarınca, şerit değiştirmek mümkün veya güvenli değilse, sürücü geçerken işaretli hız sınırının en az 10 mph altına yavaşlamalıdır. INDOT bunu 'Move Over or Slow Down' (Şerit Değiştir veya Yavaşla) olarak teşvik eder. Kaynak: IC 9-21-8-35; INDOT."},"63":{"q":"Indiana'da seyahat yönünüzde iki şeridin bulunduğu bir eyaletler arası otoyolda, bir çekici, geçiş yapma, giriş/çıkış yapma veya özel bir tehlikeden kaçınma durumları dışında genellikle hangi şeritle sınırlıdır?","options":["Serbestçe her iki şerit","Sol (geçiş) şeridi","En sağ şerit","Yolun ortası"],"explanation":"IC 9-21-8-12, bir kamyonun veya çekicinin eyaletler arası bir otoyolda en sağ şerit dışında herhangi bir şeritte kullanılmasını yasaklar; bunun istisnaları daha yavaş bir aracı geçmek, otoyola girmek veya çıkmak ya da özel bir tehlikenin başka bir şeridi gerektirdiği durumlardır. Kaynak: Indiana Code 9-21-8-12."},"64":{"q":"Indiana'da seyahat yönünüzde üç veya daha fazla şeridin bulunduğu bir eyaletler arası otoyolda, bir çekici şununla sınırlıdır:","options":["Yalnızca en sağ şerit","Yalnızca sağdaki iki şerit","En sol hariç herhangi bir şerit","Yalnızca orta şerit"],"explanation":"IC 9-21-8-13, tek yönde en az üç şeridi olan eyaletler arası otoyollardaki kamyonları sağdaki iki şeritle sınırlar; bunun istisnaları otoyola girmek veya çıkmak ya da özel bir tehlikeden kaçınmaktır. Bu, iki şeritli kesimler için geçerli tek şerit kuralından daha esnektir. Kaynak: Indiana Code 9-21-8-13."},"65":{"q":"Indiana'da, uzatılmış dur kolunu ve yanıp sönen kırmızı ışıklarını gösteren duran bir okul otobüsüyle karşılaşan veya onu geçen bir sürücü durmalı ve şu zamana kadar durmuş halde kalmalıdır:","options":["Otobüs sürücüsü el sallayarak geçmesini işaret edene kadar","Beş saniye geçene kadar","Dur kolu geri çekilene ve kırmızı ışıkların yanıp sönmesi durana kadar","Ona kadar sayana kadar"],"explanation":"IC 9-21-12-1 uyarınca, bir sürücü kol işaret cihazı uzatıldığında otobüse ulaşmadan önce durmalı ve cihaz artık uzatılmamış olana (ışıklar yanıp sönmeyi durdurana) kadar devam edemez. İhlal bir Class A infraction'dır. Kaynak: Indiana Code 9-21-12-1."},"66":{"q":"Dört şeritli bir yolun DİĞER tarafında bulunan duran bir okul otobüsüne (kırmızı ışıkları yanıp sönen) doğru sürüyorsunuz. Indiana'nın okul otobüsü yasası uyarınca, yalnızca iki yol şunlarla ayrılmışsa durmak ZORUNDA DEĞİLSİNİZ:","options":["Boyalı bir orta çizgi veya çift yönlü sol dönüş şeridi","Dört veya daha fazla kaplama şeridi","En az 4 fit genişliğinde düz boyalı bir orta refüj","Fiziksel bir bariyer veya seyahat için tasarlanmamış iyileştirilmemiş/ayırıcı bir refüj"],"explanation":"IC 9-21-12-3, yaklaşan bir sürücüyü durmaktan yalnızca yollar iyileştirilmemiş bir ara boşluk, fiziksel bir bariyer veya trafiği engellemek için inşa edilmiş bir ayırıcı bölümle ayrıldığında ve otobüs karşı tarafta olduğunda muaf tutar. Yalnızca boyalı bir çizgi nitelik kazanmaz—yine de durmalısınız. Kaynak: Indiana Code 9-21-12-3."},"67":{"q":"CMV'nizi bölünmüş bir Indiana otoyolunun banketinde durdurmak zorundaysanız, acil durum uyarı cihazlarınızı ne kadar süre içinde yerleştirmelisiniz?","options":["2 dakika içinde","5 dakika içinde","10 dakika içinde","Hemen, kabinden çıkmadan önce"],"explanation":"Indiana CDL El Kitabı (Bölüm 2.5), bir yolda veya bankette durursanız acil durum uyarı cihazlarını 10 dakika içinde yerleştirmeniz gerektiğini belirtir. Kaynak: Indiana CDL El Kitabı."},"68":{"q":"Tek yönlü veya bölünmüş bir Indiana otoyolunda durduğunuzda, üç uyarı üçgeninizi nereye yerleştirirsiniz?","options":["Yaklaşan trafiğe doğru 10 ft, 100 ft ve 200 ft","Yaklaşan trafiğe doğru 10 ft, 50 ft ve 100 ft","100 ft önde, 100 ft arkada ve aracın yanında","Dörtlü flaşörler açık olarak yalnızca aracın yanında"],"explanation":"Indiana CDL El Kitabı, tek yönlü veya bölünmüş bir otoyolda uyarı cihazlarının yaklaşan trafiğe doğru 10 fit, 100 fit ve 200 fit mesafelere yerleştirilmesini talimat verir. Kaynak: Indiana CDL El Kitabı, Bölüm 2.5."},"69":{"q":"Her iki yönde de trafik taşıyan iki şeritli bir Indiana yolunda durduğunuzda, uyarı üçgenleriniz nereye yerleştirilmelidir?","options":["Yalnızca aracın arkasında 10 ft, 100 ft ve 200 ft mesafelere","Yalnızca 50 ft önde ve 50 ft arkada","Yalnızca 200 ft önde ve 200 ft arkada","Aracın 10 ft yakınında ve 100 ft önde ile 100 ft arkada"],"explanation":"Bölünmemiş çift yönlü bir yolda, Indiana CDL El Kitabı aracı işaretlemek için ön veya arka köşenin 10 fit yakınına bir üçgen, ayrıca 100 fit önde ve 100 fit arkada birer üçgeni bankette veya şeritte gerektirir. Kaynak: Indiana CDL El Kitabı, Bölüm 2.5."},"70":{"q":"Indiana'da sürdüğünüz bir okul otobüsü bir demiryolu hemzemin geçidine yaklaşır. Otobüsünüzü durdurmanız gereken yer:","options":["Geçişten 15 ila 50 fit önce","Raya 5 fitten daha yakın olmamak üzere","Raydan tam olarak 25 fit","Yalnızca bir tren görünürse"],"explanation":"Indiana CDL El Kitabı (Bölüm 4.3.5), otobüs sürücülerine otobüsü demiryolu geçişlerinden 15 ila 50 fit önce durdurmalarını, ardından devam etmeden önce her iki yöne bakıp dinlemelerini talimat verir. Kaynak: Indiana CDL El Kitabı."},"71":{"q":"Indiana'nın değiştirilmiş Move Over yasası uyarınca, yanıp sönen ışıklara sahip duran bir araç için şerit değiştirmeyen veya yavaşlamayan bir sürücü (yaralanma ile sonuçlanmayan), şunu işler:","options":["Class A infraction","Class B infraction","Class C infraction","Class D felony"],"explanation":"IC 9-21-8-35'in temel bir ihlali bir Class B infraction'dır; yalnızca ihlal kapsamdaki bir çalışana ciddi bedensel yaralanma veya ölüme neden olursa bir felony'ye yükselir. Kaynak: IC 9-21-8-35; INDOT."},"72":{"q":"Indiana Gelir Dairesi/INDOT'tan büyük boyut (oversize) izni olmadan, Indiana otoyollarında ticari bir yük için azami yasal GENİŞLİK nedir?","options":["8 fit 0 inç","8 fit 6 inç","10 fit 0 inç","9 fit 0 inç"],"explanation":"Indiana'nın yasal (izinsiz) azami genişliği 8 fit 6 inçtir (102 inç). Bunu aşan yükler Indiana DOR Motor Carrier Services aracılığıyla bir oversize/overweight izni gerektirir. Kaynak: INDOT / Indiana DOR OSOW düzenlemeleri."},"73":{"q":"Indiana'da büyük boyut izni olmadan, bir araç ve yük için azami yasal YÜKSEKLİK nedir?","options":["13 fit 0 inç","13 fit 6 inç","14 fit 0 inç","12 fit 6 inç"],"explanation":"Indiana'nın yasal azami yüksekliği 13 fit 6 inçtir; bundan daha yüksek olan herhangi bir şey bir oversize izni gerektirir. Sürücüler, işaretli köprü yükseklikleri belirleyici olduğundan, yine de açıklıkları doğrulamalıdır. Kaynak: INDOT / Indiana DOR OSOW düzenlemeleri."},"74":{"q":"Aşırı ağırlık (overweight) izni olmadan, Indiana otoyollarında standart bir araç için azami yasal brüt araç ağırlığı nedir?","options":["73,280 pound","90,000 pound","100,000 pound","80,000 pound"],"explanation":"Indiana'nın yasal azami brüt araç ağırlığı 80,000 pounddur (federal eyaletler arası sınırla tutarlı). Daha ağır yükler Indiana DOR Motor Carrier Services'ten bir overweight izni gerektirir. Kaynak: INDOT / Indiana DOR OSOW düzenlemeleri."},"75":{"q":"Çok şeritli bir Indiana otoyolunda, normal trafik akışından daha yavaş seyahat eden bir CMV'nin Indiana yasasına göre yapması gereken:","options":["Birleşen trafikten uzak durmak için en sol şeridi kullanmak","Her zaman orta şeritte seyahat etmek","Herhangi bir şeritte en azından işaretli asgariyi korumak","Seyahat için mevcut sağ şerit(ler)i kullanmak"],"explanation":"IC 9-21-5-9, belirlenen azami hızdan daha yavaş hareket eden araçların sağ şeritleri kullanmasını gerektirir ve geçilirken en sol şeritte devam etmeyi yasaklar. Kaynak: Indiana Code 9-21-5-9."},"76":{"q":"Kırsal bir Indiana bölgesindeki bir okul otobüsü, sırayla yanıp sönen SARI ışıklarını etkinleştirir. Bu ışıklar şu anlama gelir:","options":["Otobüs arızalı—dikkatle geçin","Çocuklar karşıya geçiyor—hemen durun","Otobüs demiryolu durağından muaftır","Otobüs yolcu alıp indirmek için durmaya hazırlanıyor; durmaya hazır olun"],"explanation":"Sarı (amber) ışıklar, otobüsün yolcu alıp indirmek için durmak üzere olduğuna dair bir ön uyarıdır ve kırsal alanlarda yaklaşık 300 fit önceden etkinleştirilir; ardından KIRMIZI ışıklar ve uzatılmış dur kolu trafiğin durmasını gerektirir. Kaynak: Indiana CDL El Kitabı / INDOT okul otobüsü güvenliği."},"77":{"q":"Bir polis memuru, bir Indiana demiryolu hemzemin geçidinde trafiği yönlendiriyor ve plakart taşıyan aracınıza durmadan devam etmesini işaret ediyor. Yapmanız gereken:","options":["Memuru görmezden gelerek yine de 15 ila 50 fit aralığında durmak","Yalnızca bir tren görürseniz durmak","Memurun talimatını izlemek ve zorunlu durma olmadan devam etmek","Geri gidip başka bir geçit bulmak"],"explanation":"Plakart taşıyan ve yolcu araçları için zorunlu 15 ila 50 fitlik durma, bir polis memuru veya işaretçi trafiğe devam etmesini yönlendirdiğinde uygulanmaz (Indiana'da uygulanan 49 CFR 392.10 kapsamında da kabul edilir). Kaynak: Indiana CDL El Kitabı; 49 CFR 392.10."},"78":{"q":"Dur kolu uzatılmış ve kırmızı ışıkları yanıp sönen bir Indiana okul otobüsünü pervasızca geçen bir sürücü, para cezalarına ek olarak şu olası sonuçla karşı karşıya kalır:","options":["İlk suç için 90 güne kadar sürücü belgesi askıya alınması","Belge işlemi olmaksızın zorunlu 30 günlük hapis cezası","Yalnızca yazılı bir uyarı","Herhangi bir ilk suç için kalıcı CDL diskalifikasyonu"],"explanation":"Dur kolu uzatılmış halde duran bir okul otobüsünü geçmek bir Class A infraction'dır (IC 9-21-12-1); pervasız ihlaller IC 9-21-8-52 kapsamına girer ve ilk suçlular 90 güne kadar belge askıya alınmasıyla karşılaşabilir (tekrar edenler için bir yıla kadar). Kaynak: IC 9-21-12-1 ve IC 9-21-8-52."},"79":{"q":"Indiana'da Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["Indiana Bureau of Motor Vehicles (BMV)","Indiana Department of Transportation (INDOT)","Federal Motor Carrier Safety Administration (FMCSA)","Indiana State Police Ticari Araç Bölümü"],"explanation":"Indiana'da CDL'ler Indiana Bureau of Motor Vehicles (BMV) tarafından verilir. CDL el kitabı ve tüm belgelendirme işlemleri BMV şubelerinde yürütülür. Kaynak: Indiana Specific CDL Applicant Information manual (SP 283), Indiana BMV."},"80":{"q":"Indiana'da bir Ticari Öğrenme İzni (CLP) ne kadar süre geçerlidir?","options":["Bir yıl","180 gün","İki yıl","Altı ay, süresiz olarak yenilenebilir"],"explanation":"Mevcut Indiana CDL el kitabına göre, 'Bir CLP bir yıl süreyle geçerlidir.' Kaynak: Indiana Specific CDL Applicant Information manual (SP 283), Commercial Learner's Permit bölümü, Indiana BMV."},"81":{"q":"Indiana'da bir başvuru sahibi, CDL beceri testine girmeyi denemeden önce CLP'yi ne kadar süre elinde tutmalıdır?","options":["En az 14 gün","En az 30 gün","En az 10 gün","En az 60 gün"],"explanation":"El kitabı şunu belirtir: 'Bir başvuru sahibi, CDL beceri testine girmeyi denemeden önce CLP'yi 14 gün elinde tutmalıdır.' Bu, federal asgariyi yansıtır ve Indiana'da geçerlidir. Kaynak: Indiana CDL manual (SP 283), CDL Skills Testing bölümü, Indiana BMV."},"82":{"q":"Indiana'da verilen bir CDL, yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["Dört yıl","Beş yıl","Altı yıl","Üç yıl"],"explanation":"Indiana'da verilen bir CDL dört yıl süreyle geçerlidir. Süresi dolmadan bir yıl öncesine kadar herhangi bir BMV şubesinde yenileyebilirsiniz. Kaynak: Indiana BMV, Renewing or Replacing a CDL."},"83":{"q":"Indiana CDL beceri sınavı hangi üç bölümden oluşur?","options":["Araç (sefer öncesi) muayenesi, temel araç kontrolü ve yolda sürüş","Hava fren testi, kombinasyon testi ve yolda sürüş","Genel bilgi testi, temel kontrol ve sefer öncesi muayene","Sefer öncesi muayene, yazılı onay testi ve yolda sürüş"],"explanation":"Indiana'nın CDL beceri testinin üç bölümü vardır: Araç Muayene Testi (Bölüm 11), Temel Araç Kontrol Beceri Testi (Bölüm 12) ve Yolda Sürüş (Bölüm 13). Kaynak: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV."},"84":{"q":"Indiana'da ilk Class A veya Class B CDL'yi almadan önce, bir başvuru sahibi hangi federal olarak gerekli eğitimi tamamlamalıdır?","options":["FMCSA kayıtlı bir sağlayıcı aracılığıyla Entry-Level Driver Training (ELDT)","Bir BMV şubesinde eyalet tarafından yürütülen bir savunmacı sürüş kursu","INDOT tarafından doğrulanan 160 saatlik bir Indiana çıraklığı","Bir OSHA tehlikeli kargo sertifikasyonu"],"explanation":"Başvuru sahipleri, CDL'yi almadan önce FMCSA Training Provider Registry'de listelenen bir sağlayıcı ile Entry-Level Driver Training (ELDT) tamamlamalıdır. Kaynak: Indiana CDL manual (SP 283); 49 CFR Part 380; 7 Şubat 2022'de yürürlüğe girdi."},"85":{"q":"Bir Indiana CLP veya CDL için gerekli olan tıbbi muayeneyi kim yapmalıdır?","options":["FMCSA National Registry of Certified Medical Examiners'da listelenen bir sağlık muayene uzmanı","Başvuru sahibinin seçtiği herhangi bir lisanslı Indiana hekimi","Doğrudan Indiana BMV tarafından istihdam edilen bir hekim","INDOT'un izin ofisi tarafından onaylanmış bir sağlık muayene uzmanı"],"explanation":"Tüm tıbbi muayeneler, FMCSA National Registry of Certified Medical Examiners'da (nationalregistry.fmcsa.dot.gov) sertifikalı bir sağlık muayene uzmanı tarafından tamamlanmalıdır. Kaynak: Indiana CDL manual (SP 283), Medical Examiner Requirements, Indiana BMV."},"86":{"q":"Sağlık Muayene Uzmanı Sertifikası (MEC) Indiana BMV'nin sistemine nasıl girer?","options":["Sertifikalı muayene uzmanı MEC'yi FMCSA National Registry'ye yükler ve böylece BMV sistemine uygulanmasını sağlar","Başvuru sahibi kağıt kartı Washington, D.C.'deki FMCSA merkezine postalar","INDOT, bir yol kenarı denetiminden sonra sertifikayı BMV'ye iletir","Sertifika, başvuru sahibi beceri testini geçtiğinde otomatik olarak oluşturulur"],"explanation":"El kitabı, CLP/CDL sahiplerine sertifikalı hekimin MEC'yi National Registry'ye yüklemesini sağlamalarını talimat verir, böylece BMV sistemine uygulanır. Kaynak: Indiana CDL manual (SP 283), Medical Examiner Requirements and Certification, Indiana BMV."},"87":{"q":"Bir Indiana CDL/CLP başvuru sahibi, yapacağı sürüş türünü beyan ederken kaç öz-belgelendirme kategorisi arasından seçim yapmalıdır?","options":["Dört","İki","Üç","Beş"],"explanation":"Başvuru sahipleri dört kategoriden birine öz-belgelendirme yapar: muaf olmayan eyaletler arası (non-excepted interstate), muaf eyaletler arası (excepted interstate), muaf olmayan eyalet içi (non-excepted intrastate) veya muaf eyalet içi (excepted intrastate). Kaynak: 49 CFR 383.71 (Indiana BMV tarafından uygulanır); Indiana BMV öz-belgelendirme."},"88":{"q":"Hangi öz-belgelendirme kategorisi, eyalet sınırları arasında çalışan ve federal tıbbi/fiziksel yeterlilik gerekliliklerini karşılaması gereken bir sürücüyü tanımlar?","options":["Non-excepted interstate (muaf olmayan eyaletler arası)","Excepted interstate (muaf eyaletler arası)","Non-excepted intrastate (muaf olmayan eyalet içi)","Excepted intrastate (muaf eyalet içi)"],"explanation":"Non-excepted interstate sürücüler eyaletler arası ticarette çalışır ve 49 CFR Part 391'in tıbbi gerekliliklerini karşılamalı, dosyada geçerli bir MEC bulundurmalıdır. Kaynak: 49 CFR 383.71 / 391.41 (Indiana BMV tarafından uygulanır)."},"89":{"q":"Indiana kuralları uyarınca, bir başvuru sahibi bir CDL bilgi testine ne sıklıkla girmeyi deneyebilir?","options":["Günde bir kez; başarısız olan bir test bir sonraki iş günü tekrar verilebilir","Geçene kadar günde üç kez","Yalnızca randevuyla, haftada bir kez","Tek bir günde sınırsız sayıda"],"explanation":"El kitabı, bir başvuru sahibinin bir CDL bilgi testine günde yalnızca bir kez girebileceğini ve başarısızlıktan sonra bir sonraki iş günü tekrar girebileceğini belirtir. Kaynak: Indiana CDL manual (SP 283), CDL Knowledge Tests, Indiana BMV."},"90":{"q":"Geçildikten sonra, Indiana CDL bilgi testi sonuçları ve beceri testi sonuçları ne kadar süre geçerlidir?","options":["Bir yıl","Altı ay","İki yıl","90 gün"],"explanation":"El kitabı, CDL bilgi testi sonuçlarının bir yıl ve CDL beceri testi sonuçlarının bir yıl geçerli olduğunu belirtir. Kaynak: Indiana CDL manual (SP 283), CDL Knowledge Tests ve CDL Skills Testing, Indiana BMV."},"91":{"q":"Bir başvuru sahibi Indiana CDL beceri testini nerede vermelidir?","options":["BMV onaylı (üçüncü taraf yetkili) bir CDL beceri testi merkezinde","Herhangi bir tam hizmet BMV belge şubesi gişesinde","Bir INDOT tartı istasyonunda veya giriş noktasında","FMCSA bölge saha ofisinde"],"explanation":"CDL beceri testi BMV onaylı bir CDL beceri testi merkezinde (yetkili üçüncü taraf merkezler) verilmelidir; sonuçlar elektronik olarak BMV'ye iletilir. Kaynak: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV."},"92":{"q":"Eyalet içi ticarette çalışmak için (okul otobüsü veya eyaletler arası değil) bir Indiana CDL/CLP almak için asgari yaş nedir?","options":["18 yaşında","21 yaşında","19 yaşında","16 yaşında"],"explanation":"Bir başvuru sahibi en az 18 yaşında olmalıdır; eyaletler arası ticarette çalışmak veya bir okul otobüsü onayı için başvurmak için başvuru sahibi en az 21 yaşında olmalıdır. Kaynak: Indiana CDL manual (SP 283), CLP requirements, Indiana BMV."},"93":{"q":"Indiana'da CDL beceri testini geçtikten sonra, başvuru sahibinin CDL'yi gerçekten almak için yapması gereken nedir?","options":["CLP'nin süresi dolmadan önce başvuruyu tamamlamak için bir BMV belge şubesine geri dönmek","Belgenin FMCSA'dan posta ile gelmesini beklemek","INDOT'ta ikinci bir yolda test planlamak","Test merkezinde genel bilgi testini yeniden vermek"],"explanation":"El kitabı, beceri testini geçtikten sonra başvuru sahibinin CDL başvurusunu tamamlamak için bir BMV belge şubesine geri dönmesi gerektiğini ve bunu CLP'nin süresi dolmadan önce yapması gerektiğini belirtir. Kaynak: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV."},"94":{"q":"Bir Indiana CDL beceri testi randevusu, test merkeziyle ne kadar önceden planlanmalıdır?","options":["En az iki gün önceden","En az iki hafta önceden","En az bir gün önceden","En az 30 gün önceden"],"explanation":"El kitabı, randevuların en az iki gün önceden planlanması gerektiğini ve beceri testinin bir iş gününde yalnızca bir kez verilebileceğini belirtir. Kaynak: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV."},"95":{"q":"Indiana'da bir CDL üç yıldan fazla süreyle süresi dolmuş, diskalifiye edilmiş, iptal edilmiş, geri alınmış, askıya alınmış veya geçersiz kılınmışsa ne olur?","options":["Başvuru sahibi, ilk kez başvuran biri olarak tüm geçerli bilgi ve beceri testlerini geçmelidir","Başvuru sahibi yalnızca bir görme taramasıyla çevrimiçi yenileyebilir","CDL, yazılı bir testten sonra otomatik olarak yeniden etkinleştirilir","Başvuru sahibinin yalnızca yolda sürüş testini yeniden vermesi gerekir"],"explanation":"El kitabının Retesting Requirement (Yeniden Test Gerekliliği) bölümü, CDL'si üç yıldan fazla süreyle süresi dolmuş, teslim edilmiş, diskalifiye edilmiş, iptal edilmiş, geri alınmış, askıya alınmış veya geçersiz kılınmış herhangi bir başvuru sahibinin, ilk kez başvuran biri olarak tüm geçerli bilgi ve beceri testlerini geçmesi gerektiğini belirtir. Kaynak: Indiana CDL manual (SP 283), Indiana BMV."},"96":{"q":"Geçerli bir eyalet dışı CDL'ye sahip yeni bir sakinin, onu bir Indiana CDL'sine aktarmak için ne kadar süresi vardır?","options":["30 gün","60 gün","90 gün","10 gün"],"explanation":"El kitabı, bireylerin bir eyalet dışı CDL'yi aktarmak için 30 günü olduğunu belirtir; sürücü belgesi bilgi sınavı yalnızca eyalet dışı CDL'nin süresi dolmuşsa gereklidir. Kaynak: Indiana CDL manual (SP 283), Transfer an Out-of-Country or Out-of-State CDL, Indiana BMV."},"97":{"q":"Indiana'da Tehlikeli Maddeler (H) onay süreci hakkında hangi ifade doğrudur?","options":["TSA güvenlik tehdit değerlendirmesi onayı gerektirir ve bir CLP'ye eklenmez","Hava fren testi geçildikten sonra bir CLP'ye eklenebilir","Yalnızca genel bilgi testini geçmeyi gerektirir","Herhangi bir Class A CDL ile otomatik olarak verilir"],"explanation":"El kitabı, bir HazMat onayının CDL'nin süresi boyunca TSA güvenlik tehdit değerlendirmesi onayı gerektirdiğini ve bir CLP'ye eklenmeyeceğini belirtir. Kaynak: Indiana CDL manual (SP 283), CDL Endorsements, Indiana BMV; 49 CFR 1572 (TSA)."},"98":{"q":"Bilgi ve beceri testlerini geçmenin ötesinde, belgelendirme sürecinde her Indiana CDL başvuru sahibinden özellikle istenen adım hangisidir?","options":["İnsan ticaretini tanıma, önleme ve bildirme konusunda eğitici bir video izlemek","Bir eyalet polisiyle 40 saatlik bir refakatli sürüş tamamlamak","Bir INDOT oversize/overweight izin sınavını geçmek","Test öncesinde noter onaylı işveren sponsorluğu almak"],"explanation":"Indiana, CDL başvuru sahiplerinden ELDT'yi tamamlamanın ve gerekli testleri geçmenin yanı sıra, insan ticaretini tanıma, önleme ve bildirme konusunda eğitici bir video izlemelerini ister. Kaynak: Indiana CDL manual (SP 283), application requirements, Indiana BMV."}},"es":{"0":{"q":"En las carreteras de Indiana, ¿cuál es el ancho máximo legal de un vehículo y su carga (excluyendo dispositivos exentos del cálculo de ancho, como los espejos)?","options":["8 feet 0 inches","9 feet 0 inches","8 feet 6 inches","10 feet 0 inches"],"explanation":"Indiana limita el ancho del vehículo y su carga a 8 feet 6 inches (102 inches), excluyendo los dispositivos de seguridad exentos del cálculo de ancho conforme a 23 CFR 658. Fuente: Indiana Code IC 9-20-3-2; Indiana State Police Summary of Indiana Size and Weight Laws (Title 9, Article 20)."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo, incluida su carga, en las carreteras de Indiana?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","12 feet 6 inches"],"explanation":"Indiana fija la altura máxima en 13 feet 6 inches, y no existe ninguna exención a la altura legal. Fuente: IC 9-20-3-3; Indiana State Police Summary of Indiana Size and Weight Laws."},"2":{"q":"¿Cuál es el peso bruto máximo de un vehículo o combinación permitido bajo la ley de Indiana sin un permiso de sobrepeso?","options":["73,280 pounds","80,000 pounds","88,000 pounds","84,000 pounds"],"explanation":"El peso bruto máximo legal de Indiana es de 80,000 pounds; cualquier cosa más pesada requiere un permiso. La cifra de 73,280 pounds aplica únicamente bajo la cláusula de derechos adquiridos (grandfather provision) para ciertas configuraciones. Fuente: IC 9-20-4 (General Weight Restrictions); Indiana State Police Summary of Size and Weight Laws."},"3":{"q":"¿Cuál es el peso máximo que Indiana permite sobre un solo eje?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"El peso máximo de un solo eje en Indiana es de 20,000 pounds. (Las cifras de 18,000 pounds y 16,000 pounds aparecen únicamente en escenarios de la ley de derechos adquiridos.) Fuente: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"4":{"q":"¿Cuál es el peso máximo que Indiana permite sobre un grupo de ejes en tándem?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"El peso máximo de un eje en tándem en Indiana es de 34,000 pounds, lo cual coincide con el estándar federal. Fuente: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"5":{"q":"Indiana limita el peso por rueda a cuánto por pulgada de ancho de neumático, medido entre las pestañas del rin?","options":["600 pounds","1,000 pounds","500 pounds","800 pounds"],"explanation":"Indiana limita el peso por rueda a 800 pounds por pulgada de ancho de neumático medido entre las pestañas del rin, ya sea con carga o sin carga. Fuente: IC 9-20-11-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"6":{"q":"¿Cuál es la longitud máxima de un solo vehículo que circula con su propia potencia en las carreteras de Indiana (excluyendo dispositivos exentos del cálculo de longitud)?","options":["40 feet","45 feet","35 feet","53 feet"],"explanation":"Un solo vehículo automotor no puede exceder los 40 feet, excepto por los dispositivos exentos del cálculo de longitud conforme a 23 CFR 658.13. Un vehículo recreativo puede tener hasta 45 feet. Fuente: IC 9-20-3-1 / IC 9-20-8; Indiana State Police Summary of Size and Weight Laws."},"7":{"q":"En una combinación de camión-tractor y semirremolque, ¿cuál es la longitud máxima del semirremolque (incluida la carga) bajo la ley de Indiana?","options":["48 feet","57 feet","45 feet","53 feet"],"explanation":"Indiana permite un semirremolque de hasta 53 feet en una combinación de camión-tractor, y no se impone ningún límite de longitud total a esa combinación. Fuente: IC 9-20-8; Indiana State Police Summary of Size and Weight Laws."},"8":{"q":"¿Qué agencia de Indiana emite los permisos de sobredimensión y sobrepeso (OSOW) para vehículos que exceden los límites legales de tamaño y peso?","options":["Indiana Bureau of Motor Vehicles","Indiana Department of Revenue, Motor Carrier Services","Indiana State Police","Indiana Department of Natural Resources"],"explanation":"Los permisos OSOW son emitidos por Motor Carrier Services del Indiana Department of Revenue, bajo las reglas establecidas por INDOT y la ley de Indiana. Fuente: IC 9-20-6; Indiana DOR Motor Carrier Services OSOW program (in.gov/dor)."},"9":{"q":"¿En qué año adoptó Indiana la Bridge Formula federal a su ley estatal para calcular los pesos brutos y por eje máximos legales?","options":["1975","1956","1982","1991"],"explanation":"Indiana adoptó la Bridge Formula como ley estatal en 1975, y conserva una cláusula de derechos adquiridos para los límites de peso vigentes el 4 de enero de 1975. Fuente: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"10":{"q":"Bajo la adopción por parte de Indiana de la Bridge Formula federal W = 500{[(LN) / (N-1)] + 12N + 36}, ¿qué representa la variable 'N'?","options":["El peso neto de la carga en el vehículo","La longitud total de la combinación en pies","El número de neumáticos en el eje motriz","El número de ejes en el grupo bajo consideración"],"explanation":"En la Bridge Formula, N es el número de ejes en el grupo, L es la distancia entre los ejes extremos del grupo, y W es el peso bruto permitido sobre ese grupo. Fuente: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws."},"11":{"q":"La Bridge Formula de Indiana permite que dos conjuntos consecutivos de ejes en tándem carguen cada uno 34,000 pounds, siempre que el primer y el último eje de esos tándems estén separados por una distancia de al menos cuánto?","options":["30 feet","40 feet","36 feet","51 feet"],"explanation":"Dos conjuntos consecutivos de ejes en tándem pueden cargar cada uno hasta 34,000 pounds si el primer y el último eje de los conjuntos están separados por al menos 36 feet. Fuente: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws."},"12":{"q":"Una combinación de dos vehículos acoplados, incluida la carga, generalmente no puede exceder qué longitud total en las carreteras de Indiana?","options":["65 feet","55 feet","75 feet","60 feet"],"explanation":"Una combinación de dos vehículos acoplados, incluida la carga, no puede exceder los 60 feet (con excepciones limitadas, como los transportadores de botes/vehículos y el servicio de traslado por manejo). Fuente: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws."},"13":{"q":"Una combinación de tres o más vehículos acoplados, incluida la carga, no puede exceder qué longitud total bajo la ley de Indiana?","options":["60 feet","70 feet","65 feet","75 feet"],"explanation":"Indiana limita una combinación de tres o más vehículos acoplados, incluida la carga, a 65 feet. Fuente: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws."},"14":{"q":"Indiana otorga una tolerancia del 10% en el peso bruto para un vehículo que transporta productos agrícolas desde el lugar de producción hasta el primer punto de entrega, EXCEPTO en cuál situación?","options":["Cuando el vehículo circula por cualquier parte del sistema interestatal","Cuando la carga se transporta de noche","Cuando el vehículo tiene más de cinco ejes","Cuando el viaje excede las 50 millas"],"explanation":"La tolerancia del 10% en el peso bruto para productos agrícolas no aplica en ninguna parte del sistema interestatal, ni donde rijan los límites señalizados de puentes/carreteras bajo IC 9-20-1-4. Fuente: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"15":{"q":"Si a un vehículo de combinación se le permite un peso bruto de 80,000 pounds, ¿cuál es su peso bruto máximo al transportar productos agrícolas que califican bajo la tolerancia del 10% de Indiana?","options":["84,000 pounds","90,000 pounds","88,000 pounds","86,000 pounds"],"explanation":"Indiana añade un 10% al peso bruto permitido para los transportes de productos agrícolas que califican, por lo que 80,000 pounds se convierten en 88,000 pounds (solo en rutas fuera del interestatal y no señalizadas). Fuente: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"16":{"q":"Indiana trata ciertos productos forestales como productos agrícolas para la tolerancia de peso del 10%. ¿Para cuáles de estos aplica la tolerancia del 10% EN TODO momento para el peso bruto y por eje?","options":["Madera terminada y contrachapado","Astillas de madera, corteza y aserrín","Muebles y ebanistería","Papel y cartón"],"explanation":"Los productos agrícolas incluyen troncos, astillas de madera, corteza, aserrín y leche a granel; para las astillas de madera, la corteza y el aserrín, la tolerancia del 10% aplica en todo momento al peso bruto y por eje. Fuente: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"17":{"q":"Bajo la cláusula de derechos adquiridos de Indiana que conserva los límites de peso vigentes el 4 de enero de 1975, ¿cuál es el peso bruto máximo para las configuraciones de vehículos afectadas?","options":["80,000 pounds","70,000 pounds","64,000 pounds","73,280 pounds"],"explanation":"La ley de derechos adquiridos de Indiana preserva un peso bruto máximo de 73,280 pounds para las configuraciones que de otro modo serían penalizadas por la Bridge Formula. Fuente: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"18":{"q":"Excepto en las carreteras interestatales, ¿cuál es el peso máximo por eje sencillo permitido para un vehículo municipal de recolección de basura/desechos que califica en Indiana?","options":["20,000 pounds","24,000 pounds","22,400 pounds","26,000 pounds"],"explanation":"Excepto en el sistema interestatal, los vehículos de recolección de desechos que califican pueden cargar hasta 24,000 pounds sobre un solo eje y 42,000 pounds sobre un eje en tándem, pero siguen sujetos a los límites de peso por rueda bajo IC 9-20-11-4. Fuente: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws."},"19":{"q":"En Indiana, ¿qué clase de CDL se requiere para operar una combinación de vehículos con una Gross Combination Weight Rating (GCWR) de 26,001 pounds o más, donde el o los vehículos remolcados tienen un GVWR superior a 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Indiana define una CDL Class A como cualquier combinación de vehículos con una GCWR de 26,001 lbs o más, siempre que el GVWR de la unidad o unidades remolcadas exceda los 10,000 lbs. Fuente: Indiana CDL Manual (Indiana BMV); 49 CFR 383.91 según lo adoptado por Indiana."},"20":{"q":"Bajo las reglas de Indiana, un solo vehículo con un GVWR de 26,001 pounds o más (o ese tipo de vehículo remolcando una unidad que no exceda los 10,000 pounds de GVWR) requiere qué clase de CDL?","options":["Class C","Class B","Class A","Chauffeur license"],"explanation":"Indiana define una CDL Class B como cualquier vehículo sencillo con un GVWR de 26,001 lbs o más, o ese tipo de vehículo remolcando una unidad que no exceda los 10,000 lbs de GVWR. Fuente: Indiana CDL Manual (Indiana BMV)."},"21":{"q":"En Indiana, un vehículo que no alcanza los umbrales de peso de Class A o Class B pero que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que transporta materiales peligrosos con cartel (placarded) requiere qué clase de CDL?","options":["Class A","Class B","Class C","No se requiere CDL"],"explanation":"Una CDL Class C en Indiana cubre los vehículos por debajo de los límites de peso de Class A/B que están diseñados para transportar 16 o más pasajeros (incluido el conductor) o que transportan materiales peligrosos que requieren cartel (placarding). Fuente: Indiana CDL Manual (Indiana BMV)."},"22":{"q":"¿Cuál es la edad mínima para obtener una CDL de Indiana restringida únicamente a la conducción intraestatal (dentro de Indiana)?","options":["16 años","17 años","18 años","21 años"],"explanation":"Indiana exige que los solicitantes tengan al menos 18 años para poseer una CDL o CLP para operación intraestatal; los conductores de 18 a 20 años están limitados a operar vehículos comerciales dentro de Indiana. Fuente: Indiana CDL Manual (Indiana BMV); IC 9-24."},"23":{"q":"¿Cuál es la edad mínima para conducir un vehículo motor comercial en comercio interestatal (cruzando líneas estatales) con una CDL de Indiana?","options":["18 años","19 años","20 años","21 años"],"explanation":"Un conductor debe tener al menos 21 años para operar un vehículo motor comercial de forma interestatal, para transportar materiales peligrosos o para llevar pasajeros cruzando líneas estatales. Los conductores de 18 a 20 años están restringidos a la conducción intraestatal en Indiana. Fuente: Indiana CDL Manual (Indiana BMV); 49 CFR 391.11."},"24":{"q":"¿Qué endoso exige Indiana para conducir un vehículo cisterna que transporta un líquido o gas en un tanque individual de más de 119 gallons (con un agregado de 1,000+ gallons)?","options":["Endoso N","Endoso T","Endoso H","Endoso P"],"explanation":"El endoso N (Tank Vehicle) de Indiana se requiere para vehículos diseñados para transportar líquidos o gases en un tanque con una capacidad nominal individual de más de 119 gallons y una capacidad agregada de 1,000 gallons o más. Fuente: Indiana BMV CDL Endorsements and Restrictions."},"25":{"q":"¿Qué endoso de CDL de Indiana se requiere para operar un vehículo que arrastra dos o tres remolques separados (doubles/triples)?","options":["Endoso N","Endoso P","Endoso T","Endoso S"],"explanation":"El endoso T autoriza la operación de una combinación con dos o tres remolques separados acoplados (doubles/triples). Se obtiene al aprobar el examen de conocimientos de doubles/triples. Fuente: Indiana BMV CDL Endorsements and Restrictions."},"26":{"q":"¿Qué endoso de CDL de Indiana se requiere para conducir un vehículo diseñado para transportar 16 o más pasajeros, incluido el conductor?","options":["Endoso S","Endoso P","Endoso N","Endoso H"],"explanation":"El endoso P (Passenger) se requiere para operar un vehículo diseñado para transportar 16 o más pasajeros, incluido el conductor. Requiere un examen de conocimientos, un examen de habilidades en un vehículo representativo y ELDT para los solicitantes que lo obtienen por primera vez. Fuente: Indiana BMV CDL Endorsements and Restrictions."},"27":{"q":"En Indiana, ¿qué evaluación federal adicional debe completar un solicitante para obtener el endoso H (Hazardous Materials)?","options":["Una evaluación de amenaza a la seguridad de la TSA que incluye toma de huellas dactilares","Un examen de polígrafo del FBI","Una verificación de antecedentes penales solo estatal sin huellas dactilares","Una entrevista de sustancias controladas de la DEA"],"explanation":"Agregar el endoso H requiere aprobar el examen de conocimientos de HazMat y completar una evaluación de amenaza a la seguridad de la TSA, que incluye la toma de huellas dactilares y la verificación del estatus legal. Fuente: Indiana BMV CDL Endorsements and Restrictions; 49 CFR 1572 (TSA)."},"28":{"q":"¿Con qué frecuencia debe un titular de CDL de Indiana renovar la evaluación de amenaza a la seguridad de la TSA para mantener el endoso de Hazardous Materials (H)?","options":["Cada año","Cada 2 años","Cada 5 años","Cada 10 años"],"explanation":"La evaluación de amenaza a la seguridad de la TSA para el endoso de HazMat es válida por cinco años y debe renovarse (con un nuevo examen de conocimientos de HazMat) al menos cada cinco años. Fuente: Indiana BMV CDL Endorsements and Restrictions; TSA HazMat Endorsement program."},"29":{"q":"¿Qué código de endoso combinado emite Indiana cuando un conductor posee tanto el endoso de Hazardous Materials como el de Tank Vehicle?","options":["Endoso X","Endoso HN","Endoso Z","Endoso W"],"explanation":"Indiana emite el endoso X para representar la combinación de los privilegios H (HazMat) y N (Tank Vehicle). Fuente: Indiana BMV CDL Endorsements and Restrictions."},"30":{"q":"Antes de tomar el examen de habilidades de la CDL en Indiana, ¿durante cuánto tiempo debe un solicitante poseer un Commercial Learner's Permit (CLP) válido?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 60 días"],"explanation":"Un solicitante debe poseer el CLP durante al menos 14 días antes de intentar el examen de habilidades de la CDL. Este es el mínimo federal adoptado por Indiana. Fuente: Indiana CDL Manual / Indiana BMV; 49 CFR 383.25."},"31":{"q":"Según el Indiana BMV, ¿por cuánto tiempo es válido un Commercial Learner's Permit (CLP) después de ser emitido?","options":["30 días","90 días","Un año","Cinco años"],"explanation":"El Indiana BMV establece que un CLP es válido por un año, y los resultados del examen de conocimientos de la CDL también son válidos por un año. Fuente: Indiana BMV, Obtaining a Commercial Learner's Permit."},"32":{"q":"¿Qué restricción aplica a un titular de CLP de Indiana mientras opera un vehículo motor comercial?","options":["Puede conducir solo únicamente en carreteras interestatales","Debe estar acompañado por un titular de CDL con la clase y los endosos correctos","Solo puede conducir entre el amanecer y el atardecer","Solo puede operar vehículos por debajo de 26,001 pounds de GVWR"],"explanation":"Un titular de CLP puede operar un vehículo motor comercial únicamente cuando está acompañado por una persona que posea una CDL válida con la clase y los endosos correctos, quien debe estar sentada junto al titular del CLP. Fuente: Indiana BMV, Obtaining a Commercial Learner's Permit; 49 CFR 383.25."},"33":{"q":"Al solicitar una CDL o CLP de Indiana, ¿cuántos documentos debe presentar un solicitante para comprobar su residencia en Indiana?","options":["Un documento","Dos documentos","Tres documentos","No se requiere comprobante de residencia"],"explanation":"Indiana requiere dos documentos que comprueben la residencia en Indiana, además de uno que compruebe la identidad, uno que compruebe el estatus legal y uno que compruebe el número completo del Seguro Social. Fuente: Indiana BMV document requirements."},"34":{"q":"Además del comprobante de identidad y de residencia en Indiana, ¿qué dos elementos debe documentar un solicitante de CDL de Indiana?","options":["Estatus legal en los EE. UU. y número completo del Seguro Social","Un diploma de preparatoria y el título del vehículo","Una carta de un especialista en visión y una declaración jurada del empleador","Registro electoral y un recibo de depósito de servicios públicos"],"explanation":"Indiana requiere un documento que compruebe el estatus legal (presencia legal) en los EE. UU. y un documento que compruebe el número completo del Seguro Social del solicitante, además de la identidad y los dos documentos de residencia. Fuente: Indiana BMV document requirements."},"35":{"q":"A partir del 7 de febrero de 2022, ¿en qué situación deben completar el Entry-Level Driver Training (ELDT) los solicitantes de Indiana?","options":["Renovar una CDL Class A existente sin cambio de clase","Obtener una primera CDL Class A o Class B, o un primer endoso H, P o S","Agregar únicamente el endoso T (doubles/triples)","Autocertificarse como intraestatal exento (excepted intrastate)"],"explanation":"El ELDT aplica a los conductores que obtienen una primera CDL Class A o Class B, que ascienden a una clase superior, o que obtienen un endoso de Hazardous Materials (H), Passenger (P) o School Bus (S) por primera vez a partir del 7 de febrero de 2022. Fuente: FMCSA ELDT rule; Indiana BMV."},"36":{"q":"¿Dónde debe completar un solicitante de Indiana el Entry-Level Driver Training (ELDT) requerido?","options":["En cualquier escuela de manejo privada que el solicitante elija","Con un proveedor incluido en el FMCSA Training Provider Registry","En un centro de pruebas de una sucursal del Indiana BMV","Mediante un curso en línea aprobado por la TSA"],"explanation":"La capacitación teórica y práctica al volante del ELDT debe ser impartida por una entidad incluida en el FMCSA Training Provider Registry (TPR); solo los proveedores incluidos pueden reportar la finalización. Fuente: FMCSA Training Provider Registry; Indiana BMV."},"37":{"q":"¿Qué categoría de autocertificación médica elige un titular de CDL de Indiana si opera únicamente dentro de Indiana y debe cumplir con los requisitos estatales de calificación del conductor con un certificado de examinador médico?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Non-Excepted Intrastate (NA) aplica a los conductores que operan únicamente en comercio intraestatal (dentro de Indiana) que deben cumplir con las reglas de calificación del conductor de Indiana y presentar un certificado de examinador médico. Fuente: Indiana BMV CDL self-certification; 49 CFR 383.71."},"38":{"q":"¿Qué categoría de autocertificación requiere que un titular de CDL de Indiana mantenga un DOT Medical Examiner's Certificate federal válido de un proveedor incluido en el FMCSA National Registry?","options":["Excepted Intrastate (EA)","Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Restricted Agricultural (RA)"],"explanation":"Un conductor que se autocertifica como Non-Excepted Interstate (NI) opera cruzando líneas estatales en comercio no exento y debe poseer y mantener un Medical Examiner's Certificate válido emitido por un examinador certificado incluido en el FMCSA National Registry. Fuente: Indiana BMV CDL self-certification; 49 CFR 391.41."},"39":{"q":"En Indiana, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que es legal operar un vehículo motor comercial (CMV)?","options":["Por debajo de 0.04%","Por debajo de 0.08%","Por debajo de 0.02%","Por debajo de 0.10%"],"explanation":"El Indiana BMV CDL Manual (Section 1.3.2) establece que es ilegal operar un CMV si su concentración de alcohol en la sangre es de .04% o más, por lo que un conductor de CMV debe mantenerse por debajo de 0.04% (la mitad del límite de 0.08% para conductores no comerciales). Fuente: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2."},"40":{"q":"Bajo la regla de consentimiento implícito (implied-consent) de Indiana, ¿a qué ha aceptado un conductor al operar un CMV?","options":["A someterse a pruebas de alcohol","A renunciar al derecho a un abogado","A una inspección del vehículo en cualquier momento","A un programa obligatorio de tratamiento de drogas"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.2) establece que si usted opera un CMV, se considerará que ha dado su consentimiento para someterse a pruebas de alcohol. Fuente: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2; IC 9-30-6."},"41":{"q":"Por una primera infracción mayor, como conducir un CMV con un BAC de 0.04% o más, ¿por cuánto tiempo perderá su CDL un titular en Indiana?","options":["Al menos 1 año","Al menos 6 meses","Al menos 90 días","Al menos 3 años"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.2) establece que perderá su CDL durante al menos un año por una primera infracción mayor, incluido conducir un CMV con un BAC de .04% o más. Fuente: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51)."},"42":{"q":"Si una primera infracción mayor ocurre mientras el conductor opera un CMV con cartel (placarded) para materiales peligrosos, ¿cuál es la descalificación mínima en Indiana?","options":["Al menos 3 años","Al menos 1 año","Al menos 5 años","De por vida"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.2) establece que perderá su CDL durante al menos tres años si una primera infracción mayor ocurre mientras opera un CMV con cartel (placarded) para materiales peligrosos. Fuente: Indiana BMV CDL Manual, Sec. 1.3.2."},"43":{"q":"¿Cuál es la consecuencia de una segunda infracción mayor (como un segundo DWI en un CMV) bajo las reglas de CDL de Indiana?","options":["Pérdida de la CDL de por vida","Pérdida de la CDL por 10 años","Pérdida de la CDL por 3 años","Pérdida de la CDL por 5 años"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.2) establece que perderá su CDL de por vida por una segunda infracción mayor. Fuente: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51)."},"44":{"q":"¿Cuál de las siguientes se trata como una primera infracción mayor que le cuesta a un titular de CDL de Indiana su licencia durante al menos un año?","options":["Negarse a someterse a una prueba de alcohol en la sangre","Seguir a un vehículo demasiado de cerca","Conducir 16 mph por encima del límite señalizado","Un cambio de carril indebido"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.2) enumera negarse a someterse a una prueba de alcohol en la sangre como una infracción mayor que conlleva una descalificación de al menos un año; las otras opciones son infracciones de tránsito graves, no infracciones mayores. Fuente: Indiana BMV CDL Manual, Sec. 1.3.2."},"45":{"q":"En Indiana, ¿qué le sucede a un titular de CDL que usa un CMV para cometer un delito grave (felony) que involucra sustancias controladas?","options":["Pérdida de la CDL de por vida","Pérdida de la CDL por 3 años","Pérdida de la CDL por 1 año","Pérdida de la CDL por 5 años"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.2) establece que perderá su CDL de por vida si usa un CMV para cometer un delito grave (felony) que involucra sustancias controladas. Fuente: Indiana BMV CDL Manual, Sec. 1.3.2."},"46":{"q":"Se determina que un conductor de CMV en Indiana tiene una cantidad detectable de alcohol por debajo de 0.04%. ¿Cuál es la consecuencia inmediata?","options":["Puesto fuera de servicio (out-of-service) por 24 horas","CDL descalificada por 60 días","Una multa civil de $2,750","CDL descalificada por 1 año"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.2) establece que será puesto fuera de servicio (out-of-service) por 24 horas si tiene cualquier cantidad detectable de alcohol por debajo de .04%. Fuente: Indiana BMV CDL Manual, Sec. 1.3.2."},"47":{"q":"¿Cómo define el Indiana CDL Manual el 'exceso de velocidad' (excessive speeding) como una infracción de tránsito grave?","options":["15 mph o más por encima del límite señalizado","10 mph o más por encima del límite señalizado","20 mph o más por encima del límite señalizado","25 mph o más por encima del límite señalizado"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.3) define el exceso de velocidad como 15 mph o más por encima del límite señalizado. Fuente: Indiana BMV CDL Manual, Sec. 1.3.3."},"48":{"q":"Por dos infracciones de tránsito graves en un CMV dentro de un período de tres años, ¿por cuánto tiempo perderá su CDL un titular en Indiana?","options":["Al menos 60 días","Al menos 30 días","Al menos 90 días","Al menos 120 días"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.3) establece que perderá su CDL durante al menos 60 días por dos infracciones de tránsito graves dentro de un período de tres años que involucren un CMV. Fuente: Indiana BMV CDL Manual, Sec. 1.3.3."},"49":{"q":"Por tres o más infracciones de tránsito graves en un CMV dentro de un período de tres años, ¿cuál es la descalificación en Indiana?","options":["Al menos 120 días","Al menos 60 días","Al menos 90 días","Al menos 1 año"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.3) establece que perderá su CDL durante al menos 120 días por tres o más infracciones de tránsito graves dentro de un período de tres años que involucren un CMV. Fuente: Indiana BMV CDL Manual, Sec. 1.3.3."},"50":{"q":"¿Cuál de las siguientes figura como una infracción de tránsito grave en el Indiana CDL Manual?","options":["Conducción imprudente (reckless driving)","Conducir un CMV con un BAC de 0.04%","Abandonar la escena de un accidente con un CMV","Negarse a una prueba de alcohol en la sangre"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.3) enumera la conducción imprudente (reckless driving) entre las infracciones de tránsito graves; las otras tres son infracciones mayores bajo la Sec. 1.3.2. Fuente: Indiana BMV CDL Manual, Sec. 1.3.3."},"51":{"q":"¿Cuál es la descalificación mínima por una primera violación de una orden de fuera de servicio (out-of-service) en Indiana?","options":["Al menos 90 días","Al menos 60 días","Al menos 30 días","Al menos 180 días"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.4) establece que perderá su CDL durante al menos 90 días por su primera violación de una orden de fuera de servicio. Fuente: Indiana BMV CDL Manual, Sec. 1.3.4."},"52":{"q":"¿Cuál es la descalificación mínima por dos violaciones de órdenes de fuera de servicio dentro de un período de diez años en Indiana?","options":["Al menos 1 año","Al menos 90 días","Al menos 6 meses","Al menos 3 años"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.4) establece que perderá su CDL durante al menos un año por dos violaciones de una orden de fuera de servicio en un período de diez años. Fuente: Indiana BMV CDL Manual, Sec. 1.3.4."},"53":{"q":"Tres o más violaciones de órdenes de fuera de servicio dentro de un período de diez años resultan en qué descalificación mínima en Indiana?","options":["Al menos 3 años","Al menos 1 año","Al menos 5 años","De por vida"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.4) establece que perderá su CDL durante al menos tres años por tres o más violaciones de una orden de fuera de servicio en un período de diez años. Fuente: Indiana BMV CDL Manual, Sec. 1.3.4."},"54":{"q":"¿Cuál es la descalificación mínima por una primera infracción en un cruce a nivel entre ferrocarril y carretera (railroad-highway grade crossing) en Indiana?","options":["Al menos 60 días","Al menos 30 días","Al menos 90 días","Al menos 120 días"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.5) establece que perderá su CDL durante al menos 60 días por su primera infracción en un cruce a nivel entre ferrocarril y carretera. Fuente: Indiana BMV CDL Manual, Sec. 1.3.5."},"55":{"q":"Una segunda infracción en un cruce a nivel entre ferrocarril y carretera dentro de un período de tres años conlleva qué descalificación mínima en Indiana?","options":["Al menos 120 días","Al menos 60 días","Al menos 90 días","Al menos 1 año"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.5) establece que perderá su CDL durante al menos 120 días por una segunda infracción en un cruce a nivel entre ferrocarril y carretera dentro de un período de tres años. Fuente: Indiana BMV CDL Manual, Sec. 1.3.5."},"56":{"q":"Una tercera infracción en un cruce a nivel entre ferrocarril y carretera dentro de un período de tres años conlleva qué descalificación mínima en Indiana?","options":["Al menos 1 año","Al menos 120 días","Al menos 6 meses","Al menos 3 años"],"explanation":"El Indiana BMV CDL Manual (Sec. 1.3.5) establece que perderá su CDL durante al menos un año por una tercera infracción en un cruce a nivel entre ferrocarril y carretera dentro de un período de tres años. Fuente: Indiana BMV CDL Manual, Sec. 1.3.5."},"57":{"q":"Bajo las reglas de Indiana, ¿después de cuántas condenas por una ley estatal que prohíbe enviar mensajes de texto mientras se conduce un CMV se descalifica una CDL, y por cuánto tiempo en la segunda infracción?","options":["Dos o más condenas; 60 días por la segunda infracción dentro de 3 años","Una condena; 120 días de inmediato","Dos condenas; 1 año por la segunda infracción","Tres condenas; 30 días por la tercera infracción"],"explanation":"El Indiana BMV CDL Manual (Sec. 2.9.5) establece que su CDL será descalificada después de dos o más condenas por cualquier ley estatal sobre mensajes de texto mientras se opera un CMV, con una descalificación de 60 días por la segunda infracción dentro de 3 años (120 días por tres o más dentro de 3 años). Fuente: Indiana BMV CDL Manual, Sec. 2.9.5."},"58":{"q":"Según el Indiana CDL Manual, un conductor de CMV que viola la restricción de teléfono móvil de mano o de mensajes de texto está sujeto a una multa civil de hasta qué monto?","options":["$2,750","$1,000","$5,000","$11,000"],"explanation":"El Indiana BMV CDL Manual (Secs. 2.9.4-2.9.5) establece que cada violación de la prohibición de teléfono de mano o mensajes de texto sujeta al conductor a una multa civil de hasta $2,750; los empleadores pueden estar sujetos a multas de hasta $11,000. Fuente: Indiana BMV CDL Manual, Secs. 2.9.4 y 2.9.5."},"59":{"q":"En una autopista interestatal rural de Indiana (fuera de una zona urbanizada), ¿cuál es el límite máximo de velocidad para un tractocamión cargado con un peso bruto declarado mayor a 26,000 libras?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Conforme al IC 9-21-5-2, un vehículo distinto de un autobús con un peso bruto declarado mayor a 26,000 libras está limitado a 65 mph en las autopistas interestatales rurales, mientras que los automóviles de pasajeros pueden circular a 70 mph. Esta es la base de las señales de velocidad diferenciada (camión vs. automóvil) de Indiana en las interestatales."},"60":{"q":"Un automóvil de pasajeros puede circular a 70 mph en una autopista interestatal rural de Indiana. En el mismo lugar, un autobús chárter que transporta pasajeros puede legalmente viajar hasta:","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"El IC 9-21-5-2 aplica el límite de 65 mph para camiones a los vehículos 'distintos de un autobús' que superan las 26,000 libras. Los autobuses no están sujetos al límite reducido de los camiones, por lo que un autobús puede viajar a las 70 mph señalizadas en las interestatales rurales. Fuente: Indiana Code 9-21-5-2."},"61":{"q":"Está conduciendo un camión cisterna con placas de materiales peligrosos en una carretera de Indiana. En un cruce a nivel de ferrocarril donde es obligatorio detenerse, debe parar:","options":["A no menos de 15 pies y no más de 50 pies del riel más cercano","A no menos de 10 pies y no más de 25 pies del riel más cercano","Exactamente a 50 pies del riel más cercano","A no menos de 50 pies y no más de 100 pies del riel más cercano"],"explanation":"El Manual CDL de Indiana (Sección 9.6.12) exige que los vehículos con placas, los transportistas de cloro y los vehículos cisterna se detengan de 15 a 50 pies del riel más cercano y luego avancen solo cuando estén seguros de que no viene ningún tren. Fuente: Manual CDL de Indiana."},"62":{"q":"La ley de Indiana 'Move Over' (IC 9-21-8-35) exige que cambie de carril para alejarse de un vehículo de emergencia o averiado que esté detenido con luces intermitentes. Si no puede cambiar de carril de forma segura, debe:","options":["Reducir su velocidad a 10 mph por debajo del límite de velocidad señalizado","Detenerse por completo hasta que sea seguro continuar","Tocar la bocina y mantener la velocidad señalizada","Reducir su velocidad a 20 mph por debajo del límite de velocidad señalizado"],"explanation":"Conforme al IC 9-21-8-35, cuando cambiar de carril no es posible o no es seguro, el conductor debe reducir la velocidad a al menos 10 mph por debajo del límite señalizado mientras pasa. INDOT lo promueve como 'Move Over or Slow Down' (Cámbiese de carril o reduzca la velocidad). Fuente: IC 9-21-8-35; INDOT."},"63":{"q":"En una autopista interestatal de Indiana con dos carriles en su sentido de circulación, un tractocamión generalmente está restringido a qué carril, salvo al rebasar, entrar/salir o evitar un peligro especial?","options":["Cualquier carril, libremente","El carril izquierdo (de rebase)","El carril del extremo derecho","El centro de la calzada"],"explanation":"El IC 9-21-8-12 prohíbe operar un camión o tractocamión en una autopista interestatal en cualquier carril que no sea el del extremo derecho, salvo al rebasar a un vehículo más lento, al entrar o salir de la autopista, o donde un peligro especial requiera otro carril. Fuente: Indiana Code 9-21-8-12."},"64":{"q":"En una autopista interestatal de Indiana con tres o más carriles en su sentido de circulación, un tractocamión está restringido a:","options":["Únicamente el carril del extremo derecho","Únicamente los dos carriles de la derecha","Cualquier carril excepto el del extremo izquierdo","Únicamente el carril central"],"explanation":"El IC 9-21-8-13 limita a los camiones en interestatales con al menos tres carriles en un sentido a los dos carriles del extremo derecho, salvo al entrar o salir de la autopista o evitar un peligro especial. Esto es más permisivo que la regla de un solo carril para los tramos de dos carriles. Fuente: Indiana Code 9-21-8-13."},"65":{"q":"En Indiana, un conductor que se encuentra de frente o que alcanza a un autobús escolar detenido que muestra su brazo de alto extendido y luces rojas intermitentes debe detenerse y permanecer detenido hasta que:","options":["El conductor del autobús le haga señas para que avance","Hayan pasado cinco segundos","El brazo de alto se retraiga y las luces rojas dejen de parpadear","Haya contado hasta diez"],"explanation":"Conforme al IC 9-21-12-1, el conductor debe detenerse antes de llegar al autobús cuando el dispositivo de señal de brazo está extendido y no puede continuar hasta que el dispositivo ya no esté extendido (las luces dejen de parpadear). La infracción es una infracción Clase A. Fuente: Indiana Code 9-21-12-1."},"66":{"q":"Se dirige hacia un autobús escolar detenido (luces rojas intermitentes) que está del OTRO lado de una vía de cuatro carriles. Según la ley de autobuses escolares de Indiana, NO tiene que detenerse únicamente si las dos calzadas están separadas por:","options":["Una línea central pintada o un carril central de giro a la izquierda en ambos sentidos","Cualquier cantidad de cuatro o más carriles de pavimento","Una mediana pintada al ras de al menos 4 pies de ancho","Una barrera física o una mediana sin pavimentar/divisoria no destinada a la circulación"],"explanation":"El IC 9-21-12-3 exime de detenerse a un conductor que se aproxima únicamente cuando las calzadas están divididas por un espacio intermedio sin pavimentar, una barrera física o una sección divisoria construida para impedir el tránsito, y el autobús está del lado opuesto. Una simple línea pintada NO califica: aun así debe detenerse. Fuente: Indiana Code 9-21-12-3."},"67":{"q":"Si debe detener su CMV en el acotamiento de una carretera dividida de Indiana, ¿en cuánto tiempo debe colocar sus dispositivos de advertencia de emergencia?","options":["Dentro de los 2 minutos","Dentro de los 5 minutos","Dentro de los 10 minutos","De inmediato, antes de salir de la cabina"],"explanation":"El Manual CDL de Indiana (Sección 2.5) establece que si se detiene en una vía o en el acotamiento, debe colocar los dispositivos de advertencia de emergencia dentro de los 10 minutos. Fuente: Manual CDL de Indiana."},"68":{"q":"Cuando está detenido en una carretera de un solo sentido o dividida de Indiana, ¿dónde coloca sus tres triángulos de advertencia?","options":["A 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima","A 10 pies, 50 pies y 100 pies hacia el tránsito que se aproxima","A 100 pies adelante, 100 pies atrás y junto al vehículo","Solo junto al vehículo, con las luces intermitentes de cuatro vías encendidas"],"explanation":"El Manual CDL de Indiana indica que en una carretera de un solo sentido o dividida, los dispositivos de advertencia se colocan a 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima. Fuente: Manual CDL de Indiana, Sección 2.5."},"69":{"q":"Cuando está detenido en una carretera de dos carriles de Indiana que lleva tránsito en ambos sentidos, sus triángulos de advertencia deben colocarse:","options":["A 10 pies, 100 pies y 200 pies únicamente detrás del vehículo","A 50 pies adelante y 50 pies atrás únicamente","A 200 pies adelante y 200 pies atrás únicamente","A 10 pies del vehículo, y a 100 pies adelante y 100 pies atrás"],"explanation":"En una carretera no dividida de doble sentido, el Manual CDL de Indiana exige un triángulo a 10 pies de la esquina delantera o trasera para señalizar el vehículo, más uno a 100 pies adelante y otro a 100 pies atrás, en el acotamiento o en el carril. Fuente: Manual CDL de Indiana, Sección 2.5."},"70":{"q":"Un autobús escolar que conduce en Indiana se aproxima a un cruce a nivel de ferrocarril. Debe detener su autobús:","options":["Entre 15 y 50 pies antes del cruce","A no menos de 5 pies del riel","Exactamente a 25 pies del riel","Solo si hay un tren visible"],"explanation":"El Manual CDL de Indiana (Sección 4.3.5) indica a los conductores de autobús detener el autobús entre 15 y 50 pies antes de los cruces de ferrocarril, y luego mirar y escuchar en ambas direcciones antes de continuar. Fuente: Manual CDL de Indiana."},"71":{"q":"Según la ley 'Move Over' reformada de Indiana, un conductor que no se cambia de carril ni reduce la velocidad ante un vehículo detenido con luces intermitentes (sin que resulte lesión) comete una:","options":["Infracción Clase A","Infracción Clase B","Infracción Clase C","Delito grave Clase D"],"explanation":"Una violación básica del IC 9-21-8-35 es una infracción Clase B; se eleva a delito grave solo si la falta causa lesión corporal grave o la muerte a un trabajador cubierto. Fuente: IC 9-21-8-35; INDOT."},"72":{"q":"Sin un permiso de carga sobredimensionada del Departamento de Hacienda de Indiana/INDOT, el ANCHO máximo legal para una carga comercial en las carreteras de Indiana es:","options":["8 pies 0 pulgadas","8 pies 6 pulgadas","10 pies 0 pulgadas","9 pies 0 pulgadas"],"explanation":"El ancho máximo legal (sin permiso) de Indiana es 8 pies 6 pulgadas (102 pulgadas). Las cargas que superen esto requieren un permiso de sobredimensión/sobrepeso a través de Indiana DOR Motor Carrier Services. Fuente: INDOT / regulaciones OSOW de Indiana DOR."},"73":{"q":"Sin un permiso de carga sobredimensionada en Indiana, la ALTURA máxima legal para un vehículo y su carga es:","options":["13 pies 0 pulgadas","13 pies 6 pulgadas","14 pies 0 pulgadas","12 pies 6 pulgadas"],"explanation":"La altura máxima legal de Indiana es 13 pies 6 pulgadas; cualquier cosa más alta necesita un permiso de carga sobredimensionada. Los conductores aún deben verificar los gálibos, ya que las alturas señalizadas de los puentes prevalecen. Fuente: INDOT / regulaciones OSOW de Indiana DOR."},"74":{"q":"Sin un permiso de sobrepeso, el peso bruto vehicular máximo legal para una unidad estándar en las carreteras de Indiana es:","options":["73,280 libras","90,000 libras","100,000 libras","80,000 libras"],"explanation":"El peso bruto vehicular máximo legal de Indiana es 80,000 libras (en concordancia con el límite federal interestatal). Las cargas más pesadas requieren un permiso de sobrepeso de Indiana DOR Motor Carrier Services. Fuente: INDOT / regulaciones OSOW de Indiana DOR."},"75":{"q":"En una carretera de varios carriles de Indiana, un CMV que viaja más lento que el flujo normal del tránsito está obligado por la ley de Indiana a:","options":["Usar el carril del extremo izquierdo para mantenerse fuera del tránsito de incorporación","Viajar en el carril central en todo momento","Mantener al menos el mínimo señalizado en cualquier carril","Usar el o los carriles de la derecha disponibles para circular"],"explanation":"El IC 9-21-5-9 exige que los vehículos que se desplazan más lento que la velocidad máxima establecida usen los carriles de la derecha, y prohíbe continuar en el carril del extremo izquierdo cuando están siendo rebasados. Fuente: Indiana Code 9-21-5-9."},"76":{"q":"Un autobús escolar en una zona rural de Indiana activa sus luces ÁMBAR intermitentes alternantes. Estas luces significan:","options":["El autobús está averiado: rebase con precaución","Hay niños cruzando: deténgase de inmediato","El autobús está exento de la parada en el ferrocarril","El autobús se está preparando para detenerse a recoger o dejar pasajeros; esté listo para detenerse"],"explanation":"Las luces ámbar (amarillas) son una advertencia previa de que el autobús está por detenerse para recoger o dejar pasajeros, activadas aproximadamente 300 pies antes en las zonas rurales; las luces ROJAS y el brazo de alto extendido luego obligan al tránsito a detenerse. Fuente: Manual CDL de Indiana / seguridad de autobuses escolares de INDOT."},"77":{"q":"Un oficial de policía está dirigiendo el tránsito en un cruce a nivel de ferrocarril de Indiana y le indica a su vehículo con placas que avance sin detenerse. Debe:","options":["Detenerse de 15 a 50 pies de todas formas, ignorando al oficial","Detenerse solo si ve un tren","Seguir la indicación del oficial y avanzar sin la parada obligatoria","Retroceder y buscar otro cruce"],"explanation":"La parada obligatoria de 15 a 50 pies para vehículos con placas y de pasajeros no aplica cuando un oficial de policía o un señalero dirige el tránsito para que avance (también reconocido conforme al 49 CFR 392.10, aplicado en Indiana). Fuente: Manual CDL de Indiana; 49 CFR 392.10."},"78":{"q":"Un automovilista que rebasa de forma temeraria un autobús escolar de Indiana con su brazo de alto extendido y luces rojas intermitentes se enfrenta, además de las multas, a una posible:","options":["Suspensión de la licencia de conducir de hasta 90 días por una primera infracción","Pena obligatoria de 30 días de cárcel sin acción sobre la licencia","Solo una advertencia por escrito","Descalificación permanente del CDL por cualquier primera infracción"],"explanation":"Rebasar un autobús escolar detenido con el brazo de alto extendido es una infracción Clase A (IC 9-21-12-1); las violaciones temerarias caen bajo el IC 9-21-8-52, y los infractores primerizos pueden enfrentar una suspensión de la licencia de hasta 90 días (hasta un año para los reincidentes). Fuente: IC 9-21-12-1 e IC 9-21-8-52."},"79":{"q":"¿Qué organismo emite las Licencias de Conducir Comerciales (CDL) en Indiana?","options":["El Departamento de Vehículos Motorizados de Indiana (BMV)","El Departamento de Transporte de Indiana (INDOT)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","La División de Vehículos Comerciales de la Policía Estatal de Indiana"],"explanation":"Las CDL en Indiana son emitidas por el Departamento de Vehículos Motorizados de Indiana (BMV). El manual de CDL y todos los trámites de licencias se gestionan en las sucursales del BMV. Fuente: Indiana Specific CDL Applicant Information manual (SP 283), Indiana BMV."},"80":{"q":"En Indiana, ¿por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP)?","options":["Un año","180 días","Dos años","Seis meses, renovable indefinidamente"],"explanation":"Según el manual de CDL vigente de Indiana, 'Un CLP es válido por un año.' Fuente: Indiana Specific CDL Applicant Information manual (SP 283), sección del Permiso de Aprendiz Comercial, Indiana BMV."},"81":{"q":"¿Durante cuánto tiempo debe el solicitante tener el CLP antes de intentar el examen de habilidades del CDL en Indiana?","options":["Al menos 14 días","Al menos 30 días","Al menos 10 días","Al menos 60 días"],"explanation":"El manual establece: 'El solicitante debe tener el CLP por 14 días antes de intentar el examen de habilidades del CDL.' Esto refleja el mínimo federal y aplica en Indiana. Fuente: Manual CDL de Indiana (SP 283), sección CDL Skills Testing, Indiana BMV."},"82":{"q":"¿Por cuánto tiempo es válido un CDL emitido en Indiana antes de que deba renovarse?","options":["Cuatro años","Cinco años","Seis años","Tres años"],"explanation":"Un CDL emitido en Indiana es válido por cuatro años. Puede renovarlo en cualquier sucursal del BMV hasta un año antes de que venza. Fuente: Indiana BMV, Renewing or Replacing a CDL."},"83":{"q":"El examen de habilidades del CDL de Indiana se compone de ¿cuáles tres partes?","options":["Inspección del vehículo (pre-viaje), control básico del vehículo y conducción en carretera","Examen de frenos de aire, examen de combinación y conducción en carretera","Examen de conocimientos generales, control básico e inspección pre-viaje","Inspección pre-viaje, examen escrito de endoso y conducción en carretera"],"explanation":"El examen de habilidades del CDL de Indiana tiene tres partes: el Examen de Inspección del Vehículo (Sección 11), el Examen de Habilidades de Control Básico del Vehículo (Sección 12) y la Conducción en Carretera (Sección 13). Fuente: Manual CDL de Indiana (SP 283), CDL Skills Testing, Indiana BMV."},"84":{"q":"Antes de obtener un primer CDL de Clase A o Clase B en Indiana, el solicitante debe completar ¿cuál capacitación requerida a nivel federal?","options":["Capacitación de Conductor de Nivel Básico (ELDT) a través de un proveedor registrado ante la FMCSA","Un curso estatal de manejo defensivo en una sucursal del BMV","Un aprendizaje de 160 horas en Indiana verificado por INDOT","Una certificación de carga peligrosa de OSHA"],"explanation":"Los solicitantes deben completar la Capacitación de Conductor de Nivel Básico (ELDT) con un proveedor incluido en el Registro de Proveedores de Capacitación de la FMCSA antes de obtener el CDL. Fuente: Manual CDL de Indiana (SP 283); 49 CFR Part 380; en vigor desde el 7 de febrero de 2022."},"85":{"q":"¿Quién debe realizar el examen médico requerido para un CLP o CDL de Indiana?","options":["Un examinador médico incluido en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA","Cualquier médico licenciado de Indiana que elija el solicitante","Un médico empleado directamente por el Indiana BMV","Un examinador médico aprobado por la oficina de permisos de INDOT"],"explanation":"Todos los exámenes médicos deben ser realizados por un examinador médico certificado en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA (nationalregistry.fmcsa.dot.gov). Fuente: Manual CDL de Indiana (SP 283), Medical Examiner Requirements, Indiana BMV."},"86":{"q":"¿Cómo ingresa el Certificado del Examinador Médico (MEC) al sistema del Indiana BMV?","options":["El examinador certificado sube el MEC al Registro Nacional de la FMCSA, lo que permite que aplique al sistema del BMV","El solicitante envía por correo la tarjeta en papel a la sede de la FMCSA en Washington, D.C.","INDOT remite el certificado al BMV después de una inspección en carretera","El certificado se genera automáticamente cuando el solicitante aprueba el examen de habilidades"],"explanation":"El manual indica a los titulares del CLP/CDL que hagan que el médico certificado suba el MEC al Registro Nacional para que aplique al sistema del BMV. Fuente: Manual CDL de Indiana (SP 283), Medical Examiner Requirements and Certification, Indiana BMV."},"87":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un solicitante de CDL/CLP de Indiana al declarar el tipo de conducción que realizará?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Los solicitantes se autocertifican en una de cuatro categorías: interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado o intraestatal exceptuado. Fuente: 49 CFR 383.71 (aplicado por el Indiana BMV); autocertificación del Indiana BMV."},"88":{"q":"¿Cuál categoría de autocertificación describe a un conductor que opera cruzando líneas estatales y que debe cumplir con los requisitos federales de calificación médica/física?","options":["Interestatal no exceptuado","Interestatal exceptuado","Intraestatal no exceptuado","Intraestatal exceptuado"],"explanation":"Los conductores interestatales no exceptuados operan en el comercio interestatal y deben cumplir con los requisitos médicos del 49 CFR Part 391, manteniendo un MEC válido en archivo. Fuente: 49 CFR 383.71 / 391.41 (aplicado por el Indiana BMV)."},"89":{"q":"Según las reglas de Indiana, ¿con qué frecuencia puede un solicitante intentar un examen de conocimientos del CDL?","options":["Una vez al día; un examen reprobado puede repetirse el siguiente día hábil","Tres veces al día hasta aprobar","Una vez por semana, solo con cita","Cantidad ilimitada de veces en un solo día"],"explanation":"El manual establece que el solicitante puede intentar un examen de conocimientos del CDL solo una vez al día, y tras reprobar puede tomarlo de nuevo el siguiente día hábil. Fuente: Manual CDL de Indiana (SP 283), CDL Knowledge Tests, Indiana BMV."},"90":{"q":"Una vez aprobados, ¿por cuánto tiempo son válidos los resultados del examen de conocimientos y del examen de habilidades del CDL de Indiana?","options":["Un año","Seis meses","Dos años","90 días"],"explanation":"El manual establece que los resultados del examen de conocimientos del CDL son válidos por un año y los resultados del examen de habilidades del CDL son válidos por un año. Fuente: Manual CDL de Indiana (SP 283), CDL Knowledge Tests y CDL Skills Testing, Indiana BMV."},"91":{"q":"¿Dónde debe el solicitante presentar el examen de habilidades del CDL de Indiana?","options":["En un sitio de examen de habilidades del CDL aprobado por el BMV (autorizado a terceros)","En cualquier mostrador de sucursal de licencias del BMV de servicio completo","En una estación de pesaje o puerto de entrada de INDOT","En la oficina regional de campo de la FMCSA"],"explanation":"El examen de habilidades del CDL debe presentarse en un sitio de examen de habilidades del CDL aprobado por el BMV (sitios de terceros autorizados); los resultados se transmiten electrónicamente al BMV. Fuente: Manual CDL de Indiana (SP 283), CDL Skills Testing, Indiana BMV."},"92":{"q":"¿Cuál es la edad mínima para obtener un CDL/CLP de Indiana para operar en el comercio intraestatal (y no un autobús escolar ni el comercio interestatal)?","options":["18 años","21 años","19 años","16 años"],"explanation":"El solicitante debe tener al menos 18 años; para operar en el comercio interestatal o solicitar un endoso de autobús escolar, el solicitante debe tener al menos 21 años. Fuente: Manual CDL de Indiana (SP 283), requisitos del CLP, Indiana BMV."},"93":{"q":"Después de aprobar el examen de habilidades del CDL en Indiana, ¿qué debe hacer el solicitante para recibir efectivamente el CDL?","options":["Regresar a una sucursal de licencias del BMV para completar la solicitud antes de que venza el CLP","Esperar a que la licencia llegue por correo desde la FMCSA","Programar un segundo examen en carretera en INDOT","Volver a tomar el examen de conocimientos generales en el sitio de examen"],"explanation":"El manual establece que, tras aprobar el examen de habilidades, el solicitante debe regresar a una sucursal de licencias del BMV para completar la solicitud del CDL, y debe hacerlo antes del vencimiento del CLP. Fuente: Manual CDL de Indiana (SP 283), CDL Skills Testing, Indiana BMV."},"94":{"q":"¿Con cuánta anticipación debe programarse una cita para el examen de habilidades del CDL de Indiana con el sitio de examen?","options":["Al menos dos días de anticipación","Al menos dos semanas de anticipación","Al menos un día de anticipación","Al menos 30 días de anticipación"],"explanation":"El manual establece que las citas deben programarse con al menos dos días de anticipación, y el examen de habilidades solo puede presentarse una vez por día hábil. Fuente: Manual CDL de Indiana (SP 283), CDL Skills Testing, Indiana BMV."},"95":{"q":"En Indiana, ¿qué sucede si un CDL ha estado vencido, descalificado, cancelado, revocado, suspendido o invalidado por más de tres años?","options":["El solicitante debe aprobar todos los exámenes de conocimientos y de habilidades aplicables como solicitante por primera vez","El solicitante puede renovar en línea solo con un examen de la vista","El CDL se reinstala automáticamente tras un examen escrito","El solicitante solo necesita volver a presentar el examen de conducción en carretera"],"explanation":"El Requisito de Reexamen del manual establece que todo solicitante cuyo CDL haya estado vencido, entregado, descalificado, cancelado, revocado, suspendido o invalidado por más de tres años debe aprobar todos los exámenes de conocimientos y de habilidades aplicables como solicitante por primera vez. Fuente: Manual CDL de Indiana (SP 283), Indiana BMV."},"96":{"q":"Un nuevo residente con un CDL válido de otro estado, ¿cuánto tiempo tiene para transferirlo a un CDL de Indiana?","options":["30 días","60 días","90 días","10 días"],"explanation":"El manual establece que las personas tienen 30 días para transferir un CDL de otro estado; el examen de conocimientos de la licencia de conducir solo se requiere si el CDL de otro estado está vencido. Fuente: Manual CDL de Indiana (SP 283), Transfer an Out-of-Country or Out-of-State CDL, Indiana BMV."},"97":{"q":"¿Cuál afirmación sobre el proceso del endoso de Materiales Peligrosos (H) en Indiana es correcta?","options":["Requiere la aprobación de la evaluación de amenazas de seguridad de la TSA y no se agrega a un CLP","Puede agregarse a un CLP una vez que se aprueba el examen de frenos de aire","Solo requiere aprobar el examen de conocimientos generales","Se emite automáticamente con cualquier CDL de Clase A"],"explanation":"El manual establece que un endoso de HazMat requiere la aprobación de la evaluación de amenazas de seguridad de la TSA por el plazo del CDL, y que no se agregará a un CLP. Fuente: Manual CDL de Indiana (SP 283), CDL Endorsements, Indiana BMV; 49 CFR 1572 (TSA)."},"98":{"q":"Además de aprobar los exámenes de conocimientos y de habilidades, ¿cuál paso se exige específicamente a todo solicitante de CDL de Indiana durante el proceso de obtención de la licencia?","options":["Ver un video instructivo sobre cómo reconocer, prevenir y reportar la trata de personas","Completar 40 horas de acompañamiento con un agente estatal","Aprobar un examen de permisos de sobredimensión/sobrepeso de INDOT","Obtener el patrocinio notariado de un empleador antes de presentar los exámenes"],"explanation":"Indiana exige que los solicitantes de CDL vean un video instructivo sobre cómo reconocer, prevenir y reportar la trata de personas, además de completar la ELDT y aprobar los exámenes requeridos. Fuente: Manual CDL de Indiana (SP 283), requisitos de la solicitud, Indiana BMV."}},"hi":{"0":{"q":"इंडियाना के राजमार्गों पर, किसी वाहन और उसके लोड की अधिकतम कानूनी चौड़ाई क्या है (चौड़ाई-अपवर्जित उपकरणों जैसे मिरर को छोड़कर)?","options":["8 feet 0 inches","9 feet 0 inches","8 feet 6 inches","10 feet 0 inches"],"explanation":"इंडियाना वाहन और लोड की चौड़ाई को 8 feet 6 inches (102 inches) तक सीमित करता है, 23 CFR 658 के अनुसार चौड़ाई-अपवर्जित सुरक्षा उपकरणों को छोड़कर। स्रोत: Indiana Code IC 9-20-3-2; Indiana State Police Summary of Indiana Size and Weight Laws (Title 9, Article 20)।"},"1":{"q":"इंडियाना के राजमार्गों पर, किसी वाहन की अधिकतम कानूनी ऊँचाई क्या है, जिसमें उसका लोड भी शामिल है?","options":["13 feet 0 inches","14 feet 0 inches","13 feet 6 inches","12 feet 6 inches"],"explanation":"इंडियाना अधिकतम ऊँचाई 13 feet 6 inches निर्धारित करता है, और इस कानूनी ऊँचाई में कोई छूट नहीं है। स्रोत: IC 9-20-3-3; Indiana State Police Summary of Indiana Size and Weight Laws।"},"2":{"q":"इंडियाना के कानून के तहत, बिना ओवरवेट परमिट के किसी वाहन या संयोजन का अधिकतम सकल वजन कितना अनुमत है?","options":["73,280 pounds","80,000 pounds","88,000 pounds","84,000 pounds"],"explanation":"इंडियाना का अधिकतम कानूनी सकल वजन 80,000 pounds है; इससे अधिक भारी कुछ भी होने पर परमिट की आवश्यकता होती है। 73,280-pound का आँकड़ा केवल कुछ विशिष्ट विन्यासों के लिए ग्रैंडफादर प्रावधान के तहत लागू होता है। स्रोत: IC 9-20-4 (General Weight Restrictions); Indiana State Police Summary of Size and Weight Laws।"},"3":{"q":"इंडियाना किसी एकल एक्सल पर अधिकतम कितना वजन अनुमत करता है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"इंडियाना का अधिकतम एकल एक्सल वजन 20,000 pounds है। (18,000-pound और 16,000-pound के आँकड़े केवल ग्रैंडफादर-कानून परिदृश्यों में दिखाई देते हैं।) स्रोत: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws।"},"4":{"q":"इंडियाना किसी टैंडम एक्सल समूह पर अधिकतम कितना वजन अनुमत करता है?","options":["34,000 pounds","32,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"इंडियाना का अधिकतम टैंडम एक्सल वजन 34,000 pounds है, जो संघीय मानक से मेल खाता है। स्रोत: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws।"},"5":{"q":"इंडियाना व्हील वजन को रिम के फ्लैंजों के बीच मापी गई टायर की चौड़ाई के प्रति इंच कितने तक सीमित करता है?","options":["600 pounds","1,000 pounds","500 pounds","800 pounds"],"explanation":"इंडियाना व्हील वजन को रिम के फ्लैंजों के बीच मापी गई टायर की चौड़ाई के प्रति इंच 800 pounds पर सीमित करता है, चाहे लदा हुआ हो या बिना लदा। स्रोत: IC 9-20-11-4; Indiana State Police Summary of Indiana Size and Weight Laws।"},"6":{"q":"इंडियाना के राजमार्गों पर अपनी ही शक्ति से चलने वाले किसी एकल वाहन की अधिकतम लंबाई क्या है (लंबाई-अपवर्जित उपकरणों को छोड़कर)?","options":["40 feet","45 feet","35 feet","53 feet"],"explanation":"23 CFR 658.13 के अनुसार लंबाई-अपवर्जित उपकरणों को छोड़कर, कोई एकल मोटर वाहन 40 feet से अधिक नहीं हो सकता। मनोरंजक वाहन (recreational vehicle) के लिए 45 feet तक की अनुमति है। स्रोत: IC 9-20-3-1 / IC 9-20-8; Indiana State Police Summary of Size and Weight Laws।"},"7":{"q":"ट्रक-ट्रैक्टर और सेमीट्रेलर संयोजन में, इंडियाना के कानून के तहत सेमीट्रेलर (लोड सहित) की अधिकतम लंबाई क्या है?","options":["48 feet","57 feet","45 feet","53 feet"],"explanation":"इंडियाना ट्रक-ट्रैक्टर संयोजन में सेमीट्रेलर को 53 feet तक अनुमत करता है, और उस संयोजन पर कुल लंबाई की कोई सीमा नहीं लगाई जाती। स्रोत: IC 9-20-8; Indiana State Police Summary of Size and Weight Laws।"},"8":{"q":"कानूनी आकार और वजन सीमा से अधिक वाहनों के लिए ओवरसाइज़ और ओवरवेट (OSOW) परमिट कौन-सी इंडियाना एजेंसी जारी करती है?","options":["Indiana Bureau of Motor Vehicles","Indiana Department of Revenue, Motor Carrier Services","Indiana State Police","Indiana Department of Natural Resources"],"explanation":"OSOW परमिट Indiana Department of Revenue की Motor Carrier Services द्वारा जारी किए जाते हैं, जो INDOT और इंडियाना कानून द्वारा निर्धारित नियमों के तहत होते हैं। स्रोत: IC 9-20-6; Indiana DOR Motor Carrier Services OSOW program (in.gov/dor)।"},"9":{"q":"अधिकतम कानूनी सकल और एक्सल वजन की गणना के लिए इंडियाना ने संघीय Bridge Formula को राज्य कानून में किस वर्ष अपनाया?","options":["1975","1956","1982","1991"],"explanation":"इंडियाना ने 1975 में Bridge Formula को राज्य कानून के रूप में अपनाया, और January 4, 1975 को प्रभावी वजन सीमाओं के लिए एक ग्रैंडफादर प्रावधान बरकरार रखता है। स्रोत: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws।"},"10":{"q":"इंडियाना द्वारा संघीय Bridge Formula W = 500{[(LN) / (N-1)] + 12N + 36} को अपनाने के तहत, चर 'N' किसका प्रतिनिधित्व करता है?","options":["वाहन में शुद्ध कार्गो वजन","संयोजन की कुल लंबाई feet में","ड्राइव एक्सल पर टायरों की संख्या","विचाराधीन समूह में एक्सलों की संख्या"],"explanation":"Bridge Formula में, N समूह में एक्सलों की संख्या है, L समूह के दो छोर वाले एक्सलों के बीच की दूरी है, और W उस समूह पर अनुमेय सकल वजन है। स्रोत: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws।"},"11":{"q":"इंडियाना का Bridge Formula टैंडम एक्सलों के दो लगातार सेटों में से प्रत्येक को 34,000 pounds ले जाने की अनुमति देता है, बशर्ते उन टैंडमों के पहले और अंतिम एक्सल कम-से-कम कितनी दूरी पर हों?","options":["30 feet","40 feet","36 feet","51 feet"],"explanation":"टैंडम एक्सलों के दो लगातार सेट प्रत्येक 34,000 pounds तक ले जा सकते हैं यदि इन सेटों के पहले और अंतिम एक्सल कम-से-कम 36 feet दूर हों। स्रोत: IC 9-20-4 (Bridge Formula); Indiana State Police Summary of Indiana Size and Weight Laws।"},"12":{"q":"एक साथ जुड़े हुए दो वाहनों का संयोजन, लोड सहित, इंडियाना के राजमार्गों पर सामान्यतः कितनी कुल लंबाई से अधिक नहीं हो सकता?","options":["65 feet","55 feet","75 feet","60 feet"],"explanation":"दो जुड़े हुए वाहनों का संयोजन, लोड सहित, 60 feet से अधिक नहीं हो सकता (कुछ सीमित अपवादों के साथ जैसे boat/vehicle haulers और drive-away service)। स्रोत: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws।"},"13":{"q":"एक साथ जुड़े हुए तीन या अधिक वाहनों का संयोजन, लोड सहित, इंडियाना के कानून के तहत कितनी कुल लंबाई से अधिक नहीं हो सकता?","options":["60 feet","70 feet","65 feet","75 feet"],"explanation":"इंडियाना तीन या अधिक जुड़े हुए वाहनों के संयोजन को, लोड सहित, 65 feet तक सीमित करता है। स्रोत: IC 9-20-8; Indiana State Police Summary of Indiana Size and Weight Laws।"},"14":{"q":"इंडियाना उत्पादन स्थल से पहले डिलीवरी बिंदु तक कृषि वस्तुएँ ढोने वाले वाहन के लिए 10% सकल-वजन सहनशीलता प्रदान करता है, सिवाय किस स्थिति के?","options":["जब वाहन इंटरस्टेट सिस्टम के किसी भी भाग पर संचालित हो","जब लोड रात में ढोया जाए","जब वाहन में पाँच से अधिक एक्सल हों","जब यात्रा 50 miles से अधिक हो"],"explanation":"10% कृषि-वस्तु सकल-वजन सहनशीलता इंटरस्टेट सिस्टम के किसी भी भाग पर लागू नहीं होती, और न ही वहाँ जहाँ IC 9-20-1-4 के तहत पोस्ट की गई पुल/राजमार्ग सीमाएँ लागू हों। स्रोत: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws।"},"15":{"q":"यदि किसी संयोजन वाहन को 80,000-pound सकल वजन की अनुमति है, तो इंडियाना की 10% सहनशीलता के तहत योग्य कृषि वस्तुएँ ढोते समय उसका अधिकतम सकल वजन क्या है?","options":["84,000 pounds","90,000 pounds","88,000 pounds","86,000 pounds"],"explanation":"इंडियाना योग्य कृषि-वस्तु ढुलाई के लिए अनुमेय सकल वजन में 10% जोड़ता है, इसलिए 80,000 pounds 88,000 pounds हो जाता है (केवल इंटरस्टेट से बाहर, बिना-पोस्ट किए मार्गों पर)। स्रोत: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws।"},"16":{"q":"इंडियाना 10% वजन सहनशीलता के लिए कुछ वन उत्पादों को कृषि वस्तुओं के रूप में मानता है। इनमें से किसके लिए सकल और एक्सल वजन हेतु 10% सहनशीलता हर समय लागू होती है?","options":["तैयार लकड़ी और प्लाईवुड","लकड़ी के चिप्स, छाल, और बुरादा","फर्नीचर और कैबिनेटरी","कागज और गत्ता"],"explanation":"कृषि वस्तुओं में लट्ठे, लकड़ी के चिप्स, छाल, बुरादा, और थोक दूध शामिल हैं; लकड़ी के चिप्स, छाल, और बुरादे के लिए 10% सहनशीलता हर समय सकल और एक्सल वजन पर लागू होती है। स्रोत: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws।"},"17":{"q":"January 4, 1975 को प्रभावी वजन सीमाओं को बरकरार रखने वाले इंडियाना के ग्रैंडफादर प्रावधान के तहत, प्रभावित वाहन विन्यासों के लिए अधिकतम सकल वजन क्या है?","options":["80,000 pounds","70,000 pounds","64,000 pounds","73,280 pounds"],"explanation":"इंडियाना का ग्रैंडफादर कानून उन विन्यासों के लिए 73,280 pounds का अधिकतम सकल वजन संरक्षित करता है जो अन्यथा Bridge Formula द्वारा दंडित किए जाते। स्रोत: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws।"},"18":{"q":"इंटरस्टेट राजमार्गों को छोड़कर, इंडियाना में किसी योग्य नगरपालिका कचरा/अपशिष्ट संग्रह वाहन के लिए अधिकतम एकल-एक्सल वजन कितना अनुमत है?","options":["20,000 pounds","24,000 pounds","22,400 pounds","26,000 pounds"],"explanation":"इंटरस्टेट सिस्टम को छोड़कर, योग्य कचरा वाहन एकल एक्सल पर 24,000 pounds तक और टैंडम एक्सल पर 42,000 pounds तक ले जा सकते हैं, लेकिन IC 9-20-11-4 के तहत व्हील-वजन सीमाओं के अधीन रहते हैं। स्रोत: IC 9-20-4; Indiana State Police Summary of Indiana Size and Weight Laws।"},"19":{"q":"इंडियाना में, 26,001 pounds या उससे अधिक के Gross Combination Weight Rating (GCWR) वाले वाहनों के संयोजन को संचालित करने के लिए कौन-सा CDL वर्ग आवश्यक है, जहाँ खींचे जाने वाले वाहन(नों) का GVWR 10,000 pounds से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"इंडियाना Class A CDL को 26,001 lbs या उससे अधिक GCWR वाले वाहनों के किसी भी संयोजन के रूप में परिभाषित करता है, बशर्ते खींची जाने वाली इकाई(यों) का GVWR 10,000 lbs से अधिक हो। स्रोत: Indiana CDL Manual (Indiana BMV); 49 CFR 383.91 जैसा इंडियाना द्वारा अपनाया गया।"},"20":{"q":"इंडियाना के नियमों के तहत, 26,001 pounds या उससे अधिक GVWR वाले एकल वाहन (या ऐसा वाहन जो 10,000 pounds GVWR से अधिक न होने वाली इकाई को खींच रहा हो) के लिए कौन-सा CDL वर्ग आवश्यक है?","options":["Class C","Class B","Class A","Chauffeur license"],"explanation":"इंडियाना Class B CDL को 26,001 lbs या उससे अधिक GVWR वाले किसी भी एकल वाहन, या ऐसे वाहन जो 10,000 lbs GVWR से अधिक न होने वाली इकाई को खींच रहा हो, के रूप में परिभाषित करता है। स्रोत: Indiana CDL Manual (Indiana BMV)।"},"21":{"q":"इंडियाना में, ऐसा वाहन जो Class A या Class B वजन सीमाओं को पूरा नहीं करता लेकिन 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है या प्लेकार्ड वाली खतरनाक सामग्री ले जाता है, के लिए कौन-सा CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं"],"explanation":"इंडियाना में Class C CDL उन वाहनों को कवर करता है जो Class A/B वजन सीमाओं से नीचे हैं और 16+ यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए हैं या जो प्लेकार्डिंग की आवश्यकता वाली खतरनाक सामग्री ले जाते हैं। स्रोत: Indiana CDL Manual (Indiana BMV)।"},"22":{"q":"केवल इंट्रास्टेट (इंडियाना के भीतर) ड्राइविंग तक सीमित इंडियाना CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 years old","17 years old","18 years old","21 years old"],"explanation":"इंडियाना में इंट्रास्टेट संचालन के लिए CDL या CLP धारण करने हेतु आवेदकों का कम-से-कम 18 वर्ष का होना आवश्यक है; 18-20 आयु के चालक इंडियाना के भीतर ही वाणिज्यिक वाहन संचालित करने तक सीमित हैं। स्रोत: Indiana CDL Manual (Indiana BMV); IC 9-24।"},"23":{"q":"इंडियाना CDL के साथ इंटरस्टेट वाणिज्य (राज्य की सीमाओं के पार) में वाणिज्यिक मोटर वाहन चलाने की न्यूनतम आयु क्या है?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"किसी वाणिज्यिक मोटर वाहन को इंटरस्टेट संचालित करने, खतरनाक सामग्री ले जाने, या राज्य की सीमाओं के पार यात्रियों को ले जाने के लिए चालक का कम-से-कम 21 वर्ष का होना आवश्यक है। 18-20 आयु के चालक इंडियाना में इंट्रास्टेट ड्राइविंग तक सीमित हैं। स्रोत: Indiana CDL Manual (Indiana BMV); 49 CFR 391.11।"},"24":{"q":"किसी एकल टैंक में 119 gallons से अधिक का तरल या गैस ले जाने वाले टैंक वाहन को चलाने के लिए इंडियाना कौन-सा एंडोर्समेंट आवश्यक करता है (कुल मिलाकर 1,000+ gallons के साथ)?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"इंडियाना का N (Tank Vehicle) एंडोर्समेंट उन वाहनों के लिए आवश्यक है जो किसी टैंक में तरल या गैस ले जाने के लिए डिज़ाइन किए गए हैं जिसकी व्यक्तिगत रेटेड क्षमता 119 gallons से अधिक और कुल क्षमता 1,000 gallons या उससे अधिक हो। स्रोत: Indiana BMV CDL Endorsements and Restrictions।"},"25":{"q":"दो या तीन अलग-अलग ट्रेलरों (doubles/triples) को खींचने वाले वाहन को संचालित करने के लिए कौन-सा इंडियाना CDL एंडोर्समेंट आवश्यक है?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement S"],"explanation":"T एंडोर्समेंट दो या तीन अलग-अलग ट्रेलरों (doubles/triples) के जुड़े हुए संयोजन के संचालन को अधिकृत करता है। इसे doubles/triples ज्ञान परीक्षा पास करके प्राप्त किया जाता है। स्रोत: Indiana BMV CDL Endorsements and Restrictions।"},"26":{"q":"16 या अधिक यात्रियों, चालक सहित, को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए कौन-सा इंडियाना CDL एंडोर्समेंट आवश्यक है?","options":["Endorsement S","Endorsement P","Endorsement N","Endorsement H"],"explanation":"P (Passenger) एंडोर्समेंट 16 या अधिक यात्रियों, चालक सहित, को ले जाने के लिए डिज़ाइन किए गए वाहन को संचालित करने के लिए आवश्यक है। इसके लिए ज्ञान परीक्षा, प्रतिनिधि वाहन में कौशल परीक्षा, और पहली बार आवेदन करने वालों के लिए ELDT की आवश्यकता होती है। स्रोत: Indiana BMV CDL Endorsements and Restrictions।"},"27":{"q":"इंडियाना में, H (Hazardous Materials) एंडोर्समेंट प्राप्त करने के लिए आवेदक को कौन-सी अतिरिक्त संघीय जाँच पूरी करनी होती है?","options":["फिंगरप्रिंटिंग सहित एक TSA security threat assessment","एक FBI पॉलीग्राफ परीक्षा","बिना फिंगरप्रिंट के केवल राज्य-स्तरीय आपराधिक रिकॉर्ड जाँच","एक DEA नियंत्रित-पदार्थ साक्षात्कार"],"explanation":"H एंडोर्समेंट जोड़ने के लिए HazMat ज्ञान परीक्षा पास करना और एक TSA security threat assessment पूरा करना आवश्यक है, जिसमें फिंगरप्रिंटिंग और वैध स्थिति का सत्यापन शामिल है। स्रोत: Indiana BMV CDL Endorsements and Restrictions; 49 CFR 1572 (TSA)।"},"28":{"q":"Hazardous Materials (H) एंडोर्समेंट बनाए रखने के लिए इंडियाना CDL धारक को TSA security threat assessment को कितनी बार नवीनीकृत करना होता है?","options":["हर साल","हर 2 साल","हर 5 साल","हर 10 साल"],"explanation":"HazMat एंडोर्समेंट के लिए TSA security threat assessment पाँच वर्षों तक वैध रहता है और कम-से-कम हर पाँच वर्ष में (एक नई HazMat ज्ञान परीक्षा के साथ) नवीनीकृत किया जाना चाहिए। स्रोत: Indiana BMV CDL Endorsements and Restrictions; TSA HazMat Endorsement program।"},"29":{"q":"जब कोई चालक Hazardous Materials और Tank Vehicle दोनों एंडोर्समेंट रखता है, तो इंडियाना कौन-सा संयुक्त एंडोर्समेंट कोड जारी करता है?","options":["Endorsement X","Endorsement HN","Endorsement Z","Endorsement W"],"explanation":"इंडियाना H (HazMat) और N (Tank Vehicle) विशेषाधिकारों के संयोजन का प्रतिनिधित्व करने के लिए X एंडोर्समेंट जारी करता है। स्रोत: Indiana BMV CDL Endorsements and Restrictions।"},"30":{"q":"इंडियाना में CDL कौशल परीक्षा देने से पहले, किसी आवेदक को कितने समय तक वैध Commercial Learner's Permit (CLP) धारण करना होता है?","options":["कम-से-कम 7 days","कम-से-कम 14 days","कम-से-कम 30 days","कम-से-कम 60 days"],"explanation":"किसी आवेदक को CDL कौशल परीक्षा का प्रयास करने से पहले कम-से-कम 14 days तक CLP धारण करना होता है। यह इंडियाना द्वारा अपनाई गई संघीय न्यूनतम सीमा है। स्रोत: Indiana CDL Manual / Indiana BMV; 49 CFR 383.25।"},"31":{"q":"Indiana BMV के अनुसार, Commercial Learner's Permit (CLP) जारी होने के बाद कितने समय तक वैध रहता है?","options":["30 days","90 days","एक वर्ष","पाँच वर्ष"],"explanation":"Indiana BMV कहता है कि CLP एक वर्ष के लिए वैध होता है, और CDL ज्ञान परीक्षा के परिणाम भी इसी प्रकार एक वर्ष के लिए वैध होते हैं। स्रोत: Indiana BMV, Obtaining a Commercial Learner's Permit।"},"32":{"q":"वाणिज्यिक मोटर वाहन संचालित करते समय इंडियाना CLP धारक पर कौन-सा प्रतिबंध लागू होता है?","options":["वे केवल इंटरस्टेट राजमार्गों पर अकेले गाड़ी चला सकते हैं","उनके साथ उचित वर्ग और एंडोर्समेंट वाला एक CDL धारक होना चाहिए","वे केवल सूर्योदय से सूर्यास्त के बीच गाड़ी चला सकते हैं","वे केवल 26,001 pounds GVWR से कम के वाहन संचालित कर सकते हैं"],"explanation":"कोई CLP धारक वाणिज्यिक मोटर वाहन केवल तभी संचालित कर सकता है जब उसके साथ उचित वर्ग और एंडोर्समेंट वाला एक वैध CDL रखने वाला व्यक्ति हो जो CLP धारक के बगल में बैठा हो। स्रोत: Indiana BMV, Obtaining a Commercial Learner's Permit; 49 CFR 383.25।"},"33":{"q":"इंडियाना CDL या CLP के लिए आवेदन करते समय, आवेदक को इंडियाना निवास सिद्ध करने के लिए कितने दस्तावेज़ प्रस्तुत करने होते हैं?","options":["एक दस्तावेज़","दो दस्तावेज़","तीन दस्तावेज़","किसी निवास प्रमाण की आवश्यकता नहीं"],"explanation":"इंडियाना को इंडियाना निवास सिद्ध करने वाले दो दस्तावेज़ों की आवश्यकता होती है, साथ ही पहचान सिद्ध करने वाला एक, वैध स्थिति सिद्ध करने वाला एक, और पूरा Social Security नंबर सिद्ध करने वाला एक दस्तावेज़ भी चाहिए। स्रोत: Indiana BMV document requirements।"},"34":{"q":"पहचान और इंडियाना निवास के प्रमाण के अतिरिक्त, इंडियाना CDL आवेदक को कौन-सी दो चीज़ें दस्तावेज़ित करनी होती हैं?","options":["अमेरिका में वैध स्थिति और पूरा Social Security नंबर","एक हाई स्कूल डिप्लोमा और वाहन टाइटल","एक दृष्टि विशेषज्ञ का पत्र और नियोक्ता शपथपत्र","मतदाता पंजीकरण और एक उपयोगिता जमा रसीद"],"explanation":"इंडियाना को पहचान और दो निवास दस्तावेज़ों के अतिरिक्त, अमेरिका में वैध स्थिति (वैध उपस्थिति) सिद्ध करने वाला एक दस्तावेज़ और आवेदक का पूरा Social Security नंबर सिद्ध करने वाला एक दस्तावेज़ आवश्यक है। स्रोत: Indiana BMV document requirements।"},"35":{"q":"February 7, 2022 से प्रभावी, Entry-Level Driver Training (ELDT) इंडियाना आवेदकों द्वारा किस स्थिति में पूरा किया जाना चाहिए?","options":["वर्ग में बदलाव किए बिना मौजूदा Class A CDL का नवीनीकरण","पहली बार Class A या Class B CDL प्राप्त करना, या पहला H, P, या S एंडोर्समेंट प्राप्त करना","केवल T (doubles/triples) एंडोर्समेंट जोड़ना","अपवादित इंट्रास्टेट के रूप में स्व-प्रमाणन"],"explanation":"ELDT उन चालकों पर लागू होता है जो पहली बार Class A या Class B CDL प्राप्त कर रहे हैं, उच्च वर्ग में अपग्रेड कर रहे हैं, या February 7, 2022 को या उसके बाद पहली बार Hazardous Materials (H), Passenger (P), या School Bus (S) एंडोर्समेंट प्राप्त कर रहे हैं। स्रोत: FMCSA ELDT rule; Indiana BMV।"},"36":{"q":"इंडियाना आवेदक को आवश्यक Entry-Level Driver Training (ELDT) कहाँ पूरा करना चाहिए?","options":["आवेदक की पसंद के किसी भी निजी ड्राइविंग स्कूल में","FMCSA Training Provider Registry पर सूचीबद्ध किसी प्रदाता के साथ","किसी Indiana BMV शाखा परीक्षण केंद्र में","किसी ऑनलाइन TSA-अनुमोदित पाठ्यक्रम के माध्यम से"],"explanation":"ELDT सैद्धांतिक और व्यावहारिक (behind-the-wheel) प्रशिक्षण FMCSA Training Provider Registry (TPR) पर सूचीबद्ध किसी संस्था द्वारा दिया जाना चाहिए; केवल सूचीबद्ध प्रदाता ही पूर्णता की रिपोर्ट कर सकते हैं। स्रोत: FMCSA Training Provider Registry; Indiana BMV।"},"37":{"q":"इंडियाना CDL धारक कौन-सी चिकित्सा स्व-प्रमाणन श्रेणी चुनता है यदि वह केवल इंडियाना के भीतर संचालन करता है और उसे चिकित्सा परीक्षक के प्रमाणपत्र के साथ राज्य के चालक योग्यता आवश्यकताओं को पूरा करना होता है?","options":["Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Non-Excepted Intrastate (NA) उन चालकों पर लागू होता है जो केवल इंट्रास्टेट (इंडियाना के भीतर) वाणिज्य में संचालन करते हैं और जिन्हें इंडियाना के चालक योग्यता नियमों को पूरा करना होता है और एक चिकित्सा परीक्षक का प्रमाणपत्र प्रदान करना होता है। स्रोत: Indiana BMV CDL self-certification; 49 CFR 383.71।"},"38":{"q":"कौन-सी स्व-प्रमाणन श्रेणी इंडियाना CDL धारक को FMCSA National Registry पर किसी प्रदाता से वैध संघीय DOT Medical Examiner's Certificate बनाए रखने की आवश्यकता होती है?","options":["Excepted Intrastate (EA)","Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Restricted Agricultural (RA)"],"explanation":"Non-Excepted Interstate (NI) के रूप में स्व-प्रमाणित करने वाला चालक गैर-अपवादित वाणिज्य में राज्य की सीमाओं के पार संचालन करता है और उसे FMCSA National Registry पर किसी प्रमाणित परीक्षक द्वारा जारी एक वैध Medical Examiner's Certificate रखना और बनाए रखना होता है। स्रोत: Indiana BMV CDL self-certification; 49 CFR 391.41।"},"39":{"q":"इंडियाना में, अधिकतम रक्त अल्कोहल सांद्रता (BAC) क्या है जिस पर वाणिज्यिक मोटर वाहन (CMV) संचालित करना कानूनी है?","options":["0.04% से कम","0.08% से कम","0.02% से कम","0.10% से कम"],"explanation":"Indiana BMV CDL Manual (Section 1.3.2) कहती है कि यदि आपकी रक्त अल्कोहल सांद्रता .04% या उससे अधिक है तो CMV संचालित करना अवैध है, इसलिए एक CMV चालक को 0.04% से नीचे रहना चाहिए (गैर-वाणिज्यिक चालकों के लिए 0.08% सीमा का आधा)। स्रोत: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2।"},"40":{"q":"इंडियाना के implied-consent नियम के तहत, CMV संचालित करने का मतलब है कि चालक ने किस बात पर सहमति दी है?","options":["अल्कोहल परीक्षण के लिए प्रस्तुत होने पर","वकील के अधिकार को त्यागने पर","किसी भी समय वाहन निरीक्षण पर","एक अनिवार्य नशा उपचार कार्यक्रम पर"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) कहती है कि यदि आप CMV संचालित करते हैं, तो माना जाएगा कि आपने अल्कोहल परीक्षण के लिए अपनी सहमति दे दी है। स्रोत: Indiana BMV Commercial Driver's License Manual, Sec. 1.3.2; IC 9-30-6।"},"41":{"q":"0.04% या उससे अधिक BAC के साथ CMV चलाने जैसे पहले प्रमुख अपराध के लिए, इंडियाना CDL धारक कितने समय तक अपना CDL खो देगा?","options":["कम-से-कम 1 year","कम-से-कम 6 months","कम-से-कम 90 days","कम-से-कम 3 years"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) कहती है कि पहले प्रमुख अपराध के लिए आप कम-से-कम एक वर्ष के लिए अपना CDL खो देंगे, जिसमें 0.04% या उससे अधिक BAC के साथ CMV चलाना शामिल है। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51)।"},"42":{"q":"यदि कोई पहला प्रमुख अपराध तब होता है जब चालक खतरनाक सामग्री के लिए प्लेकार्ड वाला CMV संचालित कर रहा हो, तो इंडियाना में न्यूनतम अयोग्यता क्या है?","options":["कम-से-कम 3 years","कम-से-कम 1 year","कम-से-कम 5 years","जीवनभर"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) कहती है कि यदि कोई पहला प्रमुख अपराध तब होता है जब आप खतरनाक सामग्री के लिए प्लेकार्ड वाला CMV संचालित कर रहे हों, तो आप कम-से-कम तीन वर्षों के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.2।"},"43":{"q":"इंडियाना CDL नियमों के तहत दूसरे प्रमुख अपराध (जैसे दूसरा CMV DWI) का परिणाम क्या है?","options":["जीवनभर के लिए CDL की हानि","10 years के लिए CDL की हानि","3 years के लिए CDL की हानि","5 years के लिए CDL की हानि"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) कहती है कि दूसरे प्रमुख अपराध के लिए आप जीवनभर के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.2 (49 CFR 383.51)।"},"44":{"q":"निम्नलिखित में से किसे पहले प्रमुख अपराध के रूप में माना जाता है जिसके कारण इंडियाना CDL धारक कम-से-कम एक वर्ष के लिए अपना लाइसेंस खो देता है?","options":["रक्त अल्कोहल परीक्षण कराने से इनकार करना","किसी वाहन का बहुत पास से अनुसरण करना","पोस्ट की गई सीमा से 16 mph तेज़ गाड़ी चलाना","एक अनुचित लेन परिवर्तन"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) रक्त अल्कोहल परीक्षण कराने से इनकार करने को एक प्रमुख अपराध के रूप में सूचीबद्ध करती है जो कम-से-कम एक वर्ष की अयोग्यता रखता है; अन्य विकल्प गंभीर यातायात उल्लंघन हैं, प्रमुख अपराध नहीं। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.2।"},"45":{"q":"इंडियाना में, ऐसे CDL धारक का क्या होता है जो नियंत्रित पदार्थों से जुड़े किसी अपराध (felony) को करने के लिए CMV का उपयोग करता है?","options":["जीवनभर के लिए CDL की हानि","3 years के लिए CDL की हानि","1 year के लिए CDL की हानि","5 years के लिए CDL की हानि"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) कहती है कि यदि आप नियंत्रित पदार्थों से जुड़े किसी अपराध (felony) को करने के लिए CMV का उपयोग करते हैं, तो आप जीवनभर के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.2।"},"46":{"q":"इंडियाना में किसी CMV चालक में 0.04% से कम का पता लगाने योग्य अल्कोहल पाया जाता है। तत्काल परिणाम क्या है?","options":["24 hours के लिए सेवा से बाहर (out-of-service) रखा जाना","60 days के लिए CDL अयोग्य","एक $2,750 सिविल जुर्माना","1 year के लिए CDL अयोग्य"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.2) कहती है कि यदि आपमें 0.04% से कम कोई भी पता लगाने योग्य अल्कोहल मात्रा है तो आपको 24 hours के लिए सेवा से बाहर (out-of-service) रखा जाएगा। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.2।"},"47":{"q":"Indiana CDL Manual एक गंभीर यातायात उल्लंघन के रूप में 'अत्यधिक गति (excessive speeding)' को कैसे परिभाषित करती है?","options":["पोस्ट की गई सीमा से 15 mph या अधिक ऊपर","पोस्ट की गई सीमा से 10 mph या अधिक ऊपर","पोस्ट की गई सीमा से 20 mph या अधिक ऊपर","पोस्ट की गई सीमा से 25 mph या अधिक ऊपर"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3) अत्यधिक गति को पोस्ट की गई सीमा से 15 mph या अधिक ऊपर के रूप में परिभाषित करती है। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.3।"},"48":{"q":"तीन-वर्ष की अवधि के भीतर किसी CMV में दो गंभीर यातायात उल्लंघनों के लिए, इंडियाना CDL धारक कितने समय तक अपना CDL खो देगा?","options":["कम-से-कम 60 days","कम-से-कम 30 days","कम-से-कम 90 days","कम-से-कम 120 days"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3) कहती है कि CMV से जुड़े तीन-वर्ष की अवधि के भीतर दो गंभीर यातायात उल्लंघनों के लिए आप कम-से-कम 60 days के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.3।"},"49":{"q":"तीन-वर्ष की अवधि के भीतर किसी CMV में तीन या अधिक गंभीर यातायात उल्लंघनों के लिए, इंडियाना की अयोग्यता क्या है?","options":["कम-से-कम 120 days","कम-से-कम 60 days","कम-से-कम 90 days","कम-से-कम 1 year"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3) कहती है कि CMV से जुड़े तीन-वर्ष की अवधि के भीतर तीन या अधिक गंभीर यातायात उल्लंघनों के लिए आप कम-से-कम 120 days के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.3।"},"50":{"q":"निम्नलिखित में से किसे Indiana CDL Manual में एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध किया गया है?","options":["लापरवाह ड्राइविंग (reckless driving)","0.04% BAC के साथ CMV चलाना","किसी CMV दुर्घटना के स्थल को छोड़कर जाना","रक्त अल्कोहल परीक्षण से इनकार करना"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.3) लापरवाह ड्राइविंग (reckless driving) को गंभीर यातायात उल्लंघनों में सूचीबद्ध करती है; अन्य तीन Sec. 1.3.2 के तहत प्रमुख अपराध हैं। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.3।"},"51":{"q":"इंडियाना में out-of-service order के पहले उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["कम-से-कम 90 days","कम-से-कम 60 days","कम-से-कम 30 days","कम-से-कम 180 days"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.4) कहती है कि out-of-service order के आपके पहले उल्लंघन के लिए आप कम-से-कम 90 days के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.4।"},"52":{"q":"इंडियाना में दस-वर्ष की अवधि के भीतर दो out-of-service order उल्लंघनों के लिए न्यूनतम अयोग्यता क्या है?","options":["कम-से-कम 1 year","कम-से-कम 90 days","कम-से-कम 6 months","कम-से-कम 3 years"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.4) कहती है कि दस-वर्ष की अवधि में out-of-service order के दो उल्लंघनों के लिए आप कम-से-कम एक वर्ष के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.4।"},"53":{"q":"दस-वर्ष की अवधि के भीतर तीन या अधिक out-of-service order उल्लंघनों का परिणाम इंडियाना में क्या न्यूनतम अयोग्यता है?","options":["कम-से-कम 3 years","कम-से-कम 1 year","कम-से-कम 5 years","जीवनभर"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.4) कहती है कि दस-वर्ष की अवधि में out-of-service order के तीन या अधिक उल्लंघनों के लिए आप कम-से-कम तीन वर्षों के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.4।"},"54":{"q":"इंडियाना में पहले railroad-highway grade crossing उल्लंघन के लिए न्यूनतम अयोग्यता क्या है?","options":["कम-से-कम 60 days","कम-से-कम 30 days","कम-से-कम 90 days","कम-से-कम 120 days"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.5) कहती है कि आपके पहले railroad-highway grade crossing उल्लंघन के लिए आप कम-से-कम 60 days के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.5।"},"55":{"q":"तीन-वर्ष की अवधि के भीतर दूसरा railroad-highway grade crossing उल्लंघन इंडियाना में क्या न्यूनतम अयोग्यता रखता है?","options":["कम-से-कम 120 days","कम-से-कम 60 days","कम-से-कम 90 days","कम-से-कम 1 year"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.5) कहती है कि तीन-वर्ष की अवधि के भीतर दूसरे railroad-highway grade crossing उल्लंघन के लिए आप कम-से-कम 120 days के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.5।"},"56":{"q":"तीन-वर्ष की अवधि के भीतर तीसरा railroad-highway grade crossing उल्लंघन इंडियाना में क्या न्यूनतम अयोग्यता रखता है?","options":["कम-से-कम 1 year","कम-से-कम 120 days","कम-से-कम 6 months","कम-से-कम 3 years"],"explanation":"Indiana BMV CDL Manual (Sec. 1.3.5) कहती है कि तीन-वर्ष की अवधि के भीतर तीसरे railroad-highway grade crossing उल्लंघन के लिए आप कम-से-कम एक वर्ष के लिए अपना CDL खो देंगे। स्रोत: Indiana BMV CDL Manual, Sec. 1.3.5।"},"57":{"q":"इंडियाना के नियमों के तहत, CMV चलाते समय texting करने संबंधी किसी राज्य कानून की कितनी दोषसिद्धियों के बाद CDL अयोग्य हो जाता है, और दूसरे अपराध पर कितने समय के लिए?","options":["दो या अधिक दोषसिद्धियाँ; 3 साल के भीतर दूसरे अपराध के लिए 60 days","एक दोषसिद्धि; तत्काल 120 days","दो दोषसिद्धियाँ; दूसरे अपराध के लिए 1 year","तीन दोषसिद्धियाँ; तीसरे अपराध के लिए 30 days"],"explanation":"Indiana BMV CDL Manual (Sec. 2.9.5) कहती है कि CMV संचालित करते समय किसी राज्य के texting कानून की दो या अधिक दोषसिद्धियों के बाद आपका CDL अयोग्य हो जाएगा, जिसमें 3 साल के भीतर दूसरे अपराध के लिए 60 days की अयोग्यता होती है (3 साल के भीतर तीन या अधिक के लिए 120 days)। स्रोत: Indiana BMV CDL Manual, Sec. 2.9.5।"},"58":{"q":"Indiana CDL Manual के अनुसार, hand-held मोबाइल फोन या texting प्रतिबंध का उल्लंघन करने वाला CMV चालक अधिकतम कितनी राशि के सिविल जुर्माने के अधीन होता है?","options":["$2,750","$1,000","$5,000","$11,000"],"explanation":"Indiana BMV CDL Manual (Secs. 2.9.4-2.9.5) कहती है कि hand-held फोन या texting निषेध का प्रत्येक उल्लंघन चालक को $2,750 तक के सिविल जुर्माने के अधीन करता है; नियोक्ता $11,000 तक के जुर्माने के अधीन हो सकते हैं। स्रोत: Indiana BMV CDL Manual, Secs. 2.9.4 and 2.9.5।"},"59":{"q":"ग्रामीण इंडियाना इंटरस्टेट (शहरी क्षेत्र के बाहर) पर, 26,000 पाउंड से अधिक घोषित सकल वजन वाले लदे हुए ट्रैक्टर-ट्रेलर के लिए अधिकतम गति सीमा क्या है?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"IC 9-21-5-2 के अंतर्गत, बस के अलावा 26,000 पाउंड से अधिक घोषित सकल वजन वाला वाहन ग्रामीण इंटरस्टेट राजमार्गों पर 65 mph तक सीमित है, जबकि यात्री कारें 70 mph चल सकती हैं। यही इंडियाना के विभाजित (ट्रक बनाम कार) इंटरस्टेट गति संकेतों का आधार है।"},"60":{"q":"एक यात्री कार ग्रामीण इंडियाना इंटरस्टेट पर 70 mph चला सकती है। उसी स्थान पर, यात्रियों को ले जाने वाली चार्टर बस कानूनी रूप से अधिकतम कितनी गति से चल सकती है:","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"IC 9-21-5-2, 26,000 lbs से अधिक 'बस के अलावा' वाहनों पर 65 mph की ट्रक सीमा लागू करता है। बसें घटी हुई ट्रक सीमा के अधीन नहीं हैं, इसलिए एक बस ग्रामीण इंटरस्टेट पर पोस्ट किए गए 70 mph पर चल सकती है। स्रोत: Indiana Code 9-21-5-2।"},"61":{"q":"आप एक इंडियाना राजमार्ग पर प्लेकार्ड लगे खतरनाक-सामग्री टैंकर को चला रहे हैं। एक रेलमार्ग ग्रेड क्रॉसिंग पर जहां रुकना आवश्यक है, आपको रुकना चाहिए:","options":["निकटतम रेल से 15 फीट से अधिक निकट नहीं और 50 फीट से अधिक दूर नहीं","निकटतम रेल से 10 फीट से अधिक निकट नहीं और 25 फीट से अधिक दूर नहीं","निकटतम रेल से ठीक 50 फीट","निकटतम रेल से 50 फीट से अधिक निकट नहीं और 100 फीट से अधिक दूर नहीं"],"explanation":"इंडियाना CDL मैनुअल (खंड 9.6.12) के अनुसार प्लेकार्ड लगे वाहनों, क्लोरीन वाहकों और कार्गो-टैंक वाहनों को निकटतम रेल से 15 से 50 फीट दूर रुकना चाहिए, फिर तभी आगे बढ़ना चाहिए जब यह सुनिश्चित हो जाए कि कोई ट्रेन नहीं आ रही है। स्रोत: इंडियाना CDL मैनुअल।"},"62":{"q":"इंडियाना का Move Over कानून (IC 9-21-8-35) आपको चमकती लाइटों वाले रुके हुए आपातकालीन या खराब वाहन से दूर लेन बदलने की आवश्यकता रखता है। यदि आप सुरक्षित रूप से लेन नहीं बदल सकते, तो आपको चाहिए:","options":["अपनी गति को पोस्ट की गई गति सीमा से 10 mph कम करना","सुरक्षित रूप से आगे बढ़ने तक पूरी तरह रुकना","अपना हॉर्न बजाना और पोस्ट की गई गति बनाए रखना","अपनी गति को पोस्ट की गई गति सीमा से 20 mph कम करना"],"explanation":"IC 9-21-8-35 के अंतर्गत, जब लेन बदलना संभव या सुरक्षित न हो, तो चालक को गुजरते समय पोस्ट की गई गति सीमा से कम से कम 10 mph धीमा होना चाहिए। INDOT इसे 'Move Over or Slow Down' के रूप में बढ़ावा देता है। स्रोत: IC 9-21-8-35; INDOT।"},"63":{"q":"आपकी यात्रा की दिशा में दो लेन वाले एक इंडियाना इंटरस्टेट पर, एक ट्रक-ट्रैक्टर आम तौर पर किस लेन तक सीमित होता है, सिवाय जब ओवरटेक करते समय, प्रवेश/निकास करते समय, या किसी विशेष खतरे से बचते समय?","options":["कोई भी लेन, स्वतंत्र रूप से","बाईं (ओवरटेकिंग) लेन","सबसे दाईं लेन","सड़क का केंद्र"],"explanation":"IC 9-21-8-12, इंटरस्टेट राजमार्ग पर सबसे दाईं लेन के अलावा किसी भी लेन में ट्रक या ट्रक-ट्रैक्टर चलाने पर रोक लगाता है, सिवाय जब किसी धीमे वाहन को ओवरटेक करते समय, राजमार्ग में प्रवेश या निकास करते समय, या जहां किसी विशेष खतरे के लिए अन्य लेन आवश्यक हो। स्रोत: Indiana Code 9-21-8-12।"},"64":{"q":"आपकी यात्रा की दिशा में तीन या अधिक लेन वाले एक इंडियाना इंटरस्टेट पर, एक ट्रक-ट्रैक्टर किस तक सीमित होता है:","options":["केवल सबसे दाईं लेन","केवल दो दाईं लेन","सबसे बाईं को छोड़कर कोई भी लेन","केवल केंद्र लेन"],"explanation":"IC 9-21-8-13, एक दिशा में कम से कम तीन लेन वाले इंटरस्टेट पर ट्रकों को दो सबसे दाईं लेन तक सीमित करता है, सिवाय जब राजमार्ग में प्रवेश या निकास करते समय या किसी विशेष खतरे से बचते समय। यह दो-लेन वाले हिस्सों के लिए एकल-लेन नियम से अधिक अनुमेय है। स्रोत: Indiana Code 9-21-8-13।"},"65":{"q":"इंडियाना में, एक चालक जो अपने विस्तारित स्टॉप आर्म और चमकती लाल लाइटें दिखाने वाली रुकी हुई स्कूल बस से मिलता है या उसे ओवरटेक करता है, उसे रुकना चाहिए और तब तक रुका रहना चाहिए जब तक:","options":["बस चालक उन्हें आगे जाने का इशारा न करे","पांच सेकंड न बीत जाएं","स्टॉप आर्म वापस न ले लिया जाए और लाल लाइटें चमकना बंद न कर दें","वे दस तक न गिन लें"],"explanation":"IC 9-21-12-1 के अंतर्गत, जब आर्म सिग्नल डिवाइस विस्तारित हो तो चालक को बस तक पहुंचने से पहले रुकना चाहिए और तब तक आगे नहीं बढ़ सकता जब तक डिवाइस अब विस्तारित न हो (लाइटें चमकना बंद कर दें)। उल्लंघन एक Class A infraction है। स्रोत: Indiana Code 9-21-12-1।"},"66":{"q":"आप एक रुकी हुई स्कूल बस (लाल लाइटें चमकती हुई) की ओर ड्राइव कर रहे हैं जो चार-लेन वाली सड़क के दूसरी ओर है। इंडियाना के स्कूल-बस कानून के अंतर्गत, आपको रुकने की आवश्यकता केवल तभी नहीं है जब दोनों सड़कें किससे अलग की गई हों:","options":["एक चित्रित केंद्र रेखा या दो-तरफा बाएं-मोड़ लेन","कोई भी चार या अधिक फुटपाथ लेन","कम से कम 4 फीट चौड़ा एक समतल चित्रित मध्यवर्ती","एक भौतिक अवरोध या यात्रा के लिए न बनाया गया अविकसित/विभाजक मध्यवर्ती"],"explanation":"IC 9-21-12-3 एक निकट आने वाले चालक को रुकने से केवल तभी मुक्त करता है जब सड़कें एक अविकसित मध्यवर्ती स्थान, एक भौतिक अवरोध, या यातायात को बाधित करने के लिए बनाए गए एक विभाजक खंड द्वारा विभाजित हों, और बस विपरीत दिशा में हो। केवल एक चित्रित रेखा योग्य नहीं है—आपको फिर भी रुकना होगा। स्रोत: Indiana Code 9-21-12-3।"},"67":{"q":"यदि आपको अपने CMV को एक विभाजित इंडियाना राजमार्ग के किनारे पर रोकना पड़े, तो आपको अपने आपातकालीन चेतावनी उपकरण कितनी जल्दी रखने होंगे?","options":["2 मिनट के भीतर","5 मिनट के भीतर","10 मिनट के भीतर","तुरंत, केबिन से बाहर निकलने से पहले"],"explanation":"इंडियाना CDL मैनुअल (खंड 2.5) में कहा गया है कि यदि आप सड़क या किनारे पर रुकते हैं तो आपको 10 मिनट के भीतर आपातकालीन चेतावनी उपकरण बाहर रखने होंगे। स्रोत: इंडियाना CDL मैनुअल।"},"68":{"q":"एक तरफा या विभाजित इंडियाना राजमार्ग पर रुकने पर, आप अपने तीन चेतावनी त्रिकोण कहां रखते हैं?","options":["निकट आने वाले यातायात की ओर 10 फीट, 100 फीट, और 200 फीट","निकट आने वाले यातायात की ओर 10 फीट, 50 फीट, और 100 फीट","100 फीट आगे, 100 फीट पीछे, और वाहन पर","केवल वाहन पर, चार-तरफा फ्लैशर्स चालू रखते हुए"],"explanation":"इंडियाना CDL मैनुअल निर्देश देता है कि एक तरफा या विभाजित राजमार्ग पर, चेतावनी उपकरण निकट आने वाले यातायात की ओर 10 फीट, 100 फीट, और 200 फीट पर रखे जाते हैं। स्रोत: इंडियाना CDL मैनुअल, खंड 2.5।"},"69":{"q":"दोनों दिशाओं में यातायात ले जाने वाली दो-लेन वाली इंडियाना सड़क पर रुकने पर, आपके चेतावनी त्रिकोण रखे जाने चाहिए:","options":["केवल वाहन के पीछे 10 फीट, 100 फीट, और 200 फीट पर","केवल 50 फीट आगे और 50 फीट पीछे","केवल 200 फीट आगे और 200 फीट पीछे","वाहन के 10 फीट के भीतर, और 100 फीट आगे और 100 फीट पीछे"],"explanation":"एक अविभाजित दो-तरफा सड़क पर, इंडियाना CDL मैनुअल वाहन को चिह्नित करने के लिए आगे या पीछे के कोने के 10 फीट के भीतर एक त्रिकोण, साथ ही एक 100 फीट आगे और एक 100 फीट पीछे, किनारे पर या लेन में रखने की आवश्यकता रखता है। स्रोत: इंडियाना CDL मैनुअल, खंड 2.5।"},"70":{"q":"दोनों दिशाओं में यातायात ले जाने वाली दो-लेन वाली इंडियाना सड़क पर रुकने पर, आपके चेतावनी त्रिकोण रखे जाने चाहिए:","options":["केवल वाहन के पीछे 10 फीट, 100 फीट, और 200 फीट पर","केवल 50 फीट आगे और 50 फीट पीछे","केवल 200 फीट आगे और 200 फीट पीछे","वाहन के 10 फीट के भीतर, और 100 फीट आगे और 100 फीट पीछे"],"explanation":"एक अविभाजित दो-तरफा सड़क पर, इंडियाना CDL मैनुअल वाहन को चिह्नित करने के लिए आगे या पीछे के कोने के 10 फीट के भीतर एक त्रिकोण, साथ ही एक 100 फीट आगे और एक 100 फीट पीछे, किनारे पर या लेन में रखने की आवश्यकता रखता है। स्रोत: इंडियाना CDL मैनुअल, खंड 2.5।"},"71":{"q":"इंडियाना में आपके द्वारा चलाई जा रही एक स्कूल बस एक रेलमार्ग ग्रेड क्रॉसिंग के पास आती है। आपको अपनी बस को रोकना चाहिए:","options":["क्रॉसिंग से 15 और 50 फीट के बीच","रेल से 5 फीट से अधिक निकट नहीं","रेल से ठीक 25 फीट","केवल यदि कोई ट्रेन दिखाई दे"],"explanation":"इंडियाना CDL मैनुअल (खंड 4.3.5) बस चालकों को रेलमार्ग क्रॉसिंग से 15 और 50 फीट के बीच बस को रोकने का निर्देश देता है, फिर आगे बढ़ने से पहले दोनों दिशाओं में देखें और सुनें। स्रोत: इंडियाना CDL मैनुअल।"},"72":{"q":"इंडियाना के संशोधित Move Over कानून के अंतर्गत, एक चालक जो चमकती लाइटों वाले रुके हुए वाहन के लिए लेन नहीं बदलता या धीमा नहीं होता (बिना किसी परिणामी चोट के), वह क्या करता है:","options":["Class A infraction","Class B infraction","Class C infraction","Class D felony"],"explanation":"IC 9-21-8-35 का एक बुनियादी उल्लंघन एक Class B infraction है; यह केवल तभी एक felony बन जाता है जब विफलता किसी कवर किए गए कर्मचारी को गंभीर शारीरिक चोट या मृत्यु का कारण बनती है। स्रोत: IC 9-21-8-35; INDOT।"},"73":{"q":"Indiana Department of Revenue/INDOT से ओवरसाइज़ परमिट के बिना, इंडियाना राजमार्गों पर एक वाणिज्यिक लोड के लिए अधिकतम कानूनी चौड़ाई है:","options":["8 फीट 0 इंच","8 फीट 6 इंच","10 फीट 0 इंच","9 फीट 0 इंच"],"explanation":"इंडियाना की कानूनी (गैर-परमिट) अधिकतम चौड़ाई 8 फीट 6 इंच (102 inches) है। इससे अधिक के लोड के लिए Indiana DOR Motor Carrier Services के माध्यम से एक ओवरसाइज़/ओवरवेट परमिट की आवश्यकता होती है। स्रोत: INDOT / Indiana DOR OSOW विनियम।"},"74":{"q":"इंडियाना में ओवरसाइज़ परमिट के बिना, एक वाहन और लोड के लिए अधिकतम कानूनी ऊंचाई है:","options":["13 फीट 0 इंच","13 फीट 6 इंच","14 फीट 0 इंच","12 फीट 6 इंच"],"explanation":"इंडियाना की कानूनी अधिकतम ऊंचाई 13 फीट 6 इंच है; इससे अधिक ऊंची किसी भी चीज़ के लिए एक ओवरसाइज़ परमिट की आवश्यकता होती है। चालकों को फिर भी क्लीयरेंस सत्यापित करनी चाहिए, क्योंकि पोस्ट की गई पुल ऊंचाइयां शासित होती हैं। स्रोत: INDOT / Indiana DOR OSOW विनियम।"},"75":{"q":"ओवरवेट परमिट के बिना, इंडियाना राजमार्गों पर एक मानक रिग के लिए अधिकतम कानूनी सकल वाहन वजन है:","options":["73,280 pounds","90,000 pounds","100,000 pounds","80,000 pounds"],"explanation":"इंडियाना का कानूनी अधिकतम सकल वाहन वजन 80,000 pounds है (संघीय इंटरस्टेट सीमा के अनुरूप)। भारी लोड के लिए Indiana DOR Motor Carrier Services से एक ओवरवेट परमिट की आवश्यकता होती है। स्रोत: INDOT / Indiana DOR OSOW विनियम।"},"76":{"q":"एक बहु-लेन वाले इंडियाना राजमार्ग पर, यातायात के सामान्य प्रवाह से धीमी गति से चलने वाले CMV को इंडियाना कानून द्वारा क्या करने की आवश्यकता होती है:","options":["मर्ज ट्रैफ़िक से बाहर रहने के लिए सबसे बाईं लेन का उपयोग करें","हर समय केंद्र लेन में चलें","किसी भी लेन में कम से कम पोस्ट किए गए न्यूनतम को बनाए रखें","यात्रा के लिए उपलब्ध दाईं ओर की लेन का उपयोग करें"],"explanation":"IC 9-21-5-9, स्थापित अधिकतम गति से धीमी गति से चलने वाले वाहनों को दाईं ओर की लेन का उपयोग करने की आवश्यकता रखता है, और ओवरटेक किए जाने पर सबसे बाईं लेन में जारी रहने पर रोक लगाता है। स्रोत: Indiana Code 9-21-5-9।"},"77":{"q":"एक ग्रामीण इंडियाना क्षेत्र में एक स्कूल बस अपनी वैकल्पिक रूप से चमकती AMBER लाइटें सक्रिय करती है। इन लाइटों का अर्थ है:","options":["बस खराब हो गई है—सावधानी से गुजरें","बच्चे पार कर रहे हैं—तुरंत रुकें","बस रेलमार्ग स्टॉप से मुक्त है","बस लोड या अनलोड करने के लिए रुकने की तैयारी कर रही है; रुकने के लिए तैयार रहें"],"explanation":"Amber (पीली) लाइटें एक पूर्व-चेतावनी हैं कि बस लोड या अनलोड करने के लिए रुकने वाली है, ग्रामीण क्षेत्रों में लगभग 300 फीट आगे सक्रिय होती हैं; फिर लाल लाइटें और विस्तारित स्टॉप आर्म यातायात को रुकने की आवश्यकता रखते हैं। स्रोत: इंडियाना CDL मैनुअल / INDOT स्कूल बस सुरक्षा।"},"78":{"q":"एक पुलिस अधिकारी एक इंडियाना रेलमार्ग ग्रेड क्रॉसिंग पर यातायात निर्देशित कर रहा है और आपके प्लेकार्ड लगे वाहन को बिना रुके आगे बढ़ने का संकेत देता है। आपको चाहिए:","options":["अधिकारी की अनदेखी करते हुए वैसे भी 15 से 50 फीट रुकें","केवल यदि आप कोई ट्रेन देखें तो रुकें","अधिकारी के निर्देश का पालन करें और अनिवार्य स्टॉप के बिना आगे बढ़ें","पीछे जाएं और दूसरा क्रॉसिंग खोजें"],"explanation":"प्लेकार्ड लगे और यात्री वाहनों के लिए अनिवार्य 15-से-50-फीट स्टॉप तब लागू नहीं होता जब कोई पुलिस अधिकारी या फ्लैगमैन यातायात को आगे बढ़ने का निर्देश देता है (49 CFR 392.10 के तहत भी मान्यता प्राप्त, इंडियाना में लागू)। स्रोत: इंडियाना CDL मैनुअल; 49 CFR 392.10।"},"79":{"q":"इंडियाना में Commercial Driver's Licenses (CDLs) कौन सी एजेंसी जारी करती है?","options":["Indiana Bureau of Motor Vehicles (BMV)","Indiana Department of Transportation (INDOT)","Federal Motor Carrier Safety Administration (FMCSA)","Indiana State Police Commercial Vehicle Division"],"explanation":"इंडियाना में CDLs, Indiana Bureau of Motor Vehicles (BMV) द्वारा जारी किए जाते हैं। CDL मैनुअल और सभी लाइसेंसिंग लेनदेन BMV शाखाओं पर संभाले जाते हैं। स्रोत: Indiana Specific CDL Applicant Information manual (SP 283), Indiana BMV।"},"80":{"q":"इंडियाना में, एक Commercial Learner's Permit (CLP) कितने समय तक वैध रहता है?","options":["एक वर्ष","180 days","दो वर्ष","छह महीने, अनिश्चित काल तक नवीकरणीय"],"explanation":"वर्तमान इंडियाना CDL मैनुअल के अनुसार, 'एक CLP एक वर्ष के लिए वैध होता है।' स्रोत: Indiana Specific CDL Applicant Information manual (SP 283), Commercial Learner's Permit अनुभाग, Indiana BMV।"},"81":{"q":"इंडियाना में CDL कौशल परीक्षण का प्रयास करने से पहले एक आवेदक को CLP कितने समय तक रखना चाहिए?","options":["कम से कम 14 days","कम से कम 30 days","कम से कम 10 days","कम से कम 60 days"],"explanation":"मैनुअल में कहा गया है, 'एक आवेदक को CDL कौशल परीक्षण का प्रयास करने से पहले CLP को 14 days रखना चाहिए।' यह संघीय न्यूनतम को प्रतिबिंबित करता है और इंडियाना में लागू होता है। स्रोत: Indiana CDL manual (SP 283), CDL Skills Testing अनुभाग, Indiana BMV।"},"82":{"q":"इंडियाना में जारी एक CDL को नवीनीकृत किए जाने से पहले कितने समय तक वैध रहता है?","options":["चार वर्ष","पांच वर्ष","छह वर्ष","तीन वर्ष"],"explanation":"इंडियाना में जारी एक CDL चार वर्ष के लिए वैध होता है। आप इसके समाप्त होने से एक वर्ष पहले तक किसी भी BMV शाखा पर नवीनीकरण कर सकते हैं। स्रोत: Indiana BMV, Renewing or Replacing a CDL।"},"83":{"q":"इंडियाना CDL कौशल परीक्षा किन तीन भागों से बनी है?","options":["वाहन (प्री-ट्रिप) निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","एयर ब्रेक टेस्ट, कॉम्बिनेशन टेस्ट, और सड़क पर ड्राइविंग","सामान्य ज्ञान परीक्षण, बुनियादी नियंत्रण, और प्री-ट्रिप निरीक्षण","प्री-ट्रिप निरीक्षण, लिखित एंडोर्समेंट टेस्ट, और सड़क पर ड्राइविंग"],"explanation":"इंडियाना के CDL कौशल परीक्षण के तीन भाग होते हैं: Vehicle Inspection Test (Section 11), Basic Vehicle Control Skills Test (Section 12), और On-road Driving (Section 13)। स्रोत: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV।"},"84":{"q":"इंडियाना में पहला Class A या Class B CDL प्राप्त करने से पहले, एक आवेदक को कौन सा संघीय रूप से आवश्यक प्रशिक्षण पूरा करना चाहिए?","options":["FMCSA-पंजीकृत प्रदाता के माध्यम से Entry-Level Driver Training (ELDT)","एक BMV शाखा पर एक राज्य-संचालित रक्षात्मक ड्राइविंग पाठ्यक्रम","INDOT द्वारा सत्यापित 160-घंटे की इंडियाना अप्रेंटिसशिप","एक OSHA खतरनाक-कार्गो प्रमाणन"],"explanation":"आवेदकों को CDL प्राप्त करने से पहले FMCSA Training Provider Registry पर सूचीबद्ध प्रदाता के साथ Entry-Level Driver Training (ELDT) पूरा करना चाहिए। स्रोत: Indiana CDL manual (SP 283); 49 CFR Part 380; Feb 7, 2022 से प्रभावी।"},"85":{"q":"एक इंडियाना CLP या CDL के लिए आवश्यक चिकित्सा परीक्षा किसे करनी चाहिए?","options":["FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध एक चिकित्सा परीक्षक","आवेदक की पसंद का कोई भी लाइसेंस प्राप्त इंडियाना चिकित्सक","सीधे Indiana BMV द्वारा नियोजित एक चिकित्सक","INDOT के परमिट कार्यालय द्वारा अनुमोदित एक चिकित्सा परीक्षक"],"explanation":"सभी चिकित्सा परीक्षाएं FMCSA National Registry of Certified Medical Examiners (nationalregistry.fmcsa.dot.gov) पर प्रमाणित एक चिकित्सा परीक्षक द्वारा पूरी की जानी चाहिए। स्रोत: Indiana CDL manual (SP 283), Medical Examiner Requirements, Indiana BMV।"},"86":{"q":"Medical Examiner's Certificate (MEC) Indiana BMV की प्रणाली में कैसे आता है?","options":["प्रमाणित परीक्षक MEC को FMCSA National Registry पर अपलोड करता है, जिससे यह BMV प्रणाली पर लागू हो जाता है","आवेदक कागज़ का कार्ड वॉशिंगटन, D.C. में FMCSA मुख्यालय को मेल करता है","INDOT एक रोडसाइड निरीक्षण के बाद प्रमाणपत्र को BMV को अग्रेषित करता है","आवेदक के कौशल परीक्षण पास करने पर प्रमाणपत्र स्वचालित रूप से उत्पन्न होता है"],"explanation":"मैनुअल CLP/CDL धारकों को निर्देश देता है कि प्रमाणित चिकित्सक से MEC को National Registry पर अपलोड करवाएं ताकि यह BMV प्रणाली पर लागू हो। स्रोत: Indiana CDL manual (SP 283), Medical Examiner Requirements and Certification, Indiana BMV।"},"87":{"q":"एक इंडियाना CDL/CLP आवेदक को उस प्रकार की ड्राइविंग की घोषणा करते समय कितनी स्व-प्रमाणन श्रेणियों में से चुनना चाहिए जो वे करेंगे?","options":["चार","दो","तीन","पांच"],"explanation":"आवेदक चार श्रेणियों में से एक के लिए स्व-प्रमाणन करते हैं: non-excepted interstate, excepted interstate, non-excepted intrastate, या excepted intrastate। स्रोत: 49 CFR 383.71 (Indiana BMV द्वारा लागू); Indiana BMV स्व-प्रमाणन।"},"88":{"q":"कौन सी स्व-प्रमाणन श्रेणी एक ऐसे चालक का वर्णन करती है जो राज्य की सीमाओं के पार संचालन करता है और जिसे संघीय चिकित्सा/शारीरिक योग्यता आवश्यकताओं को पूरा करना चाहिए?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"Non-excepted interstate चालक अंतरराज्यीय वाणिज्य में संचालन करते हैं और उन्हें 49 CFR Part 391 की चिकित्सा आवश्यकताओं को पूरा करना चाहिए, एक वैध MEC फ़ाइल में रखते हुए। स्रोत: 49 CFR 383.71 / 391.41 (Indiana BMV द्वारा लागू)।"},"89":{"q":"इंडियाना नियमों के अंतर्गत, एक आवेदक कितनी बार CDL ज्ञान परीक्षण का प्रयास कर सकता है?","options":["प्रति दिन एक बार; एक असफल परीक्षण अगले व्यावसायिक दिन फिर से लिया जा सकता है","पास होने तक प्रति दिन तीन बार","प्रति सप्ताह एक बार, केवल अपॉइंटमेंट द्वारा","एक ही दिन में असीमित बार"],"explanation":"मैनुअल में कहा गया है कि एक आवेदक एक दिन में केवल एक बार CDL ज्ञान परीक्षण का प्रयास कर सकता है, और एक असफलता के बाद इसे अगले व्यावसायिक दिन फिर से ले सकता है। स्रोत: Indiana CDL manual (SP 283), CDL Knowledge Tests, Indiana BMV।"},"90":{"q":"एक बार पास हो जाने के बाद, इंडियाना CDL ज्ञान परीक्षण परिणाम और कौशल परीक्षण परिणाम कितने समय तक वैध रहते हैं?","options":["एक वर्ष","छह महीने","दो वर्ष","90 days"],"explanation":"मैनुअल में कहा गया है कि CDL ज्ञान परीक्षण परिणाम एक वर्ष के लिए वैध होते हैं और CDL कौशल परीक्षण परिणाम एक वर्ष के लिए वैध होते हैं। स्रोत: Indiana CDL manual (SP 283), CDL Knowledge Tests and CDL Skills Testing, Indiana BMV।"},"91":{"q":"एक आवेदक को इंडियाना CDL कौशल परीक्षण कहां लेना चाहिए?","options":["एक BMV-अनुमोदित (तृतीय-पक्ष अधिकृत) CDL कौशल परीक्षण साइट पर","किसी भी पूर्ण-सेवा BMV लाइसेंस शाखा काउंटर पर","एक INDOT वजन स्टेशन या प्रवेश बंदरगाह पर","FMCSA क्षेत्रीय फील्ड कार्यालय पर"],"explanation":"CDL कौशल परीक्षण एक BMV-अनुमोदित CDL कौशल परीक्षण साइट (अधिकृत तृतीय-पक्ष साइटें) पर लिया जाना चाहिए; परिणाम इलेक्ट्रॉनिक रूप से BMV को प्रेषित किए जाते हैं। स्रोत: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV।"},"92":{"q":"अंतरराज्यीय वाणिज्य में संचालन के लिए (और स्कूल बस या अंतरराज्यीय नहीं) एक इंडियाना CDL/CLP प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","19 वर्ष","16 वर्ष"],"explanation":"एक आवेदक की आयु कम से कम 18 वर्ष होनी चाहिए; अंतरराज्यीय वाणिज्य में संचालन करने या एक स्कूल बस एंडोर्समेंट के लिए आवेदन करने के लिए आवेदक की आयु कम से कम 21 वर्ष होनी चाहिए। स्रोत: Indiana CDL manual (SP 283), CLP requirements, Indiana BMV।"},"93":{"q":"इंडियाना में CDL कौशल परीक्षण पास करने के बाद, वास्तव में CDL प्राप्त करने के लिए आवेदक को क्या करना चाहिए?","options":["CLP समाप्त होने से पहले आवेदन पूरा करने के लिए एक BMV लाइसेंस शाखा पर लौटें","FMCSA से डाक द्वारा लाइसेंस आने की प्रतीक्षा करें","INDOT पर दूसरा सड़क-पर परीक्षण निर्धारित करें","परीक्षण साइट पर सामान्य ज्ञान परीक्षण फिर से लें"],"explanation":"मैनुअल में कहा गया है कि कौशल परीक्षण पास करने के बाद आवेदक को CDL आवेदन पूरा करने के लिए एक BMV लाइसेंस शाखा पर लौटना चाहिए, और ऐसा CLP की समाप्ति से पहले करना चाहिए। स्रोत: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV।"},"94":{"q":"एक इंडियाना CDL कौशल परीक्षण अपॉइंटमेंट परीक्षण साइट के साथ कितने समय पहले निर्धारित किया जाना चाहिए?","options":["कम से कम दो दिन पहले","कम से कम दो सप्ताह पहले","कम से कम एक दिन पहले","कम से कम 30 days पहले"],"explanation":"मैनुअल में कहा गया है कि अपॉइंटमेंट कम से कम दो दिन पहले निर्धारित किए जाने चाहिए, और कौशल परीक्षण एक व्यावसायिक दिन में केवल एक बार लिया जा सकता है। स्रोत: Indiana CDL manual (SP 283), CDL Skills Testing, Indiana BMV।"},"95":{"q":"इंडियाना में, यदि एक CDL तीन वर्ष से अधिक समय के लिए समाप्त, अयोग्य, रद्द, निरस्त, निलंबित, या अमान्य हो गया हो तो क्या होता है?","options":["आवेदक को एक पहली बार के आवेदक के रूप में सभी लागू ज्ञान और कौशल परीक्षण पास करने होंगे","आवेदक केवल एक दृष्टि स्क्रीनिंग के साथ ऑनलाइन नवीनीकरण कर सकता है","एक लिखित परीक्षण के बाद CDL स्वचालित रूप से बहाल हो जाता है","आवेदक को केवल सड़क-पर ड्राइविंग परीक्षण फिर से लेने की आवश्यकता है"],"explanation":"मैनुअल की Retesting Requirement में कहा गया है कि किसी भी आवेदक जिसका CDL तीन वर्ष से अधिक समय के लिए समाप्त, समर्पित, अयोग्य, रद्द, निरस्त, निलंबित, या अमान्य हो गया हो, उसे एक पहली बार के आवेदक के रूप में सभी लागू ज्ञान और कौशल परीक्षण पास करने होंगे। स्रोत: Indiana CDL manual (SP 283), Indiana BMV।"},"96":{"q":"एक वैध आउट-ऑफ-स्टेट CDL वाले एक नए निवासी के पास इसे इंडियाना CDL में स्थानांतरित करने के लिए कितना समय है?","options":["30 days","60 days","90 days","10 days"],"explanation":"मैनुअल में कहा गया है कि व्यक्तियों के पास एक आउट-ऑफ-स्टेट CDL स्थानांतरित करने के लिए 30 days हैं; ड्राइवर लाइसेंस ज्ञान परीक्षा केवल तभी आवश्यक है जब आउट-ऑफ-स्टेट CDL समाप्त हो गया हो। स्रोत: Indiana CDL manual (SP 283), Transfer an Out-of-Country or Out-of-State CDL, Indiana BMV।"},"97":{"q":"इंडियाना में Hazardous Materials (H) एंडोर्समेंट प्रक्रिया के बारे में कौन सा कथन सही है?","options":["इसके लिए TSA security threat assessment अनुमोदन की आवश्यकता है और यह CLP में नहीं जोड़ा जाता","एयर ब्रेक टेस्ट पास होने पर इसे CLP में जोड़ा जा सकता है","इसके लिए केवल सामान्य ज्ञान परीक्षण पास करना आवश्यक है","यह किसी भी Class A CDL के साथ स्वचालित रूप से जारी किया जाता है"],"explanation":"मैनुअल में कहा गया है कि एक HazMat एंडोर्समेंट के लिए CDL की अवधि के लिए TSA security threat assessment अनुमोदन की आवश्यकता होती है, और यह कि इसे CLP में नहीं जोड़ा जाएगा। स्रोत: Indiana CDL manual (SP 283), CDL Endorsements, Indiana BMV; 49 CFR 1572 (TSA)।"},"98":{"q":"ज्ञान और कौशल परीक्षण पास करने के अलावा, लाइसेंसिंग प्रक्रिया के दौरान प्रत्येक इंडियाना CDL आवेदक से विशेष रूप से कौन सा चरण आवश्यक है?","options":["मानव तस्करी को पहचानने, रोकने और रिपोर्ट करने के तरीके पर एक निर्देशात्मक वीडियो देखें","एक राज्य ट्रूपर के साथ एक 40-घंटे की राइड-अलॉन्ग पूरी करें","एक INDOT ओवरसाइज़/ओवरवेट परमिट परीक्षा पास करें","परीक्षण से पहले नोटरीकृत नियोक्ता प्रायोजन प्राप्त करें"],"explanation":"इंडियाना के लिए आवश्यक है कि CDL आवेदक ELDT पूरा करने और आवश्यक परीक्षण पास करने के अलावा, मानव तस्करी को पहचानने, रोकने और रिपोर्ट करने के तरीके पर एक निर्देशात्मक वीडियो देखें। स्रोत: Indiana CDL manual (SP 283), application requirements, Indiana BMV।"}},"ar":{"0":{"q":"على الطرق السريعة في ولاية إنديانا، ما هو الحد الأقصى القانوني لعرض المركبة وحمولتها (باستثناء الأجهزة المستثناة من احتساب العرض مثل المرايا)؟","options":["8 أقدام و0 بوصة","9 أقدام و0 بوصة","8 أقدام و6 بوصات","10 أقدام و0 بوصة"],"explanation":"تحدّ إنديانا عرض المركبة والحمولة عند 8 أقدام و6 بوصات (102 inches)، باستثناء أجهزة السلامة المستثناة من احتساب العرض وفقاً للائحة 23 CFR 658. المصدر: قانون إنديانا IC 9-20-3-2؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا (الباب 9، المادة 20)."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة، بما في ذلك حمولتها، على الطرق السريعة في إنديانا؟","options":["13 قدماً و0 بوصة","14 قدماً و0 بوصة","13 قدماً و6 بوصات","12 قدماً و6 بوصات"],"explanation":"تحدد إنديانا الحد الأقصى للارتفاع عند 13 قدماً و6 بوصات، ولا يوجد أي إعفاء من الارتفاع القانوني. المصدر: IC 9-20-3-3؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة أو المجموعة المسموح به بموجب قانون إنديانا دون تصريح الوزن الزائد؟","options":["73,280 رطلاً","80,000 رطل","88,000 رطل","84,000 رطل"],"explanation":"الحد الأقصى القانوني للوزن الإجمالي في إنديانا هو 80,000 رطل؛ وأي وزن أثقل من ذلك يتطلب تصريحاً. ينطبق الرقم البالغ 73,280 رطلاً فقط بموجب بند الحقوق المكتسبة لبعض التكوينات. المصدر: IC 9-20-4 (القيود العامة على الوزن)؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن."},"3":{"q":"ما هو الحد الأقصى للوزن الذي تسمح به إنديانا على المحور المفرد؟","options":["18,000 رطل","20,000 رطل","22,400 رطل","34,000 رطل"],"explanation":"الحد الأقصى لوزن المحور المفرد في إنديانا هو 20,000 رطل. (يظهر الرقمان 18,000 رطل و16,000 رطل فقط في سيناريوهات قانون الحقوق المكتسبة.) المصدر: IC 9-20-4؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"4":{"q":"ما هو الحد الأقصى للوزن الذي تسمح به إنديانا على مجموعة المحاور المزدوجة (الترادفية)؟","options":["34,000 رطل","32,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"الحد الأقصى لوزن المحور المزدوج (الترادفي) في إنديانا هو 34,000 رطل، وهو ما يطابق المعيار الفيدرالي. المصدر: IC 9-20-4؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"5":{"q":"تحدّ إنديانا وزن العجلة بكم لكل بوصة من عرض الإطار، مقاساً بين شفتي الجنط؟","options":["600 رطل","1,000 رطل","500 رطل","800 رطل"],"explanation":"تحدّ إنديانا وزن العجلة عند 800 رطل لكل بوصة من عرض الإطار مقاساً بين شفتي الجنط، سواء كانت محمّلة أو غير محمّلة. المصدر: IC 9-20-11-4؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"6":{"q":"ما هو الحد الأقصى لطول المركبة المفردة العاملة بقوتها الذاتية على الطرق السريعة في إنديانا (باستثناء الأجهزة المستثناة من احتساب الطول)؟","options":["40 قدماً","45 قدماً","35 قدماً","53 قدماً"],"explanation":"لا يجوز أن تتجاوز المركبة الآلية المفردة 40 قدماً، باستثناء الأجهزة المستثناة من احتساب الطول وفقاً للائحة 23 CFR 658.13. ويُسمح للمركبة الترفيهية بطول يصل إلى 45 قدماً. المصدر: IC 9-20-3-1 / IC 9-20-8؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن."},"7":{"q":"في مجموعة مكوّنة من جرار شاحنة ونصف مقطورة، ما هو الحد الأقصى لطول نصف المقطورة (بما في ذلك الحمولة) بموجب قانون إنديانا؟","options":["48 قدماً","57 قدماً","45 قدماً","53 قدماً"],"explanation":"تسمح إنديانا بنصف مقطورة بطول يصل إلى 53 قدماً في مجموعة جرار الشاحنة، ولا يُفرض أي حد إجمالي للطول على تلك المجموعة. المصدر: IC 9-20-8؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن."},"8":{"q":"أي جهة في إنديانا تصدر تصاريح الحجم الزائد والوزن الزائد (OSOW) للمركبات التي تتجاوز حدود الحجم والوزن القانونية؟","options":["Indiana Bureau of Motor Vehicles","إدارة الإيرادات في إنديانا، خدمات الناقلين الآليين (Indiana Department of Revenue, Motor Carrier Services)","شرطة ولاية إنديانا (Indiana State Police)","إدارة الموارد الطبيعية في إنديانا (Indiana Department of Natural Resources)"],"explanation":"تصدر تصاريح OSOW من قبل خدمات الناقلين الآليين التابعة لإدارة الإيرادات في إنديانا، بموجب القواعد التي تضعها INDOT وقانون إنديانا. المصدر: IC 9-20-6؛ برنامج OSOW لخدمات الناقلين الآليين بإدارة الإيرادات في إنديانا (in.gov/dor)."},"9":{"q":"في أي عام اعتمدت إنديانا معادلة الجسور الفيدرالية في قانون الولاية لحساب الحد الأقصى القانوني للوزن الإجمالي ووزن المحاور؟","options":["1975","1956","1982","1991"],"explanation":"اعتمدت إنديانا معادلة الجسور كقانون للولاية في عام 1975، وتحتفظ ببند الحقوق المكتسبة لحدود الوزن السارية في 4 يناير 1975. المصدر: IC 9-20-4؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"10":{"q":"بموجب اعتماد إنديانا لمعادلة الجسور الفيدرالية W = 500{[(LN) / (N-1)] + 12N + 36}، ماذا يمثل المتغير 'N'؟","options":["وزن الشحنة الصافي في المركبة","الطول الإجمالي للمجموعة بالأقدام","عدد الإطارات على محور القيادة","عدد المحاور في المجموعة قيد الاعتبار"],"explanation":"في معادلة الجسور، N هو عدد المحاور في المجموعة، وL هي المسافة بين المحورين الطرفيين للمجموعة، وW هو الوزن الإجمالي المسموح به على تلك المجموعة. المصدر: IC 9-20-4 (معادلة الجسور)؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"11":{"q":"تسمح معادلة الجسور في إنديانا لمجموعتين متتاليتين من المحاور المزدوجة بأن تحمل كل منهما 34,000 رطل بشرط أن يكون المحور الأول والأخير من تلك المحاور المزدوجة على بعد لا يقل عن كم؟","options":["30 قدماً","40 قدماً","36 قدماً","51 قدماً"],"explanation":"يجوز لمجموعتين متتاليتين من المحاور المزدوجة أن تحمل كل منهما ما يصل إلى 34,000 رطل إذا كان المحور الأول والأخير من المجموعتين على بعد لا يقل عن 36 قدماً. المصدر: IC 9-20-4 (معادلة الجسور)؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"12":{"q":"مجموعة من مركبتين مقترنتين معاً، بما في ذلك الحمولة، لا يجوز أن تتجاوز عموماً أي طول إجمالي على الطرق السريعة في إنديانا؟","options":["65 قدماً","55 قدماً","75 قدماً","60 قدماً"],"explanation":"مجموعة من مركبتين مقترنتين، بما في ذلك الحمولة، لا يجوز أن تتجاوز 60 قدماً (مع استثناءات محدودة مثل ناقلات القوارب/المركبات وخدمة القيادة بعيداً). المصدر: IC 9-20-8؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"13":{"q":"مجموعة من ثلاث مركبات أو أكثر مقترنة معاً، بما في ذلك الحمولة، لا يجوز أن تتجاوز أي طول إجمالي بموجب قانون إنديانا؟","options":["60 قدماً","70 قدماً","65 قدماً","75 قدماً"],"explanation":"تحدّ إنديانا مجموعة من ثلاث مركبات مقترنة أو أكثر، بما في ذلك الحمولة، عند 65 قدماً. المصدر: IC 9-20-8؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"14":{"q":"تمنح إنديانا تسامحاً بنسبة 10% في الوزن الإجمالي للمركبة التي تنقل المحاصيل الزراعية من مكان الإنتاج إلى نقطة التسليم الأولى، باستثناء أي حالة؟","options":["عندما تُشغَّل المركبة على أي جزء من نظام الطرق السريعة بين الولايات (interstate)","عندما تُنقل الحمولة ليلاً","عندما يكون للمركبة أكثر من خمسة محاور","عندما تتجاوز الرحلة 50 ميلاً"],"explanation":"لا ينطبق تسامح الوزن الإجمالي بنسبة 10% للمحاصيل الزراعية على أي جزء من نظام الطرق السريعة بين الولايات، ولا حيث تنطبق حدود الجسور/الطرق المعلنة بموجب IC 9-20-1-4. المصدر: IC 9-20-4؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"15":{"q":"إذا كان مسموحاً لمركبة مجموعة بوزن إجمالي قدره 80,000 رطل، فما هو الحد الأقصى للوزن الإجمالي عند نقل المحاصيل الزراعية المؤهلة بموجب تسامح إنديانا البالغ 10%؟","options":["84,000 رطل","90,000 رطل","88,000 رطل","86,000 رطل"],"explanation":"تضيف إنديانا 10% إلى الوزن الإجمالي المسموح به لعمليات نقل المحاصيل الزراعية المؤهلة، فيصبح 80,000 رطل بذلك 88,000 رطل (على الطرق خارج نظام الطرق بين الولايات وغير المعلنة فقط). المصدر: IC 9-20-4؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"16":{"q":"تعامل إنديانا بعض المنتجات الحرجية كمحاصيل زراعية لأغراض تسامح الوزن بنسبة 10%. لأي من هذه ينطبق تسامح الـ10% في جميع الأوقات على الوزن الإجمالي ووزن المحاور؟","options":["الأخشاب المنشورة الجاهزة والخشب الرقائقي","رقائق الخشب واللحاء ونشارة الخشب","الأثاث والخزائن","الورق والكرتون"],"explanation":"تشمل المحاصيل الزراعية جذوع الأشجار ورقائق الخشب واللحاء ونشارة الخشب والحليب السائب؛ وبالنسبة لرقائق الخشب واللحاء ونشارة الخشب ينطبق تسامح الـ10% في جميع الأوقات على الوزن الإجمالي ووزن المحاور. المصدر: IC 9-20-4؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"17":{"q":"بموجب بند الحقوق المكتسبة في إنديانا الذي يحتفظ بحدود الوزن السارية في 4 يناير 1975، ما هو الحد الأقصى للوزن الإجمالي للتكوينات المتأثرة من المركبات؟","options":["80,000 رطل","70,000 رطل","64,000 رطل","73,280 رطلاً"],"explanation":"يحافظ قانون الحقوق المكتسبة في إنديانا على حد أقصى للوزن الإجمالي قدره 73,280 رطلاً للتكوينات التي كانت ستتعرض للعقوبة بموجب معادلة الجسور. المصدر: IC 9-20-4؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"18":{"q":"باستثناء الطرق السريعة بين الولايات، ما هو الحد الأقصى لوزن المحور المفرد المسموح به لمركبة جمع النفايات/القمامة البلدية المؤهلة في إنديانا؟","options":["20,000 رطل","24,000 رطل","22,400 رطل","26,000 رطل"],"explanation":"باستثناء نظام الطرق بين الولايات، يجوز لمركبات النفايات المؤهلة أن تحمل ما يصل إلى 24,000 رطل على المحور المفرد و42,000 رطل على المحور المزدوج، لكنها تظل خاضعة لحدود وزن العجلة بموجب IC 9-20-11-4. المصدر: IC 9-20-4؛ ملخص شرطة ولاية إنديانا لقوانين الحجم والوزن في إنديانا."},"19":{"q":"في إنديانا، أي فئة من رخص القيادة التجارية (CDL) مطلوبة لتشغيل مجموعة من المركبات بتصنيف وزن إجمالي مركّب (GCWR) قدره 26,001 رطل أو أكثر، حيث يكون للمركبة (المركبات) المقطورة تصنيف وزن إجمالي للمركبة (GVWR) يزيد عن 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعرّف إنديانا رخصة CDL من الفئة A بأنها أي مجموعة من المركبات بتصنيف GCWR قدره 26,001 رطل أو أكثر، بشرط أن يتجاوز تصنيف GVWR للوحدة (الوحدات) المقطورة 10,000 رطل. المصدر: دليل CDL في إنديانا (Indiana BMV)؛ 49 CFR 383.91 كما اعتمدته إنديانا."},"20":{"q":"بموجب قواعد إنديانا، المركبة المفردة بتصنيف GVWR قدره 26,001 رطل أو أكثر (أو مثل هذه المركبة وهي تقطر وحدة لا يزيد تصنيف GVWR لها عن 10,000 رطل) تتطلب أي فئة من رخص CDL؟","options":["الفئة C","الفئة B","الفئة A","رخصة السائق المحترف (Chauffeur)"],"explanation":"تعرّف إنديانا رخصة CDL من الفئة B بأنها أي مركبة مفردة بتصنيف GVWR قدره 26,001 رطل أو أكثر، أو مثل هذه المركبة وهي تقطر وحدة لا يزيد تصنيف GVWR لها عن 10,000 رطل. المصدر: دليل CDL في إنديانا (Indiana BMV)."},"21":{"q":"في إنديانا، المركبة التي لا تستوفي حدود الوزن للفئة A أو الفئة B لكنها مصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق) أو تنقل مواد خطرة تتطلب لوحات تحذيرية (placarded)، تتطلب أي فئة من رخص CDL؟","options":["الفئة A","الفئة B","الفئة C","لا تُطلب رخصة CDL"],"explanation":"تشمل رخصة CDL من الفئة C في إنديانا المركبات التي تقل عن حدود وزن الفئة A/B والمصممة لنقل 16 راكباً أو أكثر (بما في ذلك السائق) أو التي تنقل مواد خطرة تتطلب لوحات تحذيرية. المصدر: دليل CDL في إنديانا (Indiana BMV)."},"22":{"q":"ما هو الحد الأدنى للسن للحصول على رخصة CDL في إنديانا مقيّدة بالقيادة داخل الولاية (intrastate) فقط؟","options":["16 عاماً","17 عاماً","18 عاماً","21 عاماً"],"explanation":"تشترط إنديانا أن يكون المتقدمون في سن 18 على الأقل لحمل رخصة CDL أو CLP للتشغيل داخل الولاية؛ ويقتصر السائقون الذين تتراوح أعمارهم بين 18 و20 عاماً على تشغيل المركبات التجارية داخل إنديانا. المصدر: دليل CDL في إنديانا (Indiana BMV)؛ IC 9-24."},"23":{"q":"ما هو الحد الأدنى للسن لقيادة مركبة آلية تجارية في التجارة بين الولايات (عبر حدود الولايات) برخصة CDL من إنديانا؟","options":["18 عاماً","19 عاماً","20 عاماً","21 عاماً"],"explanation":"يجب أن يكون السائق في سن 21 على الأقل لتشغيل مركبة آلية تجارية بين الولايات، أو لنقل المواد الخطرة، أو لنقل الركاب عبر حدود الولايات. ويقتصر السائقون الذين تتراوح أعمارهم بين 18 و20 عاماً على القيادة داخل الولاية في إنديانا. المصدر: دليل CDL في إنديانا (Indiana BMV)؛ 49 CFR 391.11."},"24":{"q":"أي تصديق (endorsement) تشترطه إنديانا لقيادة مركبة صهريج تنقل سائلاً أو غازاً في صهريج مفرد بسعة تزيد عن 119 جالوناً (بسعة إجمالية قدرها 1,000 جالون أو أكثر)؟","options":["التصديق N","التصديق T","التصديق H","التصديق P"],"explanation":"يُطلب تصديق N (مركبة الصهريج) في إنديانا للمركبات المصممة لنقل السوائل أو الغازات في صهريج بسعة فردية مصنّفة تزيد عن 119 جالوناً وسعة إجمالية قدرها 1,000 جالون أو أكثر. المصدر: تصديقات وقيود CDL في Indiana BMV."},"25":{"q":"أي تصديق CDL في إنديانا مطلوب لتشغيل مركبة تقطر مقطورتين أو ثلاث مقطورات منفصلة (doubles/triples)؟","options":["التصديق N","التصديق P","التصديق T","التصديق S"],"explanation":"يخوّل التصديق T تشغيل مجموعة تضم مقطورتين أو ثلاث مقطورات منفصلة مرفقة (doubles/triples). ويُحصل عليه باجتياز اختبار المعرفة الخاص بالمقطورات المزدوجة/الثلاثية. المصدر: تصديقات وقيود CDL في Indiana BMV."},"26":{"q":"أي تصديق CDL في إنديانا مطلوب لقيادة مركبة مصممة لنقل 16 راكباً أو أكثر، بما في ذلك السائق؟","options":["التصديق S","التصديق P","التصديق N","التصديق H"],"explanation":"يُطلب تصديق P (الركاب) لتشغيل مركبة مصممة لنقل 16 راكباً أو أكثر، بما في ذلك السائق. ويتطلب اختبار معرفة، واختبار مهارات في مركبة تمثيلية، وتدريب ELDT للمتقدمين لأول مرة. المصدر: تصديقات وقيود CDL في Indiana BMV."},"27":{"q":"في إنديانا، ما هو الفحص الفيدرالي الإضافي الذي يجب على المتقدم إكماله للحصول على تصديق H (المواد الخطرة)؟","options":["تقييم تهديد أمني من إدارة أمن النقل (TSA) يشمل أخذ البصمات","اختبار كشف الكذب من مكتب التحقيقات الفيدرالي (FBI)","فحص سجلات جنائية على مستوى الولاية فقط دون بصمات","مقابلة بشأن المواد الخاضعة للرقابة من إدارة مكافحة المخدرات (DEA)"],"explanation":"تتطلب إضافة التصديق H اجتياز اختبار معرفة المواد الخطرة (HazMat) وإكمال تقييم تهديد أمني من TSA، يشمل أخذ البصمات والتحقق من الوضع القانوني. المصدر: تصديقات وقيود CDL في Indiana BMV؛ 49 CFR 1572 (TSA)."},"28":{"q":"كم مرة يجب على حامل رخصة CDL في إنديانا تجديد تقييم التهديد الأمني من TSA للاحتفاظ بتصديق المواد الخطرة (H)؟","options":["كل سنة","كل سنتين","كل 5 سنوات","كل 10 سنوات"],"explanation":"تقييم التهديد الأمني من TSA لتصديق المواد الخطرة (HazMat) صالح لمدة خمس سنوات ويجب تجديده (مع اختبار معرفة جديد للمواد الخطرة) كل خمس سنوات على الأقل. المصدر: تصديقات وقيود CDL في Indiana BMV؛ برنامج تصديق HazMat من TSA."},"29":{"q":"أي رمز تصديق مدمج تصدره إنديانا عندما يحمل السائق تصديقي المواد الخطرة ومركبة الصهريج معاً؟","options":["التصديق X","التصديق HN","التصديق Z","التصديق W"],"explanation":"تصدر إنديانا التصديق X لتمثيل الجمع بين امتيازات H (المواد الخطرة) وN (مركبة الصهريج). المصدر: تصديقات وقيود CDL في Indiana BMV."},"30":{"q":"قبل إجراء اختبار مهارات CDL في إنديانا، كم من الوقت يجب على المتقدم أن يحمل تصريح المتعلم التجاري الصالح (CLP)؟","options":["7 أيام على الأقل","14 يوماً على الأقل","30 يوماً على الأقل","60 يوماً على الأقل"],"explanation":"يجب على المتقدم أن يحمل تصريح CLP لمدة 14 يوماً على الأقل قبل محاولة إجراء اختبار مهارات CDL. وهذا هو الحد الأدنى الفيدرالي الذي اعتمدته إنديانا. المصدر: دليل CDL في إنديانا / Indiana BMV؛ 49 CFR 383.25."},"31":{"q":"وفقاً لـ Indiana BMV، كم تبلغ مدة صلاحية تصريح المتعلم التجاري (CLP) بعد إصداره؟","options":["30 يوماً","90 يوماً","سنة واحدة","خمس سنوات"],"explanation":"ينصّ Indiana BMV على أن تصريح CLP صالح لمدة سنة واحدة، وكذلك تكون نتائج اختبار معرفة CDL صالحة لمدة سنة واحدة. المصدر: Indiana BMV، الحصول على تصريح المتعلم التجاري."},"32":{"q":"ما هو القيد الذي ينطبق على حامل تصريح CLP في إنديانا أثناء تشغيل مركبة آلية تجارية؟","options":["يجوز له القيادة بمفرده على الطرق السريعة بين الولايات فقط","يجب أن يكون مصحوباً بحامل رخصة CDL من الفئة والتصديقات المناسبة","يجوز له القيادة فقط بين شروق الشمس وغروبها","يجوز له تشغيل المركبات التي يقل تصنيف GVWR لها عن 26,001 رطل فقط"],"explanation":"يجوز لحامل تصريح CLP تشغيل مركبة آلية تجارية فقط عندما يكون مصحوباً بشخص يحمل رخصة CDL صالحة من الفئة والتصديقات المناسبة ويجلس بجوار حامل تصريح CLP. المصدر: Indiana BMV، الحصول على تصريح المتعلم التجاري؛ 49 CFR 383.25."},"33":{"q":"عند التقدم للحصول على رخصة CDL أو تصريح CLP في إنديانا، كم عدد المستندات التي يجب على المتقدم تقديمها لإثبات الإقامة في إنديانا؟","options":["مستند واحد","مستندان","ثلاثة مستندات","لا يُطلب إثبات الإقامة"],"explanation":"تشترط إنديانا مستندين يثبتان الإقامة في إنديانا، بالإضافة إلى مستند واحد يثبت الهوية، وواحد يثبت الوضع القانوني، وواحد يثبت رقم الضمان الاجتماعي الكامل. المصدر: متطلبات المستندات لدى Indiana BMV."},"34":{"q":"بالإضافة إلى إثبات الهوية والإقامة في إنديانا، أي عنصرين يجب على المتقدم لرخصة CDL في إنديانا توثيقهما؟","options":["الوضع القانوني في الولايات المتحدة ورقم الضمان الاجتماعي الكامل","شهادة الثانوية العامة وسند ملكية المركبة","خطاب من أخصائي بصر وإقرار من صاحب العمل","التسجيل في الانتخابات وإيصال دفعة مرافق عامة"],"explanation":"تشترط إنديانا مستنداً واحداً يثبت الوضع القانوني (الوجود القانوني) في الولايات المتحدة ومستنداً واحداً يثبت رقم الضمان الاجتماعي الكامل للمتقدم، بالإضافة إلى الهوية ومستندين للإقامة. المصدر: متطلبات المستندات لدى Indiana BMV."},"35":{"q":"اعتباراً من 7 فبراير 2022، يجب على المتقدمين في إنديانا إكمال تدريب السائق المبتدئ (ELDT) في أي حالة؟","options":["تجديد رخصة CDL قائمة من الفئة A دون تغيير الفئة","الحصول على أول رخصة CDL من الفئة A أو الفئة B، أو أول تصديق H أو P أو S","إضافة التصديق T (المقطورات المزدوجة/الثلاثية) فقط","التصديق الذاتي كمعفى داخل الولاية"],"explanation":"ينطبق ELDT على السائقين الذين يحصلون على أول رخصة CDL من الفئة A أو الفئة B، أو يرتقون إلى فئة أعلى، أو يحصلون على تصديق المواد الخطرة (H) أو الركاب (P) أو الحافلة المدرسية (S) لأول مرة في 7 فبراير 2022 أو بعده. المصدر: قاعدة ELDT الخاصة بـ FMCSA؛ Indiana BMV."},"36":{"q":"أين يجب على المتقدم في إنديانا إكمال تدريب السائق المبتدئ (ELDT) المطلوب؟","options":["في أي مدرسة قيادة خاصة يختارها المتقدم","لدى مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA (FMCSA Training Provider Registry)","في مركز اختبار بفرع Indiana BMV","من خلال دورة عبر الإنترنت معتمدة من TSA"],"explanation":"يجب أن يُقدَّم التدريب النظري والتدريب خلف المقود ضمن ELDT من قبل جهة مدرجة في سجل مزوّدي التدريب التابع لـ FMCSA (TPR)؛ ولا يجوز إلا للمزوّدين المدرجين الإبلاغ عن إتمامه. المصدر: سجل مزوّدي التدريب التابع لـ FMCSA؛ Indiana BMV."},"37":{"q":"أي فئة تصديق ذاتي طبي يختارها حامل رخصة CDL في إنديانا إذا كان يشغّل المركبة داخل إنديانا فقط ويجب عليه استيفاء متطلبات تأهيل السائق في الولاية مع شهادة فاحص طبي؟","options":["غير المعفى بين الولايات (NI)","المعفى بين الولايات (EI)","غير المعفى داخل الولاية (NA)","المعفى داخل الولاية (EA)"],"explanation":"تنطبق فئة غير المعفى داخل الولاية (NA) على السائقين الذين يعملون فقط في التجارة داخل الولاية (داخل إنديانا) والذين يجب عليهم استيفاء قواعد تأهيل السائق في إنديانا وتقديم شهادة فاحص طبي. المصدر: التصديق الذاتي لـ CDL لدى Indiana BMV؛ 49 CFR 383.71."},"38":{"q":"أي فئة تصديق ذاتي تتطلب من حامل رخصة CDL في إنديانا الاحتفاظ بشهادة فاحص طبي فيدرالية صالحة من DOT من مزوّد مدرج في السجل الوطني لـ FMCSA؟","options":["المعفى داخل الولاية (EA)","المعفى بين الولايات (EI)","غير المعفى بين الولايات (NI)","الزراعي المقيّد (RA)"],"explanation":"السائق الذي يصدّق ذاتياً كغير معفى بين الولايات (NI) يعمل عبر حدود الولايات في تجارة غير معفاة ويجب عليه حمل وصيانة شهادة فاحص طبي صالحة صادرة عن فاحص معتمد مدرج في السجل الوطني لـ FMCSA. المصدر: التصديق الذاتي لـ CDL لدى Indiana BMV؛ 49 CFR 391.41."},"39":{"q":"في إنديانا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يكون عنده تشغيل مركبة آلية تجارية (CMV) قانونياً؟","options":["أقل من 0.04%","أقل من 0.08%","أقل من 0.02%","أقل من 0.10%"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.2) على أنه من غير القانوني تشغيل مركبة CMV إذا كان تركيز الكحول في دمك 0.04% أو أكثر، لذا يجب على سائق CMV أن يبقى دون 0.04% (نصف حد 0.08% للسائقين غير التجاريين). المصدر: دليل رخصة القيادة التجارية لـ Indiana BMV، القسم 1.3.2."},"40":{"q":"بموجب قاعدة الموافقة الضمنية في إنديانا، ماذا يعني تشغيل مركبة CMV من حيث ما وافق عليه السائق؟","options":["الخضوع لاختبار الكحول","التنازل عن الحق في توكيل محامٍ","الخضوع لتفتيش المركبة في أي وقت","الالتحاق ببرنامج إلزامي لعلاج تعاطي المخدرات"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.2) على أنك إذا شغّلت مركبة CMV، فستُعتبر قد أعطيت موافقتك على اختبار الكحول. المصدر: دليل رخصة القيادة التجارية لـ Indiana BMV، القسم 1.3.2؛ IC 9-30-6."},"41":{"q":"بالنسبة لمخالفة كبرى أولى مثل قيادة مركبة CMV بتركيز كحول في الدم (BAC) قدره 0.04% أو أعلى، إلى متى سيفقد حامل رخصة CDL في إنديانا رخصته؟","options":["سنة واحدة على الأقل","6 أشهر على الأقل","90 يوماً على الأقل","3 سنوات على الأقل"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.2) على أنك ستفقد رخصة CDL لمدة سنة واحدة على الأقل عن مخالفة كبرى أولى، بما في ذلك قيادة مركبة CMV بتركيز BAC قدره 0.04% أو أعلى. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.2 (49 CFR 383.51)."},"42":{"q":"إذا وقعت مخالفة كبرى أولى أثناء قيادة السائق لمركبة CMV تحمل لوحات تحذيرية للمواد الخطرة، فما هو الحد الأدنى لفترة إسقاط الأهلية في إنديانا؟","options":["3 سنوات على الأقل","سنة واحدة على الأقل","5 سنوات على الأقل","مدى الحياة"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.2) على أنك ستفقد رخصة CDL لمدة ثلاث سنوات على الأقل إذا وقعت مخالفة كبرى أولى أثناء تشغيل مركبة CMV تحمل لوحات تحذيرية للمواد الخطرة. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.2."},"43":{"q":"ما هي عاقبة المخالفة الكبرى الثانية (مثل قيادة CMV تحت تأثير الكحول للمرة الثانية) بموجب قواعد CDL في إنديانا؟","options":["فقدان رخصة CDL مدى الحياة","فقدان رخصة CDL لمدة 10 سنوات","فقدان رخصة CDL لمدة 3 سنوات","فقدان رخصة CDL لمدة 5 سنوات"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.2) على أنك ستفقد رخصة CDL مدى الحياة عن مخالفة كبرى ثانية. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.2 (49 CFR 383.51)."},"44":{"q":"أي مما يلي يُعامل كمخالفة كبرى أولى تُكلّف حامل رخصة CDL في إنديانا رخصته لمدة سنة واحدة على الأقل؟","options":["رفض الخضوع لاختبار الكحول في الدم","اتباع مركبة عن قرب شديد","القيادة بسرعة 16 mph فوق الحد المعلن","تغيير حارة غير سليم"],"explanation":"يدرج دليل CDL الخاص بـ Indiana BMV (القسم 1.3.2) رفض الخضوع لاختبار الكحول في الدم كمخالفة كبرى تحمل إسقاطاً للأهلية لمدة سنة واحدة على الأقل؛ أما الخيارات الأخرى فهي مخالفات مرورية جسيمة، وليست مخالفات كبرى. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.2."},"45":{"q":"في إنديانا، ماذا يحدث لحامل رخصة CDL الذي يستخدم مركبة CMV لارتكاب جناية تتعلق بمواد خاضعة للرقابة؟","options":["فقدان رخصة CDL مدى الحياة","فقدان رخصة CDL لمدة 3 سنوات","فقدان رخصة CDL لمدة سنة واحدة","فقدان رخصة CDL لمدة 5 سنوات"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.2) على أنك ستفقد رخصة CDL مدى الحياة إذا استخدمت مركبة CMV لارتكاب جناية تتعلق بمواد خاضعة للرقابة. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.2."},"46":{"q":"تبيّن أن لدى سائق CMV في إنديانا كمية قابلة للكشف من الكحول أقل من 0.04%. ما هي العاقبة الفورية؟","options":["الإخراج من الخدمة لمدة 24 ساعة","إسقاط أهلية رخصة CDL لمدة 60 يوماً","غرامة مدنية قدرها $2,750","إسقاط أهلية رخصة CDL لمدة سنة واحدة"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.2) على أنك ستُخرَج من الخدمة لمدة 24 ساعة إذا كانت لديك أي كمية قابلة للكشف من الكحول أقل من 0.04%. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.2."},"47":{"q":"كيف يعرّف دليل CDL في إنديانا 'السرعة المفرطة' كمخالفة مرورية جسيمة؟","options":["15 mph أو أكثر فوق الحد المعلن","10 mph أو أكثر فوق الحد المعلن","20 mph أو أكثر فوق الحد المعلن","25 mph أو أكثر فوق الحد المعلن"],"explanation":"يعرّف دليل CDL الخاص بـ Indiana BMV (القسم 1.3.3) السرعة المفرطة بأنها 15 mph أو أكثر فوق الحد المعلن. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.3."},"48":{"q":"بالنسبة لمخالفتين مروريتين جسيمتين في مركبة CMV خلال فترة ثلاث سنوات، إلى متى سيفقد حامل رخصة CDL في إنديانا رخصته؟","options":["60 يوماً على الأقل","30 يوماً على الأقل","90 يوماً على الأقل","120 يوماً على الأقل"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.3) على أنك ستفقد رخصة CDL لمدة 60 يوماً على الأقل عن مخالفتين مروريتين جسيمتين خلال فترة ثلاث سنوات تتعلقان بمركبة CMV. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.3."},"49":{"q":"بالنسبة لثلاث مخالفات مرورية جسيمة أو أكثر في مركبة CMV خلال فترة ثلاث سنوات، ما هو إسقاط الأهلية في إنديانا؟","options":["120 يوماً على الأقل","60 يوماً على الأقل","90 يوماً على الأقل","سنة واحدة على الأقل"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.3) على أنك ستفقد رخصة CDL لمدة 120 يوماً على الأقل عن ثلاث مخالفات مرورية جسيمة أو أكثر خلال فترة ثلاث سنوات تتعلق بمركبة CMV. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.3."},"50":{"q":"أي مما يلي مدرج كمخالفة مرورية جسيمة في دليل CDL في إنديانا؟","options":["القيادة المتهورة","قيادة مركبة CMV بتركيز BAC قدره 0.04%","مغادرة موقع حادث CMV","رفض اختبار الكحول في الدم"],"explanation":"يدرج دليل CDL الخاص بـ Indiana BMV (القسم 1.3.3) القيادة المتهورة ضمن المخالفات المرورية الجسيمة؛ أما الخيارات الثلاثة الأخرى فهي مخالفات كبرى بموجب القسم 1.3.2. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.3."},"51":{"q":"ما هو الحد الأدنى لإسقاط الأهلية عن مخالفة أولى لأمر الإخراج من الخدمة في إنديانا؟","options":["90 يوماً على الأقل","60 يوماً على الأقل","30 يوماً على الأقل","180 يوماً على الأقل"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.4) على أنك ستفقد رخصة CDL لمدة 90 يوماً على الأقل عن مخالفتك الأولى لأمر الإخراج من الخدمة. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.4."},"52":{"q":"ما هو الحد الأدنى لإسقاط الأهلية عن مخالفتين لأمر الإخراج من الخدمة خلال فترة عشر سنوات في إنديانا؟","options":["سنة واحدة على الأقل","90 يوماً على الأقل","6 أشهر على الأقل","3 سنوات على الأقل"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.4) على أنك ستفقد رخصة CDL لمدة سنة واحدة على الأقل عن مخالفتين لأمر الإخراج من الخدمة خلال فترة عشر سنوات. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.4."},"53":{"q":"ثلاث مخالفات أو أكثر لأمر الإخراج من الخدمة خلال فترة عشر سنوات تؤدي إلى أي حد أدنى لإسقاط الأهلية في إنديانا؟","options":["3 سنوات على الأقل","سنة واحدة على الأقل","5 سنوات على الأقل","مدى الحياة"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.4) على أنك ستفقد رخصة CDL لمدة ثلاث سنوات على الأقل عن ثلاث مخالفات أو أكثر لأمر الإخراج من الخدمة خلال فترة عشر سنوات. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.4."},"54":{"q":"ما هو الحد الأدنى لإسقاط الأهلية عن مخالفة أولى عند تقاطع السكة الحديدية مع الطريق السريع في إنديانا؟","options":["60 يوماً على الأقل","30 يوماً على الأقل","90 يوماً على الأقل","120 يوماً على الأقل"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.5) على أنك ستفقد رخصة CDL لمدة 60 يوماً على الأقل عن مخالفتك الأولى عند تقاطع السكة الحديدية مع الطريق السريع. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.5."},"55":{"q":"مخالفة ثانية عند تقاطع السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات تحمل أي حد أدنى لإسقاط الأهلية في إنديانا؟","options":["120 يوماً على الأقل","60 يوماً على الأقل","90 يوماً على الأقل","سنة واحدة على الأقل"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.5) على أنك ستفقد رخصة CDL لمدة 120 يوماً على الأقل عن مخالفة ثانية عند تقاطع السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.5."},"56":{"q":"مخالفة ثالثة عند تقاطع السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات تحمل أي حد أدنى لإسقاط الأهلية في إنديانا؟","options":["سنة واحدة على الأقل","120 يوماً على الأقل","6 أشهر على الأقل","3 سنوات على الأقل"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 1.3.5) على أنك ستفقد رخصة CDL لمدة سنة واحدة على الأقل عن مخالفة ثالثة عند تقاطع السكة الحديدية مع الطريق السريع خلال فترة ثلاث سنوات. المصدر: دليل CDL لـ Indiana BMV، القسم 1.3.5."},"57":{"q":"بموجب قواعد إنديانا، بعد كم عدد من الإدانات بموجب قانون ولاية يحظر إرسال الرسائل النصية أثناء قيادة مركبة CMV تُسقَط أهلية رخصة CDL، وإلى متى عن المخالفة الثانية؟","options":["إدانتان أو أكثر؛ 60 يوماً عن المخالفة الثانية خلال 3 سنوات","إدانة واحدة؛ 120 يوماً فوراً","إدانتان؛ سنة واحدة عن المخالفة الثانية","ثلاث إدانات؛ 30 يوماً عن المخالفة الثالثة"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (القسم 2.9.5) على أن أهلية رخصة CDL ستُسقَط بعد إدانتين أو أكثر بموجب أي قانون ولاية يخص الرسائل النصية أثناء تشغيل مركبة CMV، مع إسقاط للأهلية لمدة 60 يوماً عن المخالفة الثانية خلال 3 سنوات (120 يوماً عن ثلاث مخالفات أو أكثر خلال 3 سنوات). المصدر: دليل CDL لـ Indiana BMV، القسم 2.9.5."},"58":{"q":"وفقاً لدليل CDL في إنديانا، سائق CMV الذي يخالف قيد الهاتف المحمول المحمول باليد أو الرسائل النصية يخضع لغرامة مدنية تصل إلى أي مبلغ؟","options":["$2,750","$1,000","$5,000","$11,000"],"explanation":"ينصّ دليل CDL الخاص بـ Indiana BMV (الأقسام 2.9.4-2.9.5) على أن كل مخالفة لحظر الهاتف المحمول باليد أو الرسائل النصية تُخضع السائق لغرامة مدنية تصل إلى $2,750؛ وقد يخضع أصحاب العمل لغرامات تصل إلى $11,000. المصدر: دليل CDL لـ Indiana BMV، القسمان 2.9.4 و2.9.5."},"59":{"q":"على طريق إنديانا السريع بين الولايات في منطقة ريفية (خارج المنطقة الحضرية)، ما هو الحد الأقصى للسرعة لمقطورة جرّار محمّلة بوزن إجمالي معلن يزيد عن 26,000 رطل؟","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"بموجب IC 9-21-5-2، تُقيَّد المركبة التي ليست حافلة والتي يزيد وزنها الإجمالي المعلن عن 26,000 رطل بسرعة 65 mph على الطرق السريعة الريفية بين الولايات، بينما يجوز لسيارات الركاب السير بسرعة 70 mph. وهذا هو الأساس لإشارات السرعة المنفصلة (الشاحنة مقابل السيارة) على الطرق السريعة بين الولايات في إنديانا."},"60":{"q":"يجوز لسيارة الركاب السير بسرعة 70 mph على طريق إنديانا السريع الريفي بين الولايات. في الموقع نفسه، يجوز قانونياً لحافلة مستأجرة تقلّ ركاباً السير بسرعة تصل إلى:","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"تطبّق IC 9-21-5-2 حدّ الشاحنات البالغ 65 mph على المركبات 'غير الحافلة' التي يزيد وزنها عن 26,000 رطل. ولا تخضع الحافلات لحدّ الشاحنات المخفّض، لذا يجوز للحافلة السير بالسرعة المعلنة 70 mph على الطرق السريعة الريفية بين الولايات. المصدر: Indiana Code 9-21-5-2."},"61":{"q":"أنت تقود صهريجاً للمواد الخطرة يحمل لوحات تحذيرية على طريق سريع في إنديانا. عند معبر سكة حديد متقاطع حيث يكون التوقف مطلوباً، يجب أن تتوقف:","options":["على ألا يقل المسافة عن 15 قدماً ولا تزيد عن 50 قدماً من أقرب قضيب","على ألا يقل المسافة عن 10 أقدام ولا تزيد عن 25 قدماً من أقرب قضيب","على بُعد 50 قدماً بالضبط من أقرب قضيب","على ألا يقل المسافة عن 50 قدماً ولا تزيد عن 100 قدم من أقرب قضيب"],"explanation":"يتطلّب دليل CDL في إنديانا (القسم 9.6.12) من المركبات التي تحمل لوحات تحذيرية، وناقلات الكلور، ومركبات صهاريج الشحن التوقف على بُعد 15 إلى 50 قدماً من أقرب قضيب، ثم المتابعة فقط عند التأكد من عدم قدوم قطار. المصدر: دليل CDL في إنديانا."},"62":{"q":"يتطلّب قانون التنحّي جانباً (Move Over) في إنديانا (IC 9-21-8-35) منك تغيير المسار بعيداً عن مركبة طوارئ متوقفة أو مركبة معطّلة تُظهر أضواءً وامضة. إذا لم تستطع تغيير المسار بأمان، يجب عليك:","options":["تخفيض سرعتك إلى 10 mph أقل من حدّ السرعة المعلن","التوقف تماماً حتى يصبح من الآمن المتابعة","إطلاق بوقك والحفاظ على السرعة المعلنة","تخفيض سرعتك إلى 20 mph أقل من حدّ السرعة المعلن"],"explanation":"بموجب IC 9-21-8-35، عندما يكون تغيير المسار غير ممكن أو غير آمن، يجب على السائق التباطؤ إلى ما لا يقل عن 10 mph أقل من حدّ السرعة المعلن أثناء التجاوز. وتروّج INDOT لهذا تحت شعار 'تنحَّ جانباً أو خفّف السرعة'. المصدر: IC 9-21-8-35؛ INDOT."},"63":{"q":"على طريق إنديانا السريع بين الولايات حيث يوجد مساران في اتجاه سيرك، يُقيَّد جرّار الشاحنة عموماً بأي مسار، باستثناء حالات التجاوز أو الدخول/الخروج أو تفادي خطر خاص؟","options":["أي مسار، بحرية","المسار الأيسر (مسار التجاوز)","المسار الأيمن الأقصى","وسط الطريق"],"explanation":"تحظر IC 9-21-8-12 تشغيل شاحنة أو جرّار شاحنة على طريق سريع بين الولايات في أي مسار باستثناء المسار الأيمن الأقصى، إلا عند تجاوز مركبة أبطأ، أو الدخول إلى الطريق السريع أو مغادرته، أو حيث يتطلّب خطر خاص استخدام مسار آخر. المصدر: Indiana Code 9-21-8-12."},"64":{"q":"على طريق إنديانا السريع بين الولايات حيث توجد ثلاثة مسارات أو أكثر في اتجاه سيرك، يُقيَّد جرّار الشاحنة بـ:","options":["المسار الأيمن الأقصى فقط","المساران الأيمنان فقط","أي مسار باستثناء الأيسر الأقصى","المسار الأوسط فقط"],"explanation":"تقصر IC 9-21-8-13 الشاحنات على الطرق السريعة بين الولايات التي بها ثلاثة مسارات على الأقل في اتجاه واحد على المسارين الأيمنين الأقصيين، إلا عند الدخول إلى الطريق السريع أو مغادرته أو تفادي خطر خاص. وهذا أكثر تساهلاً من قاعدة المسار الواحد للمقاطع ذات المسارين. المصدر: Indiana Code 9-21-8-13."},"65":{"q":"في إنديانا، السائق الذي يقابل أو يتجاوز حافلة مدرسية متوقفة تُظهر ذراع التوقف الممتدة وأضواءها الحمراء الوامضة يجب أن يتوقف ويبقى متوقفاً حتى:","options":["يلوّح سائق الحافلة له بالمرور","تمرّ خمس ثوانٍ","تُسحب ذراع التوقف وتتوقف الأضواء الحمراء عن الوميض","يَعُدّ إلى عشرة"],"explanation":"بموجب IC 9-21-12-1، يجب على السائق التوقف قبل بلوغ الحافلة عندما يكون جهاز إشارة الذراع ممتداً، ولا يجوز له المتابعة حتى لم يعد الجهاز ممتداً (تتوقف الأضواء عن الوميض). والمخالفة تُعَدّ مخالفة من الفئة A. المصدر: Indiana Code 9-21-12-1."},"66":{"q":"أنت تقود باتجاه حافلة مدرسية متوقفة (أضواء حمراء وامضة) موجودة على الجانب الآخر من طريق بأربعة مسارات. بموجب قانون الحافلات المدرسية في إنديانا، لا يتعيّن عليك التوقف فقط إذا كان الطريقان مفصولين بـ:","options":["خط مركزي مرسوم أو مسار انعطاف يساري ثنائي الاتجاه","أي أربعة مسارات أو أكثر من الرصف","جزيرة وسطية مرسومة بمستوى الطريق عرضها 4 أقدام على الأقل","حاجز مادي أو جزيرة وسطية غير ممهّدة/فاصلة غير مخصّصة للسير"],"explanation":"تُعفي IC 9-21-12-3 السائق المقترب من التوقف فقط عندما يكون الطريقان مفصولين بمساحة فاصلة غير ممهّدة، أو حاجز مادي، أو قسم فاصل مُنشأ لإعاقة المرور، وتكون الحافلة على الجانب المقابل. أما مجرد خط مرسوم فلا يُعتبر مؤهلاً—فما زال يتعيّن عليك التوقف. المصدر: Indiana Code 9-21-12-3."},"67":{"q":"إذا اضطررت لإيقاف مركبتك التجارية على كتف طريق إنديانا السريع المقسوم، خلال كم من الوقت يجب أن تضع أجهزة التحذير من الطوارئ؟","options":["خلال دقيقتين","خلال 5 دقائق","خلال 10 دقائق","فوراً، قبل الخروج من المقصورة"],"explanation":"ينصّ دليل CDL في إنديانا (القسم 2.5) على أنه إذا توقفت على طريق أو كتف يجب أن تضع أجهزة التحذير من الطوارئ خلال 10 دقائق. المصدر: دليل CDL في إنديانا."},"68":{"q":"عند التوقف على طريق إنديانا السريع أحادي الاتجاه أو المقسوم، أين تضع مثلثات التحذير الثلاثة؟","options":["على بُعد 10 أقدام، و100 قدم، و200 قدم باتجاه المرور المقترب","على بُعد 10 أقدام، و50 قدماً، و100 قدم باتجاه المرور المقترب","على بُعد 100 قدم أماماً، و100 قدم خلفاً، وعند المركبة","عند المركبة فقط، مع تشغيل الأضواء الوامضة الرباعية"],"explanation":"يوجّه دليل CDL في إنديانا بأنه على طريق أحادي الاتجاه أو مقسوم، تُوضع أجهزة التحذير على بُعد 10 أقدام، و100 قدم، و200 قدم باتجاه المرور المقترب. المصدر: دليل CDL في إنديانا، القسم 2.5."},"69":{"q":"عند التوقف على طريق إنديانا ذي مسارين يحمل المرور في كلا الاتجاهين، يجب وضع مثلثات التحذير الخاصة بك:","options":["على بُعد 10 أقدام، و100 قدم، و200 قدم خلف المركبة فقط","على بُعد 50 قدماً أماماً و50 قدماً خلفاً فقط","على بُعد 200 قدم أماماً و200 قدم خلفاً فقط","ضمن 10 أقدام من المركبة، و100 قدم أماماً و100 قدم خلفاً"],"explanation":"على طريق ثنائي الاتجاه غير مقسوم، يتطلّب دليل CDL في إنديانا وضع مثلث ضمن 10 أقدام من الزاوية الأمامية أو الخلفية لتحديد المركبة، بالإضافة إلى واحد على بُعد 100 قدم أماماً وواحد على بُعد 100 قدم خلفاً، على الكتف أو في المسار. المصدر: دليل CDL في إنديانا، القسم 2.5."},"70":{"q":"تقترب حافلة مدرسية تقودها في إنديانا من معبر سكة حديد متقاطع. يجب أن توقف حافلتك:","options":["بين 15 و50 قدماً قبل المعبر","على ألا يقل المسافة عن 5 أقدام من القضيب","على بُعد 25 قدماً بالضبط من القضيب","فقط إذا كان القطار مرئياً"],"explanation":"يوجّه دليل CDL في إنديانا (القسم 4.3.5) سائقي الحافلات بإيقاف الحافلة بين 15 و50 قدماً قبل معابر السكك الحديدية، ثم النظر والاستماع في كلا الاتجاهين قبل المتابعة. المصدر: دليل CDL في إنديانا."},"71":{"q":"بموجب قانون التنحّي جانباً المُعدَّل في إنديانا، السائق الذي يفشل في التنحّي جانباً أو تخفيف السرعة لمركبة متوقفة بأضواء وامضة (دون حدوث إصابة) يرتكب:","options":["مخالفة من الفئة A","مخالفة من الفئة B","مخالفة من الفئة C","جناية من الفئة D"],"explanation":"المخالفة الأساسية لـ IC 9-21-8-35 هي مخالفة من الفئة B؛ وترتقي إلى جناية فقط إذا تسبّب الإخفاق في إصابة جسدية خطيرة أو وفاة لعامل مشمول. المصدر: IC 9-21-8-35؛ INDOT."},"72":{"q":"بدون تصريح للحمولة الكبيرة من دائرة الإيرادات في إنديانا/INDOT، فإن الحد الأقصى القانوني للعرض لحمولة تجارية على طرق إنديانا السريعة هو:","options":["8 أقدام و0 بوصة","8 أقدام و6 بوصات","10 أقدام و0 بوصة","9 أقدام و0 بوصة"],"explanation":"الحد الأقصى القانوني (بدون تصريح) للعرض في إنديانا هو 8 أقدام و6 بوصات (102 inches). الحمولات التي تتجاوز ذلك تتطلّب تصريحاً للحمولة الكبيرة/الزائدة الوزن عبر خدمات الناقلين الآليين بدائرة الإيرادات في إنديانا. المصدر: INDOT / لوائح OSOW الخاصة بدائرة الإيرادات في إنديانا."},"73":{"q":"بدون تصريح للحمولة الكبيرة في إنديانا، فإن الحد الأقصى القانوني للارتفاع لمركبة وحمولتها هو:","options":["13 قدماً و0 بوصة","13 قدماً و6 بوصات","14 قدماً و0 بوصة","12 قدماً و6 بوصات"],"explanation":"الحد الأقصى القانوني للارتفاع في إنديانا هو 13 قدماً و6 بوصات؛ وأي شيء أعلى يحتاج إلى تصريح للحمولة الكبيرة. ويجب على السائقين مع ذلك التحقق من الارتفاعات الخالية، إذ تحكم ارتفاعات الجسور المعلنة. المصدر: INDOT / لوائح OSOW الخاصة بدائرة الإيرادات في إنديانا."},"74":{"q":"بدون تصريح للوزن الزائد، فإن الحد الأقصى القانوني للوزن الإجمالي للمركبة لشاحنة قياسية على طرق إنديانا السريعة هو:","options":["73,280 رطلاً","90,000 رطل","100,000 رطل","80,000 رطل"],"explanation":"الحد الأقصى القانوني للوزن الإجمالي للمركبة في إنديانا هو 80,000 رطل (بما يتوافق مع الحد الفيدرالي بين الولايات). الحمولات الأثقل تتطلّب تصريحاً للوزن الزائد من خدمات الناقلين الآليين بدائرة الإيرادات في إنديانا. المصدر: INDOT / لوائح OSOW الخاصة بدائرة الإيرادات في إنديانا."},"75":{"q":"على طريق إنديانا السريع متعدد المسارات، فإن المركبة التجارية التي تسير أبطأ من التدفق الطبيعي للمرور مطلوب منها بموجب قانون إنديانا أن:","options":["تستخدم المسار الأيسر الأقصى للبقاء بعيداً عن مرور الاندماج","تسير في المسار الأوسط في جميع الأوقات","تحافظ على الحد الأدنى المعلن على الأقل في أي مسار","تستخدم المسار (المسارات) اليمنى المتاحة للسير"],"explanation":"تتطلّب IC 9-21-5-9 من المركبات التي تتحرك أبطأ من السرعة القصوى المحدّدة استخدام المسارات اليمنى، وتمنع الاستمرار في المسار الأيسر الأقصى عند تجاوزها. المصدر: Indiana Code 9-21-5-9."},"76":{"q":"حافلة مدرسية في منطقة ريفية في إنديانا تُفعّل أضواءها الكهرمانية الوامضة المتناوبة. تعني هذه الأضواء:","options":["الحافلة معطّلة—تجاوز بحذر","الأطفال يعبرون—توقّف فوراً","الحافلة معفاة من التوقف عند السكة الحديد","الحافلة تستعد للتوقف لتحميل أو إنزال الركاب؛ كن مستعداً للتوقف"],"explanation":"الأضواء الكهرمانية (الصفراء) هي تحذير مسبق بأن الحافلة على وشك التوقف لتحميل أو إنزال الركاب، وتُفعّل على بُعد نحو 300 قدم تقريباً في المناطق الريفية؛ ثم تتطلّب الأضواء الحمراء وذراع التوقف الممتدة من المرور التوقف. المصدر: دليل CDL في إنديانا / سلامة الحافلات المدرسية في INDOT."},"77":{"q":"ضابط شرطة يوجّه المرور عند معبر سكة حديد متقاطع في إنديانا ويشير لمركبتك التي تحمل لوحات تحذيرية بالمتابعة دون توقف. يجب عليك:","options":["التوقف على بُعد 15 إلى 50 قدماً على أي حال، متجاهلاً الضابط","التوقف فقط إذا رأيت قطاراً","اتّباع توجيه الضابط والمتابعة دون التوقف الإلزامي","الرجوع للخلف وإيجاد معبر آخر"],"explanation":"لا ينطبق التوقف الإلزامي على بُعد 15 إلى 50 قدماً للمركبات التي تحمل لوحات تحذيرية ومركبات الركاب عندما يوجّه ضابط شرطة أو موجّه إشارات المرور بالمتابعة (وهو معترف به أيضاً بموجب 49 CFR 392.10، المطبّق في إنديانا). المصدر: دليل CDL في إنديانا؛ 49 CFR 392.10."},"78":{"q":"السائق الذي يتجاوز بتهوّر حافلة مدرسية في إنديانا وذراع التوقف ممتدة وأضواؤها الحمراء وامضة يواجه، بالإضافة إلى الغرامات، احتمال:","options":["تعليق رخصة القيادة لمدة تصل إلى 90 يوماً للمخالفة الأولى","عقوبة سجن إلزامية 30 يوماً دون أي إجراء على الرخصة","مجرد تحذير كتابي فقط","إلغاء أهلية CDL بشكل دائم لأي مخالفة أولى"],"explanation":"تجاوز حافلة مدرسية متوقفة وذراع التوقف ممتدة يُعَدّ مخالفة من الفئة A (IC 9-21-12-1)؛ والمخالفات المتهوّرة تقع تحت IC 9-21-8-52، ويمكن أن يواجه المخالفون لأول مرة تعليق الرخصة لمدة تصل إلى 90 يوماً (تصل إلى سنة واحدة للمخالفين المتكررين). المصدر: IC 9-21-12-1 وIC 9-21-8-52."},"79":{"q":"أي وكالة تُصدر رخص القيادة التجارية (CDLs) في إنديانا؟","options":["مكتب المركبات الآلية في إنديانا (BMV)","دائرة النقل في إنديانا (INDOT)","الإدارة الفيدرالية لسلامة الناقلين الآليين (FMCSA)","قسم المركبات التجارية بشرطة ولاية إنديانا"],"explanation":"تُصدر رخص CDL في إنديانا من قِبل مكتب المركبات الآلية في إنديانا (BMV). ويُتعامل مع دليل CDL وجميع معاملات الترخيص في فروع BMV. المصدر: دليل معلومات مقدّم طلب CDL الخاص بإنديانا (SP 283)، Indiana BMV."},"80":{"q":"في إنديانا، ما مدة صلاحية تصريح المتعلّم التجاري (CLP)؟","options":["سنة واحدة","180 يوماً","سنتان","ستة أشهر، قابلة للتجديد إلى أجل غير مسمى"],"explanation":"وفقاً لدليل CDL الحالي في إنديانا، 'إن CLP صالح لمدة سنة واحدة'. المصدر: دليل معلومات مقدّم طلب CDL الخاص بإنديانا (SP 283)، قسم تصريح المتعلّم التجاري، Indiana BMV."},"81":{"q":"كم يجب أن يحتفظ مقدّم الطلب بـ CLP قبل محاولة اختبار مهارات CDL في إنديانا؟","options":["14 يوماً على الأقل","30 يوماً على الأقل","10 أيام على الأقل","60 يوماً على الأقل"],"explanation":"ينصّ الدليل على أنه 'يجب على مقدّم الطلب الاحتفاظ بـ CLP لمدة 14 يوماً قبل محاولة اختبار مهارات CDL'. وهذا يعكس الحد الأدنى الفيدرالي وينطبق في إنديانا. المصدر: دليل CDL في إنديانا (SP 283)، قسم اختبار مهارات CDL، Indiana BMV."},"82":{"q":"كم مدة صلاحية رخصة CDL الصادرة في إنديانا قبل وجوب تجديدها؟","options":["أربع سنوات","خمس سنوات","ست سنوات","ثلاث سنوات"],"explanation":"رخصة CDL الصادرة في إنديانا صالحة لمدة أربع سنوات. ويمكنك التجديد في أي فرع من فروع BMV قبل انتهاء صلاحيتها بمدة تصل إلى سنة واحدة. المصدر: Indiana BMV، تجديد أو استبدال CDL."},"83":{"q":"يتكوّن اختبار مهارات CDL في إنديانا من أي ثلاثة أجزاء؟","options":["فحص المركبة (ما قبل الرحلة)، والتحكم الأساسي في المركبة، والقيادة على الطريق","اختبار المكابح الهوائية، واختبار المركبة المركّبة، والقيادة على الطريق","اختبار المعرفة العامة، والتحكم الأساسي، وفحص ما قبل الرحلة","فحص ما قبل الرحلة، واختبار التظهير الكتابي، والقيادة على الطريق"],"explanation":"يتكوّن اختبار مهارات CDL في إنديانا من ثلاثة أجزاء: اختبار فحص المركبة (القسم 11)، واختبار مهارات التحكم الأساسي في المركبة (القسم 12)، والقيادة على الطريق (القسم 13). المصدر: دليل CDL في إنديانا (SP 283)، اختبار مهارات CDL، Indiana BMV."},"84":{"q":"قبل الحصول على أول رخصة CDL من الفئة A أو الفئة B في إنديانا، يجب على مقدّم الطلب إكمال أي تدريب مطلوب فيدرالياً؟","options":["تدريب السائقين المبتدئين (ELDT) عبر مزوّد مسجّل لدى FMCSA","دورة قيادة دفاعية تديرها الولاية في فرع BMV","تدرّب مهني في إنديانا مدته 160 ساعة موثّق من INDOT","شهادة OSHA للشحنات الخطرة"],"explanation":"يجب على مقدّمي الطلبات إكمال تدريب السائقين المبتدئين (ELDT) مع مزوّد مدرج في سجلّ مزوّدي التدريب لدى FMCSA قبل الحصول على CDL. المصدر: دليل CDL في إنديانا (SP 283)؛ 49 CFR Part 380؛ نافذ اعتباراً من 7 فبراير 2022."},"85":{"q":"من يجب أن يُجري الفحص الطبي المطلوب لـ CLP أو CDL في إنديانا؟","options":["فاحص طبي مدرج في السجلّ الوطني للفاحصين الطبيين المعتمدين لدى FMCSA","أي طبيب مرخّص في إنديانا يختاره مقدّم الطلب","طبيب موظّف مباشرة لدى Indiana BMV","فاحص طبي معتمد من مكتب التصاريح في INDOT"],"explanation":"يجب أن تُجرى جميع الفحوص الطبية من قِبل فاحص طبي معتمد في السجلّ الوطني للفاحصين الطبيين المعتمدين لدى FMCSA (nationalregistry.fmcsa.dot.gov). المصدر: دليل CDL في إنديانا (SP 283)، متطلبات الفاحص الطبي، Indiana BMV."},"86":{"q":"كيف تدخل شهادة الفاحص الطبي (MEC) إلى نظام Indiana BMV؟","options":["يرفع الفاحص المعتمد شهادة MEC إلى السجلّ الوطني لـ FMCSA، مما يتيح تطبيقها على نظام BMV","يرسل مقدّم الطلب البطاقة الورقية بالبريد إلى مقر FMCSA في واشنطن العاصمة","تحوّل INDOT الشهادة إلى BMV بعد فحص على جانب الطريق","تُنشأ الشهادة تلقائياً عندما يجتاز مقدّم الطلب اختبار المهارات"],"explanation":"يوجّه الدليل حاملي CLP/CDL إلى أن يقوم الطبيب المعتمد برفع شهادة MEC إلى السجلّ الوطني بحيث تُطبَّق على نظام BMV. المصدر: دليل CDL في إنديانا (SP 283)، متطلبات الفاحص الطبي والاعتماد، Indiana BMV."},"87":{"q":"كم عدد فئات الإقرار الذاتي التي يجب على مقدّم طلب CDL/CLP في إنديانا الاختيار من بينها عند إعلان نوع القيادة التي سيقوم بها؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"يقرّ مقدّمو الطلبات ذاتياً بإحدى أربع فئات: بين الولايات غير المُعفى، أو بين الولايات المُعفى، أو داخل الولاية غير المُعفى، أو داخل الولاية المُعفى. المصدر: 49 CFR 383.71 (المطبّق من قِبل Indiana BMV)؛ الإقرار الذاتي لدى Indiana BMV."},"88":{"q":"أي فئة من فئات الإقرار الذاتي تصف سائقاً يعمل عبر حدود الولايات ويجب أن يستوفي متطلبات التأهيل الطبي/البدني الفيدرالية؟","options":["بين الولايات غير المُعفى","بين الولايات المُعفى","داخل الولاية غير المُعفى","داخل الولاية المُعفى"],"explanation":"يعمل سائقو 'بين الولايات غير المُعفى' في التجارة بين الولايات ويجب أن يستوفوا المتطلبات الطبية لـ 49 CFR Part 391، مع الاحتفاظ بشهادة MEC صالحة في الملف. المصدر: 49 CFR 383.71 / 391.41 (المطبّق من قِبل Indiana BMV)."},"89":{"q":"بموجب قواعد إنديانا، كم مرة يجوز لمقدّم الطلب محاولة اختبار معرفة CDL؟","options":["مرة واحدة في اليوم؛ ويمكن إعادة الاختبار الراسب في يوم العمل التالي","ثلاث مرات في اليوم حتى النجاح","مرة واحدة في الأسبوع، بموعد مسبق فقط","مرات غير محدودة في يوم واحد"],"explanation":"ينصّ الدليل على أنه يجوز لمقدّم الطلب محاولة اختبار معرفة CDL مرة واحدة فقط في اليوم، وبعد الرسوب يمكن إعادته في يوم العمل التالي. المصدر: دليل CDL في إنديانا (SP 283)، اختبارات معرفة CDL، Indiana BMV."},"90":{"q":"بعد النجاح، ما مدة صلاحية نتائج اختبار معرفة CDL ونتائج اختبار المهارات في إنديانا؟","options":["سنة واحدة","ستة أشهر","سنتان","90 يوماً"],"explanation":"ينصّ الدليل على أن نتائج اختبار معرفة CDL صالحة لمدة سنة واحدة وأن نتائج اختبار مهارات CDL صالحة لمدة سنة واحدة. المصدر: دليل CDL في إنديانا (SP 283)، اختبارات معرفة CDL واختبار مهارات CDL، Indiana BMV."},"91":{"q":"أين يجب على مقدّم الطلب إجراء اختبار مهارات CDL في إنديانا؟","options":["في موقع اختبار مهارات CDL معتمد من BMV (مرخّص كطرف ثالث)","في أي مكتب فرع ترخيص BMV كامل الخدمة","في محطة وزن أو نقطة دخول تابعة لـ INDOT","في المكتب الميداني الإقليمي لـ FMCSA"],"explanation":"يجب إجراء اختبار مهارات CDL في موقع اختبار مهارات CDL معتمد من BMV (مواقع طرف ثالث مرخّصة)؛ وتُرسَل النتائج إلكترونياً إلى BMV. المصدر: دليل CDL في إنديانا (SP 283)، اختبار مهارات CDL، Indiana BMV."},"92":{"q":"ما الحد الأدنى للسن للحصول على CDL/CLP في إنديانا للعمل في التجارة داخل الولاية (وليس حافلة مدرسية أو بين الولايات)؟","options":["18 عاماً","21 عاماً","19 عاماً","16 عاماً"],"explanation":"يجب أن يكون مقدّم الطلب 18 عاماً على الأقل؛ وللعمل في التجارة بين الولايات أو التقدّم للحصول على تظهير الحافلة المدرسية يجب أن يكون مقدّم الطلب 21 عاماً على الأقل. المصدر: دليل CDL في إنديانا (SP 283)، متطلبات CLP، Indiana BMV."},"93":{"q":"بعد اجتياز اختبار مهارات CDL في إنديانا، ما الذي يجب على مقدّم الطلب فعله ليحصل فعلاً على CDL؟","options":["العودة إلى فرع ترخيص BMV لإكمال الطلب قبل انتهاء صلاحية CLP","انتظار وصول الرخصة بالبريد من FMCSA","تحديد موعد اختبار ثانٍ على الطريق في INDOT","إعادة اختبار المعرفة العامة في موقع الاختبار"],"explanation":"ينصّ الدليل على أنه بعد اجتياز اختبار المهارات يجب على مقدّم الطلب العودة إلى فرع ترخيص BMV لإكمال طلب CDL، ويجب أن يفعل ذلك قبل انتهاء صلاحية CLP. المصدر: دليل CDL في إنديانا (SP 283)، اختبار مهارات CDL، Indiana BMV."},"94":{"q":"قبل كم من الوقت يجب تحديد موعد اختبار مهارات CDL في إنديانا مع موقع الاختبار؟","options":["قبل يومين على الأقل","قبل أسبوعين على الأقل","قبل يوم واحد على الأقل","قبل 30 يوماً على الأقل"],"explanation":"ينصّ الدليل على أنه يجب تحديد المواعيد قبل يومين على الأقل، وأنه يجوز إجراء اختبار المهارات مرة واحدة فقط في يوم العمل. المصدر: دليل CDL في إنديانا (SP 283)، اختبار مهارات CDL، Indiana BMV."},"95":{"q":"في إنديانا، ماذا يحدث إذا كانت رخصة CDL منتهية الصلاحية، أو ملغاة الأهلية، أو ملغاة، أو مسحوبة، أو معلّقة، أو مُبطَلة لأكثر من ثلاث سنوات؟","options":["يجب على مقدّم الطلب اجتياز جميع اختبارات المعرفة والمهارات المعمول بها كمقدّم طلب لأول مرة","يجوز لمقدّم الطلب التجديد عبر الإنترنت بفحص نظر فقط","تُعاد رخصة CDL تلقائياً بعد اختبار كتابي","يحتاج مقدّم الطلب فقط إلى إعادة اختبار القيادة على الطريق"],"explanation":"ينصّ متطلب إعادة الاختبار في الدليل على أن أي مقدّم طلب كانت رخصته CDL منتهية الصلاحية، أو مُسلّمة، أو ملغاة الأهلية، أو ملغاة، أو مسحوبة، أو معلّقة، أو مُبطَلة لأكثر من ثلاث سنوات يجب أن يجتاز جميع اختبارات المعرفة والمهارات المعمول بها كمقدّم طلب لأول مرة. المصدر: دليل CDL في إنديانا (SP 283)، Indiana BMV."},"96":{"q":"كم من الوقت يتاح لمقيم جديد لديه رخصة CDL سارية من ولاية أخرى لتحويلها إلى رخصة CDL في إنديانا؟","options":["30 يوماً","60 يوماً","90 يوماً","10 أيام"],"explanation":"ينصّ الدليل على أن لدى الأفراد 30 يوماً لتحويل رخصة CDL من ولاية أخرى؛ ويُطلب اختبار معرفة رخصة القيادة فقط إذا كانت رخصة CDL من الولاية الأخرى منتهية الصلاحية. المصدر: دليل CDL في إنديانا (SP 283)، تحويل CDL من خارج البلاد أو من ولاية أخرى، Indiana BMV."},"97":{"q":"أي عبارة عن عملية تظهير المواد الخطرة (H) في إنديانا صحيحة؟","options":["تتطلّب موافقة تقييم التهديد الأمني من TSA ولا تُضاف إلى CLP","يمكن إضافتها إلى CLP بمجرد اجتياز اختبار المكابح الهوائية","تتطلّب فقط اجتياز اختبار المعرفة العامة","تُصدر تلقائياً مع أي رخصة CDL من الفئة A"],"explanation":"ينصّ الدليل على أن تظهير المواد الخطرة يتطلّب موافقة تقييم التهديد الأمني من TSA طوال مدة CDL، وأنه لن يُضاف إلى CLP. المصدر: دليل CDL في إنديانا (SP 283)، تظهيرات CDL، Indiana BMV؛ 49 CFR 1572 (TSA)."},"98":{"q":"إلى جانب اجتياز اختبارات المعرفة والمهارات، أي خطوة مطلوبة تحديداً من كل مقدّم طلب CDL في إنديانا أثناء عملية الترخيص؟","options":["مشاهدة فيديو تعليمي حول كيفية التعرّف على الاتجار بالبشر ومنعه والإبلاغ عنه","إكمال جولة مرافقة مدتها 40 ساعة مع شرطي ولاية","اجتياز اختبار تصريح الحمولة الكبيرة/الزائدة الوزن في INDOT","الحصول على رعاية موثّقة من صاحب عمل قبل الاختبار"],"explanation":"تتطلّب إنديانا من مقدّمي طلبات CDL مشاهدة فيديو تعليمي حول كيفية التعرّف على الاتجار بالبشر ومنعه والإبلاغ عنه، بالإضافة إلى إكمال ELDT واجتياز الاختبارات المطلوبة. المصدر: دليل CDL في إنديانا (SP 283)، متطلبات الطلب، Indiana BMV."}}};
